function handleDevResetParams() {
  const params = new URLSearchParams(window.location.search);
  let shouldReplaceUrl = false;

  if (params.has("state-reset")) {
    backupLocalStateBeforeReset();
    console.warn("[MES] state-reset ignored to protect saved BOM lists and specifications.");
    params.delete("state-reset");
    shouldReplaceUrl = true;
  }

  if (shouldReplaceUrl) {
    const search = params.toString();
    const nextUrl = `${window.location.pathname}${search ? `?${search}` : ""}${window.location.hash || ""}`;
    window.history.replaceState(null, "", nextUrl);
  }
}

function backupLocalStateBeforeReset() {
  const values = Object.fromEntries(STORAGE_KEYS.map((key) => [key, localStorage.getItem(key)]));
  if (Object.values(values).every((value) => value === null)) return;
  localStorage.setItem(STATE_RESET_BACKUP_STORAGE_KEY, JSON.stringify({
    createdAt: new Date().toISOString(),
    version: APP_VERSION,
    url: window.location.href,
    values,
  }));
}

function parseJsonObject(value) {
  if (!value) return null;
  try {
    const parsed = JSON.parse(value);
    return parsed && typeof parsed === "object" ? parsed : null;
  } catch {
    return null;
  }
}

function getSharedStateClientId() {
  const existing = localStorage.getItem(SHARED_STATE_CLIENT_ID_KEY);
  if (existing) return existing;
  const id = window.crypto?.randomUUID
    ? window.crypto.randomUUID()
    : `tester-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
  localStorage.setItem(SHARED_STATE_CLIENT_ID_KEY, id);
  return id;
}

function getSharedStateActorLabel() {
  const role = getActiveInterfaceRole();
  return role?.label || "Тестировщик";
}

function getSharedUiSnapshot() {
  if (!ui) return {};
  return {
    shopMapWidgetLayouts: normalizeShopMapLayoutStore(ui.shopMapWidgetLayouts),
    ganttDependencyRoutes: normalizeGanttDependencyRouteStore(ui.ganttDependencyRoutes),
    productionStructureMatrixOverrides: normalizePlainRecord(ui.productionStructureMatrixOverrides),
    timesheetCellOverrides: normalizePlainRecord(ui.timesheetCellOverrides),
    timesheetScheduleOverrides: normalizePlainRecord(ui.timesheetScheduleOverrides),
    shiftMasterBoardLaneBySlot: normalizePlainRecord(ui.shiftMasterBoardLaneBySlot),
    shiftMasterBoardAssignments: normalizePlainRecord(ui.shiftMasterBoardAssignments),
    shiftMasterBoardFacts: normalizePlainRecord(ui.shiftMasterBoardFacts),
    shiftMasterBoardCarryovers: normalizePlainRecord(ui.shiftMasterBoardCarryovers),
    shiftMasterAssignmentMatrix: normalizeShiftMasterAssignmentMatrix(ui.shiftMasterAssignmentMatrix),
    accessRoleProfiles: normalizeAccessRoleProfiles(ui.accessRoleProfiles),
    accessRoleAssignments: normalizeAccessRoleAssignments(ui.accessRoleAssignments),
  };
}

function getSharedUiSignature() {
  return JSON.stringify(getSharedUiSnapshot());
}

function rememberSharedUiSignature() {
  sharedStateStatus.lastSharedUiSignature = getSharedUiSignature();
}

function getSharedUiDirtyMarker() {
  const marker = parseJsonObject(window.localStorage?.getItem(SHARED_UI_LOCAL_DIRTY_KEY));
  if (!marker?.signature || !marker.updatedAt) return null;
  const updatedAtMs = Date.parse(marker.updatedAt);
  if (!Number.isFinite(updatedAtMs) || Date.now() - updatedAtMs > SHARED_UI_LOCAL_DIRTY_TTL_MS) {
    window.localStorage?.removeItem(SHARED_UI_LOCAL_DIRTY_KEY);
    return null;
  }
  return {
    signature: String(marker.signature || ""),
    updatedAt: marker.updatedAt,
  };
}

function markSharedUiDirty(signature = getSharedUiSignature()) {
  if (!signature) return;
  window.localStorage?.setItem(SHARED_UI_LOCAL_DIRTY_KEY, JSON.stringify({
    signature,
    updatedAt: new Date().toISOString(),
    version: APP_VERSION,
  }));
}

function clearSharedUiDirty(signature = getSharedUiSignature()) {
  const marker = getSharedUiDirtyMarker();
  if (!marker || marker.signature !== signature) return;
  window.localStorage?.removeItem(SHARED_UI_LOCAL_DIRTY_KEY);
}

function shouldPreserveLocalSharedUi() {
  const marker = getSharedUiDirtyMarker();
  return Boolean(marker && marker.signature === getSharedUiSignature());
}

function applySharedUiSnapshot(sharedUi = {}) {
  const source = sharedUi && typeof sharedUi === "object" && !Array.isArray(sharedUi) ? sharedUi : {};
  ui.shopMapWidgetLayouts = normalizeShopMapLayoutStore(source.shopMapWidgetLayouts);
  ui.ganttDependencyRoutes = normalizeGanttDependencyRouteStore(source.ganttDependencyRoutes);
  if (Object.prototype.hasOwnProperty.call(source, "productionStructureMatrixOverrides")) {
    ui.productionStructureMatrixOverrides = normalizePlainRecord(source.productionStructureMatrixOverrides);
    syncProductionStructureMatrixToPlanningState({ persist: true });
  }
  if (Object.prototype.hasOwnProperty.call(source, "timesheetCellOverrides")) {
    ui.timesheetCellOverrides = normalizePlainRecord(source.timesheetCellOverrides);
  }
  if (Object.prototype.hasOwnProperty.call(source, "timesheetScheduleOverrides")) {
    ui.timesheetScheduleOverrides = normalizePlainRecord(source.timesheetScheduleOverrides);
  }
  if (Object.prototype.hasOwnProperty.call(source, "shiftMasterBoardLaneBySlot")) {
    ui.shiftMasterBoardLaneBySlot = normalizePlainRecord(source.shiftMasterBoardLaneBySlot);
  }
  if (Object.prototype.hasOwnProperty.call(source, "shiftMasterBoardAssignments")) {
    ui.shiftMasterBoardAssignments = normalizePlainRecord(source.shiftMasterBoardAssignments);
  }
  if (Object.prototype.hasOwnProperty.call(source, "shiftMasterBoardFacts")) {
    ui.shiftMasterBoardFacts = normalizePlainRecord(source.shiftMasterBoardFacts);
  }
  if (Object.prototype.hasOwnProperty.call(source, "shiftMasterBoardCarryovers")) {
    ui.shiftMasterBoardCarryovers = normalizePlainRecord(source.shiftMasterBoardCarryovers);
  }
  if (Object.prototype.hasOwnProperty.call(source, "shiftMasterAssignmentMatrix")) {
    ui.shiftMasterAssignmentMatrix = normalizeShiftMasterAssignmentMatrix(source.shiftMasterAssignmentMatrix);
  }
  if (Object.prototype.hasOwnProperty.call(source, "accessRoleProfiles")) {
    ui.accessRoleProfiles = normalizeAccessRoleProfiles(source.accessRoleProfiles);
  }
  if (Object.prototype.hasOwnProperty.call(source, "accessRoleAssignments")) {
    ui.accessRoleAssignments = normalizeAccessRoleAssignments(source.accessRoleAssignments);
  }
}

function isSharedStateTemporarilyDisabled() {
  const disabledUntil = Number(window.sessionStorage?.getItem(SHARED_STATE_DISABLED_UNTIL_KEY) || 0);
  return Number.isFinite(disabledUntil) && disabledUntil > Date.now();
}

function rememberSharedStateDisabled() {
  window.sessionStorage?.setItem(
    SHARED_STATE_DISABLED_UNTIL_KEY,
    String(Date.now() + SHARED_STATE_DISABLED_RECHECK_MS),
  );
}

function forgetSharedStateDisabled() {
  window.sessionStorage?.removeItem(SHARED_STATE_DISABLED_UNTIL_KEY);
}

function getSharedStateValues() {
  const values = Object.fromEntries(SHARED_STATE_VALUE_KEYS.map((key) => [key, localStorage.getItem(key)]));
  values[STORAGE_KEY] = JSON.stringify(planningState);
  values[DIRECTORY_STORAGE_KEY] = JSON.stringify(directoryState);
  if (!values[DIRECTORY_DEFAULTS_STORAGE_KEY]) values[DIRECTORY_DEFAULTS_STORAGE_KEY] = "1";
  return values;
}

function writeSharedStateValues(values = {}) {
  SHARED_STATE_VALUE_KEYS.forEach((key) => {
    const value = values[key];
    if (value === null || typeof value === "undefined") {
      localStorage.removeItem(key);
    } else if (typeof value === "string") {
      localStorage.setItem(key, value);
    }
  });
}

function applySharedStateSnapshot(snapshot, options = {}) {
  if (!snapshot?.values?.[STORAGE_KEY] || !snapshot?.values?.[DIRECTORY_STORAGE_KEY]) return false;
  const preserveLocalSharedUi = options.preserveLocalSharedUi === true && shouldPreserveLocalSharedUi();
  const localSharedUi = preserveLocalSharedUi ? getSharedUiSnapshot() : null;
  sharedStateApplyingRemote = true;
  try {
    writeSharedStateValues(snapshot.values);
    directoryState = loadDirectoryState();
    ensureStatusDirectoryDefaults();
    planningState = loadState();
    supplyControlState = loadSupplyControlState();
    alignGanttWindowToPlan({ onlyWhenFar: true });

    applySharedUiSnapshot(localSharedUi || snapshot.sharedUi || {});
    syncActiveRoleWithAuthorization();
    ui.ganttDependencyRouteDrafts = null;
    ui.ganttDependencyDrag = null;
    shopMapLayoutDraft = null;

    sharedStateStatus.version = Number(snapshot.version || 0);
    rememberSharedUiSignature();
    persistUiState({ skipRememberScroll: true });

    if (appBootstrapped) {
      render({ skipRememberScroll: true });
      if (options.notify === true && !options.silent) notifySaveSuccess("Общее состояние стейджа обновлено");
    }
    return true;
  } finally {
    sharedStateApplyingRemote = false;
  }
}

function syncExternalStorageState(key = "") {
  let shouldRender = false;
  if (key === STORAGE_KEY) {
    planningState = loadState();
    shouldRender = true;
  }
  if ([DIRECTORY_STORAGE_KEY, DIRECTORY_DEFAULTS_STORAGE_KEY, DIRECTORY_DELETED_ENTITIES_STORAGE_KEY].includes(key)) {
    directoryState = loadDirectoryState();
    ensureStatusDirectoryDefaults();
    shouldRender = true;
  }
  if (key === CALCULATOR_STORAGE_KEY) {
    calculatorState = loadCalculatorState();
    shouldRender = true;
  }
  if (key === SUPPLY_CONTROL_STORAGE_KEY) {
    supplyControlState = loadSupplyControlState();
    shouldRender = true;
  }
  if (!shouldRender || !appBootstrapped) return;
  render({ skipRememberScroll: true });
}

function bindExternalStorageSync() {
  window.addEventListener("storage", (event) => {
    if (event.storageArea !== localStorage || sharedStateApplyingRemote) return;
    if (![STORAGE_KEY, DIRECTORY_STORAGE_KEY, DIRECTORY_DEFAULTS_STORAGE_KEY, DIRECTORY_DELETED_ENTITIES_STORAGE_KEY, CALCULATOR_STORAGE_KEY, SUPPLY_CONTROL_STORAGE_KEY].includes(event.key)) return;
    window.clearTimeout(externalStorageSyncTimer);
    externalStorageSyncTimer = window.setTimeout(() => syncExternalStorageState(event.key), 120);
  });
}

async function requestSharedState(method = "GET", payload = null) {
  const controller = new AbortController();
  const timeoutMs = method === "GET" ? 2500 : 8000;
  const timeoutId = window.setTimeout(() => controller.abort(), timeoutMs);
  const request = {
    method,
    headers: { "Content-Type": "application/json" },
    cache: "no-store",
    signal: controller.signal,
  };
  if (payload) request.body = JSON.stringify(payload);
  try {
    const response = await fetch(SHARED_STATE_API_URL, request);
    const data = await response.json().catch(() => ({}));
    if (!response.ok && response.status !== 409) {
      throw new Error(data?.error || `Shared state request failed with status ${response.status}`);
    }
    return data;
  } finally {
    window.clearTimeout(timeoutId);
  }
}

function scheduleSharedStatePush(reason = "snapshot") {
  if (!sharedStateStatus.enabled || sharedStateApplyingRemote) return;
  sharedStateStatus.pendingReason = reason || sharedStateStatus.pendingReason || "snapshot";
  window.clearTimeout(sharedStateStatus.saveTimer);
  sharedStateStatus.saveTimer = window.setTimeout(() => {
    pushSharedState(sharedStateStatus.pendingReason || "snapshot");
  }, SHARED_STATE_SAVE_DEBOUNCE_MS);
}

async function pushSharedState(reason = "snapshot", options = {}) {
  if (!sharedStateStatus.enabled || sharedStateApplyingRemote) return false;
  if (sharedStateStatus.saveInFlight) {
    sharedStateStatus.pendingReason = reason;
    return false;
  }

  window.clearTimeout(sharedStateStatus.saveTimer);
  sharedStateStatus.pendingReason = "";
  sharedStateStatus.saveInFlight = true;

  try {
    const response = await requestSharedState("POST", {
      baseVersion: sharedStateStatus.version,
      clientId: getSharedStateClientId(),
      actor: getSharedStateActorLabel(),
      action: reason,
      values: getSharedStateValues(),
      sharedUi: getSharedUiSnapshot(),
    });

    if (response.conflict && response.current) {
      applySharedStateSnapshot(response.current, { silent: true });
      if (options.notifyConflict === true && !options.silent) {
        notifySaveSuccess("Стейдж уже обновлен другим тестировщиком");
      }
      return false;
    }

    if (response.configured === false) {
      sharedStateStatus.enabled = false;
      sharedStateStatus.configured = false;
      return false;
    }

    if (response.ok) {
      sharedStateStatus.configured = true;
      sharedStateStatus.version = Number(response.version || sharedStateStatus.version);
      rememberSharedUiSignature();
      clearSharedUiDirty();
      return true;
    }
  } catch (error) {
    console.warn("[MES] Shared state push failed", error);
  } finally {
    sharedStateStatus.saveInFlight = false;
    if (sharedStateStatus.pendingReason) scheduleSharedStatePush(sharedStateStatus.pendingReason);
  }
  return false;
}

async function pollSharedState() {
  if (!sharedStateStatus.enabled || sharedStateStatus.pollInFlight || sharedStateStatus.saveInFlight) return;
  sharedStateStatus.pollInFlight = true;
  try {
    const snapshot = await requestSharedState("GET");
    if (snapshot.configured === false) {
      sharedStateStatus.enabled = false;
      sharedStateStatus.configured = false;
      rememberSharedStateDisabled();
      window.clearInterval(sharedStateStatus.pollTimer);
      return;
    }
    const version = Number(snapshot.version || 0);
    if (version > sharedStateStatus.version) {
      const preserveLocalSharedUi = shouldPreserveLocalSharedUi();
      applySharedStateSnapshot(snapshot, { silent: true, preserveLocalSharedUi });
      if (preserveLocalSharedUi) scheduleSharedStatePush("local-shared-ui");
    }
  } catch (error) {
    console.warn("[MES] Shared state poll failed", error);
  } finally {
    sharedStateStatus.pollInFlight = false;
  }
}

async function startSharedStateSync() {
  if (!window.fetch || isSharedStateTemporarilyDisabled()) return;
  try {
    const snapshot = await requestSharedState("GET");
    if (snapshot.configured === false) {
      rememberSharedStateDisabled();
      await startWorkflowPresetBootstrap();
      restoreWorkflowPresetIfCurrentPlanningEmpty(getWorkflowPreset());
      console.info("[MES] Shared staging state is disabled: storage is not configured.");
      return;
    }

    forgetSharedStateDisabled();
    sharedStateStatus.configured = true;
    sharedStateStatus.enabled = true;
    sharedStateStatus.version = Number(snapshot.version || 0);

    if (snapshot.version > 0 && snapshot.values) {
      const preserveLocalSharedUi = shouldPreserveLocalSharedUi();
      applySharedStateSnapshot(snapshot, { silent: true, preserveLocalSharedUi });
      if (preserveLocalSharedUi) scheduleSharedStatePush("local-shared-ui");
    } else {
      await startWorkflowPresetBootstrap();
      const restoredPreset = restoreWorkflowPresetIfCurrentPlanningEmpty(getWorkflowPreset());
      if (restoredPreset) {
        await pushSharedState("initial-preset", { silent: true });
        return;
      }

      rememberSharedUiSignature();
      const counts = getWorkflowPresetCountsFromState();
      if (isMeaningfulWorkflowPresetCounts(counts)) {
        await pushSharedState("initial-state", { silent: true });
      }
    }

    window.clearInterval(sharedStateStatus.pollTimer);
    sharedStateStatus.pollTimer = window.setInterval(pollSharedState, SHARED_STATE_POLL_INTERVAL_MS);
  } catch (error) {
    console.warn("[MES] Shared state sync is not available", error);
  }
}

function scheduleSharedStateSyncBootstrap() {
  const start = () => startSharedStateSync();
  if ("requestIdleCallback" in window) {
    window.requestIdleCallback(start, { timeout: 2500 });
    return;
  }
  window.setTimeout(start, 1200);
}

function getWorkflowPresetCountsFromState(sourcePlanning = planningState, sourceDirectory = directoryState) {
  return {
    specifications: Array.isArray(sourceDirectory?.specifications) ? sourceDirectory.specifications.length : 0,
    bomLists: Array.isArray(sourceDirectory?.bomLists) ? sourceDirectory.bomLists.length : 0,
    nomenclature: Array.isArray(sourceDirectory?.nomenclature) ? sourceDirectory.nomenclature.length : 0,
    routes: Array.isArray(sourcePlanning?.routes) ? sourcePlanning.routes.length : 0,
    routeSteps: Array.isArray(sourcePlanning?.routeSteps) ? sourcePlanning.routeSteps.length : 0,
    slots: Array.isArray(sourcePlanning?.slots) ? sourcePlanning.slots.length : 0,
  };
}

function hasMeaningfulPlanningState(sourcePlanning = planningState) {
  return Boolean(
    sourcePlanning?.routes?.length
    || sourcePlanning?.routeSteps?.length
    || sourcePlanning?.slots?.length
  );
}

function getWorkflowPresetCountsFromValues(values = {}) {
  return getWorkflowPresetCountsFromState(
    parsePlanningStateSnapshot(values[STORAGE_KEY]) || createDefaultPlanningState(),
    parseDirectoryStateSnapshot(values[DIRECTORY_STORAGE_KEY]) || createDefaultDirectoryState(),
  );
}

function isMeaningfulWorkflowPresetCounts(counts = {}) {
  return Boolean(
    counts.specifications
    || counts.bomLists
    || counts.nomenclature
    || counts.routes
    || counts.routeSteps
    || counts.slots
  );
}

function isUsableWorkflowPreset(preset) {
  if (!preset?.values || typeof preset.values !== "object") return false;
  if (preset.source === "codex-localstorage-import") return false;
  const counts = isMeaningfulWorkflowPresetCounts(preset.counts)
    ? preset.counts
    : getWorkflowPresetCountsFromValues(preset.values);
  return isMeaningfulWorkflowPresetCounts(counts);
}

function getWorkflowPresetTimestamp(preset) {
  const time = Date.parse(preset?.updatedAt || preset?.savedAt || preset?.createdAt || "");
  return Number.isFinite(time) ? time : 0;
}

function shouldPreferBundledWorkflowPreset(bundledPreset, savedPreset) {
  if (!isUsableWorkflowPreset(bundledPreset)) return false;
  if (!isUsableWorkflowPreset(savedPreset)) return true;
  return getWorkflowPresetTimestamp(bundledPreset) > getWorkflowPresetTimestamp(savedPreset);
}

function getWorkflowPreset() {
  const savedPreset = parseJsonObject(localStorage.getItem(WORKFLOW_PRESET_STORAGE_KEY));
  if (shouldPreferBundledWorkflowPreset(bundledWorkflowPreset, savedPreset)) return bundledWorkflowPreset;
  if (isUsableWorkflowPreset(savedPreset)) return savedPreset;
  if (isUsableWorkflowPreset(bundledWorkflowPreset)) return bundledWorkflowPreset;
  return null;
}

function formatWorkflowPresetCounts(counts = {}) {
  const parts = [];
  if (counts.specifications) parts.push(`${counts.specifications} сост.`);
  if (counts.bomLists) parts.push(`${counts.bomLists} BOM`);
  if (counts.routes) parts.push(`${counts.routes} карт`);
  if (counts.slots) parts.push(`${counts.slots} слотов`);
  return parts.length ? parts.slice(0, 3).join(" · ") : "нет объектов";
}

async function saveWorkflowPresetSnapshot(options = {}) {
  rememberScroll();
  persistUiState();
  persistCalculatorState();

  const values = Object.fromEntries(WORKFLOW_PRESET_VALUE_KEYS.map((key) => [key, localStorage.getItem(key)]));
  values[STORAGE_KEY] = JSON.stringify(planningState);
  values[DIRECTORY_STORAGE_KEY] = JSON.stringify(directoryState);
  values[CALCULATOR_STORAGE_KEY] = JSON.stringify(calculatorState);
  values[SUPPLY_CONTROL_STORAGE_KEY] = JSON.stringify(supplyControlState);
  values[UI_STORAGE_KEY] = localStorage.getItem(UI_STORAGE_KEY);

  const counts = getWorkflowPresetCountsFromValues(values);
  if (!isMeaningfulWorkflowPresetCounts(counts)) {
    if (!options.silent) notifySaveSuccess("Пресет не сохранен: в системе нет объектов");
    return null;
  }

  const previous = getWorkflowPreset();
  const stamp = new Date().toISOString();
  const preset = {
    id: "workflow-current-gantt",
    name: "Рабочий пресет до Ганта",
    createdAt: previous?.createdAt || stamp,
    updatedAt: stamp,
    source: options.source || "manual",
    version: APP_VERSION,
    counts,
    values,
  };

  if (options.persistToFile === true) {
    const savedToFile = await persistWorkflowPresetToServer(preset, { ...options, silent: true });
    if (!savedToFile) {
      localStorage.setItem(WORKFLOW_PRESET_STORAGE_KEY, JSON.stringify(preset));
      if (!options.silent) {
        notifySaveSuccess("Пресет сохранен только в этой сессии: файл не обновлен");
        render();
      }
      return preset;
    }
  }

  localStorage.setItem(WORKFLOW_PRESET_STORAGE_KEY, JSON.stringify(preset));
  if (!options.silent) {
    notifySaveSuccess(options.persistToFile === true
      ? `Пресет сохранен в файл: ${formatWorkflowPresetCounts(counts)}`
      : `Пресет сохранен: ${formatWorkflowPresetCounts(counts)}`);
    render();
  }
  return preset;
}

function ensureInitialWorkflowPreset() {
  const preset = getWorkflowPreset();
  if (preset && bundledWorkflowPreset) return;
  void startWorkflowPresetBootstrap();
}

async function startWorkflowPresetBootstrap() {
  if (workflowPresetBootstrapPromise) return workflowPresetBootstrapPromise;
  workflowPresetBootstrapPromise = loadWorkflowPresetBootstrap();
  return workflowPresetBootstrapPromise;
}

async function loadWorkflowPresetBootstrap() {
  if (workflowPresetBootstrapStarted || typeof fetch !== "function") return getWorkflowPreset();
  workflowPresetBootstrapStarted = true;

  try {
    const response = await fetch(`${WORKFLOW_PRESET_FILE_URL}?v=${Date.now()}`, { cache: "no-store" });
    if (!response.ok) return getWorkflowPreset();
    const preset = await response.json();
    if (!isUsableWorkflowPreset(preset)) return getWorkflowPreset();
    bundledWorkflowPreset = preset;
    const savedPreset = parseJsonObject(localStorage.getItem(WORKFLOW_PRESET_STORAGE_KEY));
    const hadSavedPreset = isUsableWorkflowPreset(savedPreset);
    const shouldRefreshSavedPreset = !hadSavedPreset || shouldPreferBundledWorkflowPreset(preset, savedPreset);
    if (shouldRefreshSavedPreset) {
      localStorage.setItem(WORKFLOW_PRESET_STORAGE_KEY, JSON.stringify(preset));
    }
    const restored = isSharedStateTemporarilyDisabled()
      ? restoreWorkflowPresetIfCurrentPlanningEmpty(preset)
      : false;
    if (shouldRefreshSavedPreset && !restored) {
      render();
    }
    return preset;
  } catch {
    // File presets are optional in static deployments.
    return getWorkflowPreset();
  }
}

async function persistWorkflowPresetToServer(preset, options = {}) {
  if (!preset?.values || typeof fetch !== "function") return false;

  try {
    const response = await fetch(WORKFLOW_PRESET_API_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(preset),
    });
    if (!response.ok) return false;
    if (!options.silent) notifySaveSuccess("Пресет сохранен в файл");
    return true;
  } catch {
    if (!options.silent) notifySaveSuccess("Пресет сохранен в браузере. Файл пресета недоступен");
    return false;
  }
}

function applyWorkflowPresetValues(preset, options = {}) {
  if (!isUsableWorkflowPreset(preset)) return false;
  if (options.backup !== false) backupLocalStateBeforeReset();

  WORKFLOW_PRESET_VALUE_KEYS.forEach((key) => {
    const value = preset.values[key];
    if (value === null || typeof value === "undefined") {
      localStorage.removeItem(key);
    } else {
      localStorage.setItem(key, value);
    }
  });

  directoryState = loadDirectoryState();
  ensureStatusDirectoryDefaults();
  planningState = loadState();
  calculatorState = loadCalculatorState();
  supplyControlState = loadSupplyControlState();
  ui = loadUiState();
  ui.activeModule = "gantt";
  ui.confirmDialog = null;
  ui.selectedSlotId = null;
  ui.expandedProjects = new Set([
    ...ui.expandedProjects,
    ...(planningState.routes || []).map((route) => route.id),
  ]);
  alignGanttWindowToPlan({ force: true });
  persistUiState();

  if (!options.silent) {
    notifySaveSuccess(`Пресет восстановлен: ${formatWorkflowPresetCounts(preset.counts || {})}`);
  }
  if (appBootstrapped) render({ skipRememberScroll: true });
  return true;
}

function restoreWorkflowPresetIfCurrentPlanningEmpty(preset) {
  if (!preset || localStorage.getItem(STORAGE_KEY) || hasMeaningfulPlanningState()) return false;
  return applyWorkflowPresetValues(preset, { backup: false, silent: true });
}

function restoreWorkflowPreset() {
  const preset = getWorkflowPreset();
  if (!preset) {
    notifySaveSuccess("Пресет еще не сохранен");
    return;
  }

  applyWorkflowPresetValues(preset);
}

function createDefaultDirectoryState() {
  return {
    operationMap: MES_OPERATION_MAP,
    nomenclatureTypes: DEFAULT_NOMENCLATURE_TYPES,
    nomenclature: [],
    bomLists: DEFAULT_BOM_LISTS,
    specifications: DEFAULT_SPECIFICATIONS,
    componentTypes: DEFAULT_COMPONENT_TYPES,
    statuses: DEFAULT_STATUSES,
  };
}

measureBootStep("first render", () => render());
appBootstrapped = true;
publishBootPerformance();
bindExternalStorageSync();
scheduleSharedStateSyncBootstrap();
setInterval(() => {
  ui.now = new Date();
  updateClockOnly();
}, 30000);

function loadState() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) {
      const restored = restorePlanningStateFromBackups("missing-planning-storage");
      if (restored) return restored;
      return normalizePlanningState(createDefaultPlanningState());
    }
    const parsed = JSON.parse(raw);
    if (parsed?.version !== 1) {
      const restored = restorePlanningStateFromBackups("invalid-planning-version");
      if (restored) return restored;
      return normalizePlanningState(createDefaultPlanningState());
    }
    const normalized = normalizePlanningState(parsed);
    const normalizedRaw = JSON.stringify(normalized);
    if (normalizedRaw !== raw) {
      localStorage.setItem(STORAGE_KEY, normalizedRaw);
    }
    return normalized;
  } catch {
    const restored = restorePlanningStateFromBackups("broken-planning-storage");
    if (restored) return restored;
    return normalizePlanningState(createDefaultPlanningState());
  }
}

function persistState() {
  const previousRaw = localStorage.getItem(STORAGE_KEY);
  const previousState = parsePlanningStateSnapshot(previousRaw);
  if (previousRaw) backupRawPlanningState("before-planning-persist", previousRaw);
  if (previousState && !planningEntityRemovalAllowed) {
    planningState = preserveCriticalPlanningEntities(previousState, planningState);
  }
  localStorage.setItem(STORAGE_KEY, JSON.stringify(planningState));
  scheduleSharedStatePush("planning-state");
}

function recoverPlanningStateFromStorageIfRuntimeEmpty(reason = "runtime-empty") {
  const storedState = parsePlanningStateSnapshot(localStorage.getItem(STORAGE_KEY));
  if (!storedState || !hasMeaningfulPlanningState(storedState) || hasMeaningfulPlanningState(planningState)) return false;
  const restored = recoverPlanningRuntimeSnapshot(storedState);
  if (!hasMeaningfulPlanningState(restored)) return false;
  planningState = restored;
  console.warn(`[MES] Planning state restored from storage after ${reason}.`);
  return true;
}

function recoverPlanningRuntimeSnapshot(snapshot = {}) {
  return {
    ...createDefaultPlanningState(),
    ...snapshot,
    version: 1,
    projects: Array.isArray(snapshot.projects) ? snapshot.projects : [],
    workCenters: mergeMesWorkCenters(Array.isArray(snapshot.workCenters) ? snapshot.workCenters : []),
    routes: Array.isArray(snapshot.routes) ? snapshot.routes : [],
    routeSteps: Array.isArray(snapshot.routeSteps) ? snapshot.routeSteps : [],
    slots: Array.isArray(snapshot.slots) ? snapshot.slots : [],
    shiftMasterAssignments: normalizeShiftMasterRecordMap(snapshot.shiftMasterAssignments, normalizeShiftMasterAssignment),
    dispatchFacts: normalizeShiftMasterRecordMap(snapshot.dispatchFacts, normalizeDispatchFact),
    planningCorrections: normalizeShiftMasterRecordMap(snapshot.planningCorrections, normalizePlanningCorrection),
  };
}

function parsePlanningStateSnapshot(raw) {
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === "object" ? parsed : null;
  } catch {
    return null;
  }
}

function backupRawPlanningState(reason, raw = localStorage.getItem(STORAGE_KEY)) {
  if (!raw) return;
  try {
    const currentHistory = JSON.parse(localStorage.getItem(PLANNING_BACKUP_STORAGE_KEY) || "[]");
    const history = Array.isArray(currentHistory) ? currentHistory : [];
    history.unshift({
      createdAt: new Date().toISOString(),
      reason,
      version: APP_VERSION,
      raw,
    });
    localStorage.setItem(PLANNING_BACKUP_STORAGE_KEY, JSON.stringify(history.slice(0, 12)));
  } catch {
    localStorage.setItem(PLANNING_BACKUP_STORAGE_KEY, JSON.stringify([{
      createdAt: new Date().toISOString(),
      reason,
      version: APP_VERSION,
      raw,
    }]));
  }
}

function collectPlanningRecoverySnapshots() {
  const snapshots = [];
  try {
    const history = JSON.parse(localStorage.getItem(PLANNING_BACKUP_STORAGE_KEY) || "[]");
    if (Array.isArray(history)) {
      history.forEach((entry) => {
        const parsed = parsePlanningStateSnapshot(entry?.raw);
        if (!parsed) return;
        snapshots.push({
          state: parsed,
          reason: entry.reason || "planning-backup",
          createdAt: entry.createdAt || "",
        });
      });
    }
  } catch {}

  try {
    const resetBackup = JSON.parse(localStorage.getItem(STATE_RESET_BACKUP_STORAGE_KEY) || "null");
    const raw = resetBackup?.values?.[STORAGE_KEY];
    const parsed = parsePlanningStateSnapshot(raw);
    if (parsed) {
      snapshots.push({
        state: parsed,
        reason: "state-reset-backup",
        createdAt: resetBackup.createdAt || "",
      });
    }
  } catch {}

  return snapshots;
}

function getCriticalPlanningCounts(state) {
  return {
    routes: Array.isArray(state?.routes) ? state.routes.length : 0,
    routeSteps: Array.isArray(state?.routeSteps) ? state.routeSteps.length : 0,
    slots: Array.isArray(state?.slots) ? state.slots.length : 0,
  };
}

function getPlanningRecoveryScore(snapshot) {
  const counts = getCriticalPlanningCounts(snapshot?.state);
  return counts.routes * 10 + counts.routeSteps + counts.slots;
}

function restorePlanningStateFromBackups(reason) {
  const candidates = collectPlanningRecoverySnapshots()
    .filter((snapshot) => getPlanningRecoveryScore(snapshot) > 0)
    .sort((left, right) => (
      getPlanningRecoveryScore(right) - getPlanningRecoveryScore(left)
      || String(right.createdAt || "").localeCompare(String(left.createdAt || ""))
    ));
  const best = candidates[0];
  if (!best) return null;

  const normalized = normalizePlanningState(best.state);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(normalized));
  console.warn("[MES] Restored planning state from local backup.", {
    reason,
    source: best.reason,
    counts: getCriticalPlanningCounts(normalized),
  });
  return normalized;
}

function preserveCriticalPlanningEntities(previousState, nextState) {
  if (!previousState || !nextState) return nextState;
  const previousCounts = getCriticalPlanningCounts(previousState);
  const nextCounts = getCriticalPlanningCounts(nextState);
  let changed = false;
  const mergedState = { ...nextState };

  if (previousCounts.routes > 0 && nextCounts.routes === 0) {
    mergedState.routes = previousState.routes || [];
    changed = true;
  }
  if (previousCounts.routeSteps > 0 && nextCounts.routeSteps === 0) {
    mergedState.routeSteps = previousState.routeSteps || [];
    changed = true;
  }

  if (!changed) return nextState;

  console.warn("[MES] Prevented critical planning wipe before save.", {
    previousCounts,
    nextCounts,
    mergedCounts: getCriticalPlanningCounts(mergedState),
  });
  return mergedState;
}

function parseDirectoryStateSnapshot(raw) {
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === "object" ? parsed : null;
  } catch {
    return null;
  }
}

function backupRawDirectoryState(reason, raw = localStorage.getItem(DIRECTORY_STORAGE_KEY)) {
  if (!raw) return;
  try {
    const currentHistory = JSON.parse(localStorage.getItem(DIRECTORY_BACKUP_STORAGE_KEY) || "[]");
    const history = Array.isArray(currentHistory) ? currentHistory : [];
    history.unshift({
      createdAt: new Date().toISOString(),
      reason,
      version: APP_VERSION,
      raw,
    });
    localStorage.setItem(DIRECTORY_BACKUP_STORAGE_KEY, JSON.stringify(history.slice(0, 10)));
  } catch {
    localStorage.setItem(DIRECTORY_BACKUP_STORAGE_KEY, JSON.stringify([{
      createdAt: new Date().toISOString(),
      reason,
      version: APP_VERSION,
      raw,
    }]));
  }
}

function collectDirectoryRecoverySnapshots() {
  const snapshots = [];
  try {
    const history = JSON.parse(localStorage.getItem(DIRECTORY_BACKUP_STORAGE_KEY) || "[]");
    if (Array.isArray(history)) {
      history.forEach((entry) => {
        const parsed = parseDirectoryStateSnapshot(entry?.raw);
        if (!parsed) return;
        snapshots.push({
          state: parsed,
          reason: entry.reason || "directory-backup",
          createdAt: entry.createdAt || "",
        });
      });
    }
  } catch {}

  try {
    const resetBackup = JSON.parse(localStorage.getItem(STATE_RESET_BACKUP_STORAGE_KEY) || "null");
    const raw = resetBackup?.values?.[DIRECTORY_STORAGE_KEY];
    const parsed = parseDirectoryStateSnapshot(raw);
    if (parsed) {
      snapshots.push({
        state: parsed,
        reason: "state-reset-backup",
        createdAt: resetBackup.createdAt || "",
      });
    }
  } catch {}

  return snapshots;
}

function getDirectoryRecoveryScore(snapshot) {
  const counts = getCriticalDirectoryCounts(snapshot?.state);
  return counts.bomLists + counts.specifications;
}

function restoreDirectoryStateFromBackups(reason) {
  const candidates = collectDirectoryRecoverySnapshots()
    .filter((snapshot) => getDirectoryRecoveryScore(snapshot) > 0)
    .sort((left, right) => (
      getDirectoryRecoveryScore(right) - getDirectoryRecoveryScore(left)
      || String(right.createdAt || "").localeCompare(String(left.createdAt || ""))
    ));
  const best = candidates[0];
  if (!best) return null;

  const normalized = omitDeletedCriticalDirectoryEntities(normalizeDirectoryState(best.state, { mergeFallback: false }));
  localStorage.setItem(DIRECTORY_STORAGE_KEY, JSON.stringify(normalized));
  localStorage.setItem(DIRECTORY_DEFAULTS_STORAGE_KEY, "1");
  console.warn("[MES] Restored directory state from local backup.", {
    reason,
    source: best.reason,
    counts: getCriticalDirectoryCounts(normalized),
  });
  return normalized;
}

function getCriticalDirectoryCounts(state) {
  return {
    bomLists: Array.isArray(state?.bomLists) ? state.bomLists.length : 0,
    specifications: Array.isArray(state?.specifications) ? state.specifications.length : 0,
  };
}

function getDirectoryRowTimestamp(row) {
  const candidates = [row?.updatedAt, row?.importedAt, row?.createdAt]
    .map((value) => Date.parse(value))
    .filter((value) => Number.isFinite(value));
  return candidates.length ? Math.max(...candidates) : 0;
}

function readDirectoryDeletedEntities() {
  try {
    const parsed = JSON.parse(localStorage.getItem(DIRECTORY_DELETED_ENTITIES_STORAGE_KEY) || "{}");
    return parsed && typeof parsed === "object" ? parsed : {};
  } catch {
    return {};
  }
}

function writeDirectoryDeletedEntities(tombstones) {
  try {
    localStorage.setItem(DIRECTORY_DELETED_ENTITIES_STORAGE_KEY, JSON.stringify(tombstones));
  } catch {}
}

function recordDirectoryEntityDeletion(sectionId, rowId) {
  if (!CRITICAL_DIRECTORY_SECTION_IDS.includes(sectionId) || !rowId) return;
  const tombstones = readDirectoryDeletedEntities();
  tombstones[sectionId] = {
    ...(tombstones[sectionId] || {}),
    [rowId]: Date.now(),
  };
  writeDirectoryDeletedEntities(tombstones);
}

function wasDirectoryEntityDeletedAfter(sectionId, row) {
  const rowId = row?.id;
  if (!rowId) return false;
  const deletedAt = Number(readDirectoryDeletedEntities()?.[sectionId]?.[rowId] || 0);
  return deletedAt > 0 && deletedAt >= getDirectoryRowTimestamp(row);
}

function omitDeletedCriticalDirectoryEntities(state) {
  if (!state) return state;
  let changed = false;
  const nextState = { ...state };
  CRITICAL_DIRECTORY_SECTION_IDS.forEach((sectionId) => {
    const rows = Array.isArray(nextState[sectionId]) ? nextState[sectionId] : [];
    const filteredRows = rows.filter((row) => !wasDirectoryEntityDeletedAfter(sectionId, row));
    if (filteredRows.length !== rows.length) {
      nextState[sectionId] = filteredRows;
      changed = true;
    }
  });
  return changed ? nextState : state;
}

function mergeCriticalDirectorySection(sectionId, previousRows = [], nextRows = []) {
  const canKeepRow = (row) => {
    if (!row) return false;
    if (sectionId === "statuses" && REMOVED_DIRECTORY_STATUS_ID_PREFIXES.some((prefix) => String(row.id || "").startsWith(prefix))) return false;
    return true;
  };
  const previousMaxTimestamp = previousRows
    .filter((row) => canKeepRow(row))
    .reduce((max, row) => Math.max(max, getDirectoryRowTimestamp(row)), 0);
  const merged = [];
  const indexById = new Map();
  let changed = false;

  const remember = (row) => {
    if (!row?.id || !canKeepRow(row)) {
      changed = true;
      return;
    }
    const existingIndex = indexById.get(row.id);
    if (existingIndex === undefined) {
      indexById.set(row.id, merged.length);
      merged.push(row);
      return;
    }
    if (getDirectoryRowTimestamp(row) > getDirectoryRowTimestamp(merged[existingIndex])) {
      merged[existingIndex] = row;
      changed = true;
    }
  };

  previousRows.forEach((row) => {
    if (!canKeepRow(row)) {
      changed = true;
      return;
    }
    if (wasDirectoryEntityDeletedAfter(sectionId, row)) {
      changed = true;
      return;
    }
    remember(row);
  });

  nextRows.forEach((row) => {
    if (!row?.id || !canKeepRow(row)) {
      changed = true;
      return;
    }
    if (wasDirectoryEntityDeletedAfter(sectionId, row)) {
      changed = true;
      return;
    }
    if (indexById.has(row.id)) {
      remember(row);
      return;
    }
    if (!previousRows.length || getDirectoryRowTimestamp(row) > previousMaxTimestamp) {
      remember(row);
      return;
    }
    changed = true;
  });

  if (merged.length !== nextRows.length) changed = true;
  return { rows: merged, changed };
}

function preserveCriticalDirectoryEntities(previousState, nextState) {
  if (!previousState || !nextState) return nextState;
  const mergedState = { ...nextState };
  const changedSections = [];

  CRITICAL_DIRECTORY_SECTION_IDS.forEach((sectionId) => {
    const previousRows = Array.isArray(previousState?.[sectionId]) ? previousState[sectionId] : [];
    const nextRows = Array.isArray(nextState?.[sectionId]) ? nextState[sectionId] : [];
    const merged = mergeCriticalDirectorySection(sectionId, previousRows, nextRows);
    if (merged.changed) {
      mergedState[sectionId] = merged.rows;
      changedSections.push(sectionId);
    }
  });

  if (!changedSections.length) return nextState;

  console.warn("[MES] Reconciled critical directory entities before save.", {
    changedSections,
    previousCounts: getCriticalDirectoryCounts(previousState),
    nextCounts: getCriticalDirectoryCounts(nextState),
    mergedCounts: getCriticalDirectoryCounts(mergedState),
  });

  return mergedState;
}

function withDirectoryEntityRemovalAllowed(callback) {
  const previousValue = directoryEntityRemovalAllowed;
  directoryEntityRemovalAllowed = true;
  try {
    return callback();
  } finally {
    directoryEntityRemovalAllowed = previousValue;
  }
}

function withPlanningEntityRemovalAllowed(callback) {
  const previousValue = planningEntityRemovalAllowed;
  planningEntityRemovalAllowed = true;
  try {
    return callback();
  } finally {
    planningEntityRemovalAllowed = previousValue;
  }
}

function loadDirectoryState() {
  try {
    const raw = localStorage.getItem(DIRECTORY_STORAGE_KEY);
    if (!raw) {
      const restored = restoreDirectoryStateFromBackups("missing-directory-storage");
      if (restored) return restored;
      const fallback = normalizeDirectoryState(createDefaultDirectoryState());
      localStorage.setItem(DIRECTORY_STORAGE_KEY, JSON.stringify(fallback));
      localStorage.setItem(DIRECTORY_DEFAULTS_STORAGE_KEY, "1");
      return fallback;
    }
    const shouldRestoreDefaults = localStorage.getItem(DIRECTORY_DEFAULTS_STORAGE_KEY) !== "1";
    const parsed = JSON.parse(raw);
    let normalized = preserveCriticalDirectoryEntities(
      parsed,
      normalizeDirectoryState(parsed, { mergeFallback: shouldRestoreDefaults }),
    );
    normalized = omitDeletedCriticalDirectoryEntities(normalized);
    const serialized = JSON.stringify(normalized);
    if (serialized !== raw || shouldRestoreDefaults) {
      backupRawDirectoryState("before-directory-load-normalize", raw);
      localStorage.setItem(DIRECTORY_STORAGE_KEY, serialized);
    }
    localStorage.setItem(DIRECTORY_DEFAULTS_STORAGE_KEY, "1");
    return normalized;
  } catch {
    const restored = restoreDirectoryStateFromBackups("broken-directory-storage");
    if (restored) return restored;
    return createDefaultDirectoryState();
  }
}

function ensureStatusDirectoryDefaults() {
  if (!directoryState) return;
  const rows = Array.isArray(directoryState.statuses) ? directoryState.statuses : [];
  const existingIds = new Set(rows.map((row) => row?.id).filter(Boolean));
  const missingRows = DEFAULT_STATUSES.filter((row) => row?.id && !existingIds.has(row.id));
  if (!missingRows.length) return;
  directoryState.statuses = [
    ...rows,
    ...missingRows.map((row) => normalizeDirectoryRow("statuses", row)),
  ];
  persistDirectoryState();
}

function isSameNumericValue(left, right, precision = 0.000001) {
  const leftNumber = Number(left);
  const rightNumber = Number(right);
  return Number.isFinite(leftNumber)
    && Number.isFinite(rightNumber)
    && Math.abs(leftNumber - rightNumber) <= precision;
}

function applySmtComponentTypeCoefficientDefaults() {
  if (!directoryState) return;
  const rows = Array.isArray(directoryState.componentTypes) ? directoryState.componentTypes : [];
  let changed = false;
  const nextRows = rows.map((row) => {
    const defaults = SMT_COMPONENT_TYPE_COEFFICIENT_DEFAULTS[row?.id];
    const previous = SMT_COMPONENT_TYPE_PREVIOUS_COEFFICIENTS[row?.id];
    if (!defaults || !previous) return row;

    const shouldUpdateCoefficient = isSameNumericValue(row.coefficient, previous.coefficient);
    const shouldUpdatePlacements = isSameNumericValue(row.placementsPerHour, previous.placementsPerHour);
    if (!shouldUpdateCoefficient && !shouldUpdatePlacements) return row;

    changed = true;
    return normalizeDirectoryRow("componentTypes", {
      ...row,
      coefficient: shouldUpdateCoefficient ? defaults.coefficient : row.coefficient,
      placementsPerHour: shouldUpdatePlacements ? defaults.placementsPerHour : row.placementsPerHour,
    });
  });

  if (!changed) return;
  directoryState = {
    ...directoryState,
    componentTypes: nextRows,
  };
  persistDirectoryState();
}

function persistDirectoryState() {
  const previousRaw = localStorage.getItem(DIRECTORY_STORAGE_KEY);
  const previousState = parseDirectoryStateSnapshot(previousRaw);
  if (previousRaw) backupRawDirectoryState("before-directory-persist", previousRaw);
  if (previousState && !directoryEntityRemovalAllowed) {
    directoryState = preserveCriticalDirectoryEntities(previousState, directoryState);
  }
  directoryState = omitDeletedCriticalDirectoryEntities(directoryState);
  localStorage.setItem(DIRECTORY_STORAGE_KEY, JSON.stringify(directoryState));
  scheduleSharedStatePush("directory-state");
}

function resolveProductionResourceType(value = "") {
  const text = normalizeLookupText(value);
  if (Object.keys(PRODUCTION_RESOURCE_TYPE_LABELS).includes(text)) return text;
  if (text.includes("агрег")) return "aggregate";
  if (text.includes("линия")) return "line";
  if (text.includes("исполн") || text.includes("сотруд") || text.includes("персон")) return "staff";
  if (text.includes("стан") || text.includes("установ") || text.includes("печ")) return "machine";
  if (text.includes("рабоч") || text.includes("мест")) return "workplace";
  if (text.includes("пост") || text.includes("стенд") || text.includes("инспектор")) return "post";
  if (text.includes("оснаст")) return "tool";
  if (text.includes("норматив")) return "normative";
  return "equipment";
}

function mapLegacyWorkCenterId(workCenterId = "") {
  const id = String(workCenterId || "").trim();
  if (!id) return "";
  if (MES_LEGACY_WORK_CENTER_ID_MAP[id]) return MES_LEGACY_WORK_CENTER_ID_MAP[id];
  if (getProductionStructureWorkCenters(getProductionStructureMatrixRuntimeOverrides()).some((center) => center.id === id)) return id;
  return resolveWorkCenterIdFromName(id) || id;
}

function isWarehouseWorkCenterId(workCenterId = "") {
  return mapLegacyWorkCenterId(workCenterId) === "D1";
}

function hasManufacturingOutputReceiptText(value = "") {
  const text = normalizeLookupText(value);
  if (!text) return false;
  const hasReceiptAction = text.includes("поступ") || text.includes("прием") || text.includes("приём");
  const hasManufacturingSource = text.includes("производ") || text.includes("готов") || text.includes("полуфаб") || text.includes("издел");
  return (
    (hasReceiptAction && hasManufacturingSource)
    || text.includes("выпуск")
    || text.includes("готовой продукции")
    || text.includes("готовых изделий")
    || text.includes("полуфаб")
  );
}

function hasNonOutputWarehouseText(value = "") {
  const text = normalizeLookupText(value);
  return [
    "поставщик",
    "выдач",
    "возврат",
    "перемещ",
    "списан",
    "инвентар",
    "комплектующ",
    "материал",
  ].some((token) => text.includes(token));
}

function isManufacturingOutputReceiptOperation(operation = {}) {
  if (!operation) return false;
  const text = `${operation.name || ""} ${operation.code || ""} ${operation.businessOutput || ""} ${operation.comment || ""}`;
  if (hasNonOutputWarehouseText(text)) return false;
  if (operation.isOutputReceipt || operation.warehouseFlow === "production_receipt") return true;
  if (!isWarehouseWorkCenterId(operation.workCenterId)) return false;
  return hasManufacturingOutputReceiptText(text) && !hasNonOutputWarehouseText(text);
}

function isManufacturingOutputReceiptRouteStep(step = {}) {
  if (!step) return false;
  const text = `${step.operationName || ""} ${step.comment || ""}`;
  if (hasNonOutputWarehouseText(text)) return false;
  const operation = getOperationMapItem(step.operationId);
  if (isManufacturingOutputReceiptOperation(operation)) return true;
  if (!isWarehouseWorkCenterId(step.workCenterId)) return false;
  return hasManufacturingOutputReceiptText(text) && !hasNonOutputWarehouseText(text);
}

function isManufacturingOutputReceiptSlot(slot = {}, state = null) {
  if (!slot) return false;
  const sourceState = state || getRuntimePlanningState();
  const step = (sourceState?.routeSteps || []).find((item) => item.id === slot.routeStepId);
  if (isManufacturingOutputReceiptRouteStep(step)) return true;
  const text = `${slot.operationName || ""} ${slot.comment || ""}`;
  if (hasNonOutputWarehouseText(text)) return false;
  const operation = getOperationMapItem(slot.operationId);
  if (isManufacturingOutputReceiptOperation(operation)) return true;
  if (!isWarehouseWorkCenterId(slot.workCenterId)) return false;
  return hasManufacturingOutputReceiptText(text) && !hasNonOutputWarehouseText(text);
}

function isSmtRouteInstructionWorkCenterId(workCenterId = "") {
  const raw = String(workCenterId || "").trim();
  if (!raw) return false;
  if (raw === "D3" || raw === "smt" || isSmtLineWorkCenterId(raw)) return true;
  const mapped = mapLegacyWorkCenterId(raw);
  return mapped === "D3" || MES_SMT_WORK_CENTER_IDS.includes(mapped);
}

function getRouteInstructionWorkCenterId(workCenterId = "") {
  const raw = String(workCenterId || "").trim();
  if (!raw) return "";
  if (isSmtRouteInstructionWorkCenterId(raw)) return "D3";
  return mapLegacyWorkCenterId(raw);
}

function getOperationRouteWorkCenterId(operation = {}) {
  return getRouteInstructionWorkCenterId(operation.routeWorkCenterId || operation.workCenterId || "");
}

function getPlanningCandidateWorkCenterIdsForRouteWorkCenter(workCenterId = "", operation = null, state = null) {
  const sourceState = state || getRuntimePlanningState();
  const activePlanningIds = new Set((sourceState?.workCenters || [])
    .filter((center) => isPlanningWorkCenter(center))
    .map((center) => center.id));
  const explicitIds = Array.isArray(operation?.planningWorkCenterIds)
    ? operation.planningWorkCenterIds
    : [];
  const normalizedExplicitIds = explicitIds
    .map((id) => mapLegacyWorkCenterId(id))
    .filter((id) => id && activePlanningIds.has(id));
  if (normalizedExplicitIds.length) return [...new Set(normalizedExplicitIds)];

  const routeWorkCenterId = getRouteInstructionWorkCenterId(workCenterId);
  if (!routeWorkCenterId) return [];
  if (routeWorkCenterId === "D3" || isSmtOperationWorkCenter(routeWorkCenterId, operation, sourceState)) {
    const smtIds = MES_SMT_WORK_CENTER_IDS.filter((id) => activePlanningIds.has(id));
    return smtIds.length ? smtIds : [...MES_SMT_WORK_CENTER_IDS];
  }

  const center = sourceState?.workCenters?.find((item) => item.id === routeWorkCenterId);
  if (center && !isPlanningWorkCenter(center)) {
    const children = (sourceState?.workCenters || [])
      .filter((item) => item.parentWorkCenterId === center.id && isPlanningWorkCenter(item))
      .map((item) => item.id);
    if (children.length) return children;
  }

  return activePlanningIds.has(routeWorkCenterId) || !sourceState?.workCenters?.length
    ? [routeWorkCenterId]
    : [];
}

function getRouteStepPlanningCandidateWorkCenterIds(step = {}, state = null) {
  const operation = getOperationMapItem(step.operationId);
  return getPlanningCandidateWorkCenterIdsForRouteWorkCenter(step.workCenterId, operation, state);
}

function getRouteStepExplicitPlanningWorkCenterId(step = {}) {
  return mapLegacyWorkCenterId(step.planningWorkCenterId || step.planningLineWorkCenterId || "");
}

function routeStepRequiresManualPlanningLine(step = {}, state = null) {
  return getRouteStepPlanningCandidateWorkCenterIds(step, state).length > 1;
}

function getRouteStepSelectedPlanningWorkCenterId(step = {}, state = null, options = {}) {
  const sourceState = state || getRuntimePlanningState();
  const candidates = getRouteStepPlanningCandidateWorkCenterIds(step, sourceState);
  if (!candidates.length) return mapLegacyWorkCenterId(step.workCenterId || "");
  const explicitWorkCenterId = getRouteStepExplicitPlanningWorkCenterId(step);
  if (explicitWorkCenterId && candidates.includes(explicitWorkCenterId)) return explicitWorkCenterId;
  const currentWorkCenterId = mapLegacyWorkCenterId(options.currentWorkCenterId || "");
  if (currentWorkCenterId && candidates.includes(currentWorkCenterId)) return currentWorkCenterId;
  return candidates.length === 1 ? candidates[0] : "";
}

function isPlanningWorkCenterCompatibleWithRouteStep(step = {}, planningWorkCenterId = "", state = null) {
  const normalizedId = mapLegacyWorkCenterId(planningWorkCenterId);
  return getRouteStepPlanningCandidateWorkCenterIds(step, state).includes(normalizedId);
}

function getPlanningResourceForRouteStep(step = {}, planningWorkCenterId = "", preferredResourceId = "") {
  const normalizedWorkCenterId = mapLegacyWorkCenterId(planningWorkCenterId);
  const normalizedPreferredResourceId = mapLegacyResourceId(preferredResourceId);
  const preferredResource = normalizedPreferredResourceId ? getProductionResource(normalizedPreferredResourceId) : null;
  if (
    preferredResource
    && getProductionResourceWorkCenterId(preferredResource) === normalizedWorkCenterId
    && (resourceParticipatesInPlanning(preferredResource) || resourceParticipatesInCalculation(preferredResource))
  ) {
    return preferredResource.id;
  }
  const resources = getResourcesForWorkCenter(normalizedWorkCenterId);
  return resources[0]?.id || "";
}

function getPlanningAssignmentForRouteStep(step = {}, quantity = 1, readyAt = null, options = {}) {
  const sourceState = options.state || getRuntimePlanningState();
  const candidates = getRouteStepPlanningCandidateWorkCenterIds(step, sourceState);
  const fallbackWorkCenterId = mapLegacyWorkCenterId(step.workCenterId || "");
  const candidateIds = candidates.length ? candidates : [fallbackWorkCenterId].filter(Boolean);
  let fallbackStart = new Date();
  try {
    fallbackStart = fromDateInput(ui?.windowStart || defaultUiState.windowStart);
  } catch {
    fallbackStart = new Date();
  }
  const earliestStart = readyAt || fallbackStart;
  const assignments = candidateIds.map((workCenterId) => {
    const resourceId = getPlanningResourceForRouteStep(step, workCenterId, options.preferredResourceId || step.resourceId || "");
    const route = getRouteForStep(step);
    const context = getRouteStepEffectiveOperationContext(route, step, workCenterId, resourceId);
    const laborPlan = getPlanningOrderLaborPlan(route, step, { quantity, workCenterId, state: sourceState });
    const durationMs = laborPlan?.mode && laborPlan.mode !== "calculator"
      ? laborPlan.durationMs
      : calculateRequiredDurationMs(workCenterId, quantity, sourceState, null, context.boardsPerPanel || null, context);
    const window = findFreeWindow(workCenterId, durationMs, earliestStart, options.ignoreSlotId || null, resourceId || "");
    return {
      workCenterId,
      resourceId,
      durationMs,
      window,
      laborPlan,
    };
  });
  return assignments.sort((left, right) => (
    toDate(left.window.end) - toDate(right.window.end)
    || toDate(left.window.start) - toDate(right.window.start)
  ))[0] || {
    workCenterId: fallbackWorkCenterId,
    resourceId: step.resourceId || "",
    durationMs: 0,
    window: { start: earliestStart, end: earliestStart },
  };
}

function getManualPlanningAssignmentForRouteStep(step = {}, quantity = 1, readyAt = null, options = {}) {
  const sourceState = options.state || getRuntimePlanningState();
  const workCenterId = getRouteStepSelectedPlanningWorkCenterId(step, sourceState, {
    currentWorkCenterId: options.currentWorkCenterId || "",
  });
  if (!workCenterId) return null;
  let fallbackStart = new Date();
  try {
    fallbackStart = fromDateInput(ui?.windowStart || defaultUiState.windowStart);
  } catch {
    fallbackStart = new Date();
  }
  const earliestStart = readyAt || fallbackStart;
  const resourceId = getPlanningResourceForRouteStep(step, workCenterId, options.preferredResourceId || step.resourceId || "");
  const route = getRouteForStep(step);
  const context = getRouteStepEffectiveOperationContext(route, step, workCenterId, resourceId);
  const laborPlan = getPlanningOrderLaborPlan(route, step, { quantity, workCenterId, state: sourceState });
  const durationMs = laborPlan?.mode && laborPlan.mode !== "calculator"
    ? laborPlan.durationMs
    : calculateRequiredDurationMs(workCenterId, quantity, sourceState, null, context.boardsPerPanel || null, context);
  const window = findFreeWindow(workCenterId, durationMs, earliestStart, options.ignoreSlotId || null, resourceId || "");
  return {
    workCenterId,
    resourceId,
    durationMs,
    window,
    laborPlan,
  };
}

function getRouteStepPlanningAssignmentForSlot(step = {}, slot = {}, options = {}) {
  const sourceState = options.state || getRuntimePlanningState();
  const quantity = normalizeQuantity(options.quantity ?? slot.quantity ?? 1, 1);
  const readyAt = options.readyAt || slot.plannedStart || null;
  const preferredResourceId = options.preferredResourceId ?? slot.resourceId ?? step.resourceId ?? "";
  const currentWorkCenterId = mapLegacyWorkCenterId(options.workCenterId || slot.workCenterId || "");
  if (currentWorkCenterId && isPlanningWorkCenterCompatibleWithRouteStep(step, currentWorkCenterId, sourceState)) {
    return {
      workCenterId: currentWorkCenterId,
      resourceId: getPlanningResourceForRouteStep(step, currentWorkCenterId, preferredResourceId),
      durationMs: 0,
      window: null,
    };
  }
  const manualAssignment = getManualPlanningAssignmentForRouteStep(step, quantity, readyAt, {
    state: sourceState,
    ignoreSlotId: options.ignoreSlotId ?? slot.id ?? null,
    preferredResourceId,
    currentWorkCenterId,
  });
  if (manualAssignment) return manualAssignment;
  if (routeStepRequiresManualPlanningLine(step, sourceState)) return null;
  return getPlanningAssignmentForRouteStep(step, quantity, readyAt, {
    state: sourceState,
    ignoreSlotId: options.ignoreSlotId ?? slot.id ?? null,
    preferredResourceId,
  });
}

function resolveWorkCenterIdFromName(value = "") {
  const normalized = normalizeLookupText(value);
  if (!normalized) return "";
  const direct = getWorkCenter(value);
  if (direct) return direct.id;
  const mappedById = MES_LEGACY_WORK_CENTER_ID_MAP[String(value || "")];
  if (mappedById) return mappedById;
  const mappedByName = Object.entries(MES_LEGACY_WORK_CENTER_NAME_MAP)
    .find(([name]) => normalizeLookupText(name) === normalized)?.[1];
  if (mappedByName) return mappedByName;
  const lineNumber = getSmtLineNumberFromText(value);
  if (lineNumber === 1) return "D3_L1";
  if (lineNumber === 2) return "D3_L2";
  if (normalized.includes("офлайн") && (normalized.includes("аои") || normalized.includes("aoi"))) return "D3_AOI";
  const exact = (getRuntimePlanningState()?.workCenters || []).find((center) => (
    normalizeLookupText(center.id) === normalized
    || normalizeLookupText(center.name) === normalized
    || normalizeLookupText(center.code) === normalized
    || (center.legacyDepartmentNames || []).some((name) => normalizeLookupText(name) === normalized)
  ));
  if (exact) return exact.id;
  if (normalized.includes("smt") || normalized.includes("смт") || normalized.includes("поверхност")) return "D3";
  if (normalized.includes("aoi") || normalized.includes("аои")) return "D3_AOI";
  if (normalized.includes("отмыв")) return "D3_UW";
  if (normalized.includes("руч") || normalized.includes("tht") || normalized.includes("вывод")) return "D5";
  if (normalized.includes("испыт") || normalized.includes("контрол") || normalized.includes("отк")) return "D4";
  if (normalized.includes("селектив") || normalized.includes("влагозащ")) return "D3_CC";
  if (normalized.includes("лак")) return "D3_CC";
  if (normalized.includes("программ") || normalized.includes("прошив")) return "D6";
  if (normalized.includes("слесар") || normalized.includes("механ") || normalized.includes("сбор")) return "D9";
  if (normalized.includes("маркиров") || normalized.includes("упаков")) return "D11";
  if (normalized.includes("склад")) return "D1";
  return "";
}

function getProductionResourceWorkCenterId(resource = {}) {
  return resource.workCenterId || resolveWorkCenterIdFromName(resource.workCenter || resource.line || resource.department || "");
}

function normalizeProductionResourceCapacity(value = "") {
  return String(value || "")
    .replace(/партия/gi, "операция")
    .replace(/партии/gi, "операции")
    .trim();
}

function normalizeProductionResource(row = {}) {
  const workCenterId = getProductionResourceWorkCenterId(row) || "D5";
  const center = getWorkCenter(workCenterId);
  const type = resolveProductionResourceType(row.type || row.resourceType || row.kind || "");
  const isLegacyEquipment = row.sourceKind === "equipment";
  const participatesInPlanning = row.participatesInPlanning ?? row.planningStatus ?? (isLegacyEquipment ? "no" : "yes");
  const participatesInCalculation = row.participatesInCalculation ?? row.calculationStatus ?? (isLegacyEquipment ? "no" : "yes");

  return {
    ...row,
    id: row.id || makeId("res"),
    name: String(row.name || "Производственный ресурс").trim(),
    type,
    workCenterId,
    workCenter: center?.name || row.workCenter || "",
    parentResourceId: row.parentResourceId || "",
    inventory: String(row.inventory || "").trim(),
    maintenance: String(row.maintenance || "").trim(),
    capacity: normalizeProductionResourceCapacity(row.capacity),
    baseCph: Math.max(0, Number(row.baseCph || 0)),
    efficiency: Math.max(0, Number(row.efficiency || 0)),
    changeoverMin: Math.max(0, Number(row.changeoverMin || 0)),
    participatesInPlanning: participatesInPlanning === true || participatesInPlanning === "yes" ? "yes" : "no",
    participatesInCalculation: participatesInCalculation === true || participatesInCalculation === "yes" ? "yes" : "no",
    sourceKind: row.sourceKind || "productionResource",
    status: String(row.status || "Доступен").trim(),
  };
}

function getSmtLineParentResourceId(value = "", resources = []) {
  const lineNumber = getSmtLineNumberFromText(value);
  if (!lineNumber) return "";
  const line = findSmtLineByNumber(lineNumber, resources);
  return line?.id || "";
}

function migrateLegacyResourceRow(row = {}) {
  return normalizeProductionResource({
    ...row,
    sourceKind: "resource",
    workCenterId: resolveWorkCenterIdFromName(row.workCenter),
    participatesInPlanning: "yes",
    participatesInCalculation: "yes",
  });
}

function migrateLegacyEquipmentRow(row = {}, migratedResources = []) {
  const parentResourceId = getSmtLineParentResourceId(row.workCenter, migratedResources);
  return normalizeProductionResource({
    ...row,
    type: row.type || "equipment",
    sourceKind: "equipment",
    workCenterId: resolveWorkCenterIdFromName(row.workCenter),
    parentResourceId,
    capacity: "",
    baseCph: 0,
    efficiency: 0,
    changeoverMin: 0,
    participatesInPlanning: "no",
    participatesInCalculation: "no",
  });
}

function dedupeProductionResources(rows = []) {
  const result = [];
  const seen = new Set();
  rows.forEach((row) => {
    const normalized = normalizeProductionResource(row);
    const key = normalized.id || `${normalizeLookupText(normalized.name)}::${normalized.workCenterId}`;
    if (seen.has(key)) return;
    seen.add(key);
    result.push(normalized);
  });
  return result;
}

function mapLegacyResourceId(resourceId = "") {
  const id = String(resourceId || "").trim();
  if (!id) return "";
  const directMap = {
    "res-smt-1": "D3_L1_MATRIX",
    "smt-line-1": "D3_L1_MATRIX",
    "res-smt-2": "D3_L2_MATRIX",
    "smt-line-2": "D3_L2_MATRIX",
    "res-aoi-offline": "EQ-S-AOI-PEMTRON-1",
    "res-manual-a": "D5_MATRIX",
    "res-test": "D4_MATRIX",
    "eq-smt1-hanwha-s2": "EQ-S-SMT-1-S2-L2-1",
    "eq-smt1-hanwha-l2": "EQ-S-SMT-1-S2-L2-1",
    "eq-smt1-oven": "EQ-S-SMT-1-S2-L2-1",
    "eq-smt2-hanwha-s2": "EQ-S-SMT-2-S2-1",
    "eq-smt2-oven": "EQ-S-SMT-2-S2-1",
    "eq-smt2-aoi": "EQ-S-AOI-PEMTRON-1",
    "eq-aoi-athena": "EQ-S-AOI-PEMTRON-1",
    "eq-cleaner": "EQ-S-WASH-UZ-3-1-1",
    "eq-ict": "D4_MATRIX",
    "eq-warehouse": "D1_MATRIX",
    D1_STAFF: "D1_MATRIX",
    D3_L1: "D3_L1_MATRIX",
    D3_UW_E1: "EQ-S-WASH-UZ-3-1-1",
    D4_STAFF: "D4_MATRIX",
    D5_STAFF: "D5_MATRIX",
    D6_STAFF: "D6_MATRIX",
    D9_STAFF: "D9_MATRIX",
    D11_STAFF: "D11_MATRIX",
  };
  return directMap[id] || id;
}

function isLegacyGeneratedOperation(operation = {}) {
  const id = String(operation.id || "");
  if (id.startsWith("op-default-")) return true;
  if (id.startsWith("op-") && MES_OBSOLETE_WORK_CENTER_IDS.has(operation.workCenterId)) return true;
  return false;
}

function findMesOperationReplacement(source = {}) {
  const mappedWorkCenterId = mapLegacyWorkCenterId(source.workCenterId || source.departmentName || source.workCenter || "");
  const normalizedName = normalizeLookupText(source.operationName || source.name || "");
  const byId = MES_OPERATION_MAP.find((operation) => operation.id === source.operationId || operation.id === source.id);
  if (byId?.legacyAliasOf) return MES_OPERATION_MAP.find((operation) => operation.id === byId.legacyAliasOf) || byId;
  if (byId) return byId;
  const exact = MES_OPERATION_MAP.find((operation) => (
    operation.workCenterId === mappedWorkCenterId
    && normalizeLookupText(operation.name) === normalizedName
  ));
  if (exact) return exact;
  if (
    (mappedWorkCenterId === "D1" || normalizedName.includes("склад") || normalizedName.includes("готов") || normalizedName.includes("полуфаб"))
    && hasManufacturingOutputReceiptText(normalizedName)
    && !hasNonOutputWarehouseText(normalizedName)
  ) {
    return MES_OPERATION_MAP.find((operation) => operation.id === "D1_OP2");
  }
  if (MES_SMT_WORK_CENTER_IDS.includes(mappedWorkCenterId) || normalizedName.includes("smt") || normalizedName.includes("смт")) {
    return MES_OPERATION_MAP.find((operation) => operation.id === "D3_L1_OP");
  }
  if (mappedWorkCenterId === "D3_AOI" || normalizedName.includes("aoi") || normalizedName.includes("аои")) return MES_OPERATION_MAP.find((operation) => operation.id === "D3_AOI_OP");
  if (mappedWorkCenterId === "D3_UW" || normalizedName.includes("отмыв")) return MES_OPERATION_MAP.find((operation) => operation.id === "D3_UW_OP");
  if (mappedWorkCenterId === "D5" || normalizedName.includes("руч") || normalizedName.includes("tht") || normalizedName.includes("пайк")) return MES_OPERATION_MAP.find((operation) => operation.id === "D5_OP1");
  if (mappedWorkCenterId === "D4" || normalizedName.includes("контрол") || normalizedName.includes("тест")) return MES_OPERATION_MAP.find((operation) => operation.id === "D4_OP2");
  if (mappedWorkCenterId === "D3_CC" || normalizedName.includes("влагозащ") || normalizedName.includes("селектив")) return MES_OPERATION_MAP.find((operation) => operation.id === "D3_CC_OP");
  if (normalizedName.includes("лакир")) return MES_OPERATION_MAP.find((operation) => operation.id === "D3_MANUAL_CC_OP");
  if (mappedWorkCenterId === "D6" || normalizedName.includes("прошив")) return MES_OPERATION_MAP.find((operation) => operation.id === "D6_OP1");
  if (mappedWorkCenterId === "D9" || normalizedName.includes("слесар") || normalizedName.includes("сбор")) return MES_OPERATION_MAP.find((operation) => operation.id === "D9_OP1");
  if (mappedWorkCenterId === "D11" || normalizedName.includes("маркир")) return MES_OPERATION_MAP.find((operation) => operation.id === "D11_OP1");
  if (mappedWorkCenterId === "D11" || normalizedName.includes("упаков")) return MES_OPERATION_MAP.find((operation) => operation.id === "D11_OP2");
  return null;
}

function mergeMesOperationMap(rows = []) {
  const mesIds = new Set(MES_OPERATION_MAP.map((operation) => operation.id));
  const normalizedDefaults = MES_OPERATION_MAP.map((operation) => normalizeDirectoryRow("operations", operation));
  const customRows = (Array.isArray(rows) ? rows : [])
    .filter((operation) => operation?.id && !mesIds.has(operation.id) && !isLegacyGeneratedOperation(operation))
    .map((operation) => {
      const replacement = findMesOperationReplacement(operation);
      if (replacement) return null;
      return normalizeDirectoryRow("operations", {
        ...operation,
        workCenterId: mapLegacyWorkCenterId(operation.workCenterId),
      });
    })
    .filter(Boolean);
  return [...normalizedDefaults, ...customRows];
}

function normalizeMesRouteEntity(entity = {}) {
  const replacementOperation = findMesOperationReplacement(entity);
  const nextWorkCenterId = replacementOperation
    ? getOperationRouteWorkCenterId(replacementOperation)
    : getRouteInstructionWorkCenterId(entity.workCenterId || "");
  const planningCandidates = getPlanningCandidateWorkCenterIdsForRouteWorkCenter(nextWorkCenterId, replacementOperation, planningState);
  const explicitPlanningWorkCenterId = mapLegacyWorkCenterId(entity.planningWorkCenterId || "");
  const selectedPlanningWorkCenterId = explicitPlanningWorkCenterId && planningCandidates.includes(explicitPlanningWorkCenterId)
    ? explicitPlanningWorkCenterId
    : planningCandidates.length === 1 ? planningCandidates[0] : "";
  return {
    ...entity,
    operationId: replacementOperation?.id || entity.operationId || "",
    operationName: replacementOperation?.name || entity.operationName || entity.name || "",
    workCenterId: nextWorkCenterId || entity.workCenterId || "",
    planningWorkCenterId: selectedPlanningWorkCenterId && planningCandidates.length > 1 ? selectedPlanningWorkCenterId : "",
    resourceId: selectedPlanningWorkCenterId
      ? getPlanningResourceForRouteStep({ ...entity, workCenterId: nextWorkCenterId }, selectedPlanningWorkCenterId, mapLegacyResourceId(entity.resourceId || ""))
      : "",
    unitsPerHour: replacementOperation?.unitsPerHour || entity.unitsPerHour || getWorkCenterUnitsPerHour(nextWorkCenterId) || 0,
    requiresBatch: replacementOperation?.requiresBatch ?? entity.requiresBatch,
    isWarehouseOperation: replacementOperation?.isWarehouse ?? entity.isWarehouseOperation,
  };
}

function replaceLegacyOrganizationTerms(value) {
  return String(value || "")
    .replace(/Все подразделения/g, "Все отделы")
    .replace(/все подразделения/g, "все отделы")
    .replace(/Подразделения,/g, "Отделы,")
    .replace(/подразделения,/g, "отделы,")
    .replace(/подразделениями/gi, "отделами")
    .replace(/подразделениях/gi, "отделах")
    .replace(/подразделениям/gi, "отделам")
    .replace(/подразделений/gi, "отделов")
    .replace(/подразделения/gi, "отдела")
    .replace(/подразделение/gi, "отдел");
}

function normalizeDirectoryOrganizationTerminology() {
  if (!directoryState) return false;
  let changed = false;
  const normalizeRowFields = (row, fields) => {
    let rowChanged = false;
    const nextRow = { ...row };
    fields.forEach((field) => {
      if (!Object.prototype.hasOwnProperty.call(nextRow, field)) return;
      const nextValue = replaceLegacyOrganizationTerms(nextRow[field]);
      if (nextValue === String(nextRow[field] || "")) return;
      nextRow[field] = nextValue;
      rowChanged = true;
    });
    if (rowChanged) changed = true;
    return rowChanged ? nextRow : row;
  };

  directoryState.statuses = (directoryState.statuses || []).map((row) => normalizeRowFields(row, ["group", "name", "type", "usage", "annotation", "impact", "originModule", "changeModule"]));
  return changed;
}

function applyMesOrgStructureDefaults() {
  let planningChanged = false;
  let directoryChanged = false;

  const previousWorkCenters = JSON.stringify(planningState.workCenters || []);
  planningState.workCenters = mergeMesWorkCenters(planningState.workCenters);
  planningChanged = planningChanged || previousWorkCenters !== JSON.stringify(planningState.workCenters || []);

  const nextRouteSteps = (planningState.routeSteps || []).map((step) => normalizeRouteStepCalculationFields(normalizeMesRouteEntity(step), planningState));
  if (JSON.stringify(nextRouteSteps) !== JSON.stringify(planningState.routeSteps || [])) {
    planningState.routeSteps = nextRouteSteps;
    planningChanged = true;
  }

  const routeStepById = new Map((planningState.routeSteps || []).map((step) => [step.id, step]));
  const nextSlots = (planningState.slots || []).map((slot) => {
    const step = routeStepById.get(slot.routeStepId);
    const currentWorkCenterId = mapLegacyWorkCenterId(slot.workCenterId || "");
    const planningWorkCenterId = step && isPlanningWorkCenterCompatibleWithRouteStep(step, currentWorkCenterId, planningState)
      ? currentWorkCenterId
      : step
        ? getManualPlanningAssignmentForRouteStep(step, slot.quantity || 1, slot.plannedStart || new Date(), {
          state: planningState,
          ignoreSlotId: slot.id,
          currentWorkCenterId,
        })?.workCenterId || currentWorkCenterId
        : currentWorkCenterId;
    const resourceId = step
      ? getPlanningResourceForRouteStep(step, planningWorkCenterId, slot.resourceId || step.resourceId || "")
      : mapLegacyResourceId(slot.resourceId || "");
    return recalculateSlotEndByQuantity({
      ...slot,
      routeWorkCenterId: step?.workCenterId || slot.routeWorkCenterId || "",
      workCenterId: planningWorkCenterId,
      routeStepId: slot.routeStepId,
      operationName: step?.operationName || slot.operationName || "",
      operationId: step?.operationId || slot.operationId || "",
      resourceId,
      unitsPerHour: step?.unitsPerHour || slot.unitsPerHour || 0,
      calculationType: step?.calculationType || slot.calculationType || "",
      secondsPerPanel: step?.secondsPerPanel || slot.secondsPerPanel || 0,
      setupMin: step?.setupMin || slot.setupMin || 0,
    }, planningState);
  });
  if (!arraysHaveSameFields(nextSlots, planningState.slots || [], STARTUP_SLOT_COMPARE_FIELDS)) {
    planningState.slots = nextSlots;
    planningChanged = true;
  }

  const nextOperationMap = mergeMesOperationMap(directoryState.operationMap);
  if (JSON.stringify(nextOperationMap) !== JSON.stringify(directoryState.operationMap || [])) {
    directoryState.operationMap = nextOperationMap;
    directoryChanged = true;
  }

  if (
    (directoryState.resources || []).length
    || (directoryState.equipment || []).length
    || (directoryState.departments || []).length
    || (directoryState.productionResources || []).length
    || (directoryState.norms || []).length
    || (directoryState.employees || []).length
  ) {
    // Legacy cleanup only: production organization now comes from the structure matrix.
    directoryState.resources = [];
    directoryState.equipment = [];
    directoryState.departments = [];
    directoryState.productionResources = [];
    directoryState.norms = [];
    directoryState.employees = [];
    directoryChanged = true;
  }

  if (normalizeDirectoryOrganizationTerminology()) {
    directoryChanged = true;
  }

  if (planningChanged) {
    planningState = normalizePlanningState(planningState);
    persistState();
  }
  if (directoryChanged) {
    directoryState = normalizeDirectoryState(directoryState, { mergeFallback: false });
    persistDirectoryState();
  }
}

function buildDefaultProductionResources() {
  return dedupeProductionResources(getProductionStructureResources(getProductionStructureMatrixRuntimeOverrides()));
}

function getProductionResources({ includeInactive = false } = {}) {
  const rows = buildDefaultProductionResources();
  return dedupeProductionResources(rows)
    .filter((resource) => includeInactive || !["Отключен", "inactive"].includes(resource.status));
}

function getProductionResource(resourceId) {
  return getProductionResources({ includeInactive: true }).find((resource) => resource.id === resourceId) || null;
}

function resourceParticipatesInPlanning(resource = {}) {
  return resource.participatesInPlanning !== "no" && !["Отключен", "inactive"].includes(resource.status);
}

function resourceParticipatesInCalculation(resource = {}) {
  return resource.participatesInCalculation !== "no" && !["Отключен", "inactive"].includes(resource.status);
}

function getProductionResourcesForWorkCenter(workCenterId, { includeInactive = false, includePassive = false } = {}) {
  const resolvedId = getCalendarWorkCenterId(workCenterId);
  return getProductionResources({ includeInactive })
    .filter((resource) => getProductionResourceWorkCenterId(resource) === resolvedId)
    .filter((resource) => includePassive || resourceParticipatesInPlanning(resource) || resourceParticipatesInCalculation(resource));
}

function makeFallbackProductionResource(workCenterId) {
  const center = getWorkCenter(workCenterId) || { id: workCenterId, name: "Отдел", code: workCenterId };
  return normalizeProductionResource({
    id: `resource-${center.id}-matrix-missing`,
    name: `${center.name} · ресурс не задан`,
    type: "staff",
    workCenterId: center.id,
    workCenter: center.name,
    capacity: "нет строки в матрице структуры",
    baseCph: 0,
    efficiency: 0,
    changeoverMin: 0,
    participatesInPlanning: "no",
    participatesInCalculation: "no",
    status: "Требует матрицу",
  });
}

function normalizeUnitType(value, row = {}) {
  const raw = String(value || row.unitType || row.type || "").trim().toLowerCase();
  if (["production", "administrative", "warehouse", "quality", "service"].includes(raw)) return raw;
  const text = `${row.id || ""} ${row.name || ""} ${row.code || ""}`.toLowerCase();
  if (text.includes("warehouse") || text.includes("склад")) return "warehouse";
  if (text.includes("отк") || text.includes("aoi") || text.includes("аои") || text.includes("контроль") || text.includes("test")) return "quality";
  if (text.includes("план") || text.includes("закуп") || text.includes("снаб") || text.includes("программ")) return "administrative";
  return "production";
}

function isPlanningWorkCenter(center) {
  return Boolean(center) && center.isActive !== false && center.isPlanningUnit !== false && center.showInGantt !== false;
}

function getPlanningWorkCenters({ includeWarehouse = true } = {}) {
  const sourceState = getRuntimePlanningState({ workCenters: getProductionStructureWorkCenters(getProductionStructureMatrixRuntimeOverrides()) });
  return (sourceState?.workCenters || [])
    .filter((center) => isPlanningWorkCenter(center))
    .filter((center) => includeWarehouse || !isWarehouseWorkCenterId(center.id));
}

function isRouteInstructionWorkCenter(center) {
  if (!center || center.isActive === false) return false;
  if (center.id === "D3") return true;
  if (MES_SMT_WORK_CENTER_IDS.includes(center.id)) return false;
  return isPlanningWorkCenter(center);
}

function getRouteInstructionWorkCenters({ includeWarehouse = true } = {}) {
  const sourceState = getRuntimePlanningState({ workCenters: getProductionStructureWorkCenters(getProductionStructureMatrixRuntimeOverrides()) });
  return (sourceState?.workCenters || [])
    .filter((center) => isRouteInstructionWorkCenter(center))
    .filter((center) => includeWarehouse || !isWarehouseWorkCenterId(center.id));
}

function normalizeWorkSchedule(value, fallback = "5/2") {
  const text = String(value || "").trim().toLowerCase();
  if (!text) return fallback || "";
  if (text.includes("24/7") || text.includes("7/0")) return "24/7";
  if (text.includes("6/1")) return "6/1";
  if (text.includes("2/2")) return "2/2";
  if (text.includes("5/2")) return "5/2";
  return fallback || "";
}

function normalizeWorkMode(value, fallback = "08:00-20:00") {
  const match = String(value || "").trim().match(/(\d{1,2}):(\d{2})\s*[-–—]\s*(\d{1,2}):(\d{2})/);
  if (!match) return fallback || "";
  const startHour = Math.max(0, Math.min(23, Number(match[1])));
  const startMinute = Math.max(0, Math.min(59, Number(match[2])));
  const endHour = Math.max(0, Math.min(24, Number(match[3])));
  const endMinute = Math.max(0, Math.min(59, Number(match[4])));
  return `${String(startHour).padStart(2, "0")}:${String(startMinute).padStart(2, "0")}-${String(endHour).padStart(2, "0")}:${String(endMinute).padStart(2, "0")}`;
}

function getDefaultWorkMode(workSchedule, isWarehouse = false) {
  if (workSchedule === "24/7" || isWarehouse) return "00:00-24:00";
  return "08:00-20:00";
}

function formatWorkShift(workSchedule, workMode) {
  if (!workSchedule) return "";
  if (workSchedule === "2/2") return `2/2 бригады · ежедневно${workMode ? ` ${workMode}` : ""}`.trim();
  return `${workSchedule}${workMode ? ` ${workMode}` : ""}`.trim();
}

function getWorkCalendarLabel(workCenter = {}) {
  const schedule = normalizeWorkSchedule(workCenter.workSchedule || workCenter.shift, isWarehouseWorkCenterId(workCenter.id) ? "24/7" : "5/2");
  const mode = normalizeWorkMode(workCenter.workMode || workCenter.shift, getDefaultWorkMode(schedule, isWarehouseWorkCenterId(workCenter.id) || workCenter.unitType === "warehouse"));
  return formatWorkShift(schedule, mode) || "график не задан";
}

function normalizeWorkCenterUnit(center = {}) {
  const migratedName = LEGACY_WORK_CENTER_NAME_MIGRATION[center.name] || center.name;
  const unitType = normalizeUnitType(center.unitType, center);
  const isWarehouse = isWarehouseWorkCenterId(center.id) || unitType === "warehouse";
  const isAdministrative = unitType === "administrative";
  const isPlanningUnit = center.isPlanningUnit === undefined
    ? !isAdministrative
    : Boolean(center.isPlanningUnit);
  const showInGantt = center.showInGantt === undefined ? isPlanningUnit : Boolean(center.showInGantt);
  const unitsPerHour = isPlanningUnit
    ? Math.max(0, Number(center.unitsPerHour || 0))
    : Math.max(0, Number(center.unitsPerHour || 0));
  const capacity = isPlanningUnit
    ? Math.max(1, Number(center.capacity || 1))
    : Math.max(0, Number(center.capacity || 0));
  const defaultSchedule = isPlanningUnit ? (isWarehouse ? "24/7" : "5/2") : "";
  const workSchedule = normalizeWorkSchedule(center.workSchedule || center.shift, defaultSchedule);
  const workMode = normalizeWorkMode(center.workMode || center.shift, isPlanningUnit ? getDefaultWorkMode(workSchedule, isWarehouse) : "");

  return {
    ...center,
    name: migratedName,
    unitType,
    owner: String(center.owner || "").trim(),
    isPlanningUnit,
    showInGantt,
    unitsPerHour,
    capacity,
    workSchedule,
    workMode,
    shift: formatWorkShift(workSchedule, workMode),
    isActive: center.isActive !== false,
  };
}

function getLegacyDepartmentTargetCenterId(departmentName = "") {
  const direct = LEGACY_DEPARTMENT_TO_WORK_CENTER_ID[departmentName];
  if (direct) return direct;
  const normalized = normalizeLookupText(EMPLOYEE_DEPARTMENT_MIGRATION[departmentName] || departmentName);
  const sourceState = getRuntimePlanningState({ workCenters: getProductionStructureWorkCenters(getProductionStructureMatrixRuntimeOverrides()) });
  const exact = (sourceState?.workCenters || []).find((center) => (
    normalizeLookupText(center.name) === normalized
    || normalizeLookupText(center.code) === normalized
  ));
  if (exact) return exact.id;
  return "";
}

function getUnifiedUnitName(name = "") {
  const migratedName = LEGACY_WORK_CENTER_NAME_MIGRATION[EMPLOYEE_DEPARTMENT_MIGRATION[name] || name] || EMPLOYEE_DEPARTMENT_MIGRATION[name] || name;
  const targetId = getLegacyDepartmentTargetCenterId(migratedName);
  const target = targetId ? getWorkCenter(targetId) : null;
  if (target?.name) return target.name;
  return migratedName;
}

function migrateSpecificationDepartmentNames(renameMap) {
  if (!renameMap.size) return false;
  let changed = false;
  directoryState.specifications = (directoryState.specifications || []).map((specification) => {
    let specificationChanged = false;
    const nextItems = getSpecificationStructureItems(specification).map((item) => {
      const nextDepartmentName = renameMap.get(item.departmentName) || item.departmentName;
      if (nextDepartmentName === item.departmentName) return item;
      specificationChanged = true;
      return { ...item, departmentName: nextDepartmentName };
    });
    if (!specificationChanged) return specification;
    changed = true;
    return { ...specification, structureItems: nextItems };
  });
  return changed;
}

function migrateDepartmentsToUnifiedWorkCenters() {
  if (!planningState || !directoryState) return;
  // Legacy cleanup only: old directory departments can rename existing matrix-derived centers, but cannot create new ones.
  const legacyDepartments = Array.isArray(directoryState.departments) ? directoryState.departments : [];
  const renameMap = new Map();
  let planningChanged = false;
  let directoryChanged = false;

  planningState.workCenters = (planningState.workCenters || []).map((center) => {
    const normalizedCenter = normalizeWorkCenterUnit(center);
    if (center.name && normalizedCenter.name !== center.name) {
      renameMap.set(center.name, normalizedCenter.name);
      planningChanged = true;
    }
    return normalizedCenter;
  });

  legacyDepartments.forEach((department) => {
    if (!department?.name) return;
    const targetId = getLegacyDepartmentTargetCenterId(department.name);
    const targetIndex = targetId
      ? planningState.workCenters.findIndex((center) => center.id === targetId)
      : -1;

    if (targetIndex >= 0) {
      const target = planningState.workCenters[targetIndex];
      renameMap.set(department.name, target.name);
      planningState.workCenters[targetIndex] = normalizeWorkCenterUnit({
        ...target,
        owner: target.owner || department.owner || "",
        legacyDepartmentNames: [...new Set([...(target.legacyDepartmentNames || []), department.name])],
      });
      planningChanged = true;
      return;
    }

    directoryChanged = true;
  });

  if ((directoryState.employees || []).length) {
    directoryState.employees = [];
    directoryChanged = true;
  }

  if (migrateSpecificationDepartmentNames(renameMap)) directoryChanged = true;

  if (legacyDepartments.length) {
    directoryState.departments = [];
    directoryChanged = true;
  }

  if (planningChanged) {
    planningState = normalizePlanningState(planningState);
    persistState();
  }
  if (directoryChanged) persistDirectoryState();
}

function migrateProjectEntityToSpecifications() {
  // Legacy migration only. "Project" is no longer a business entity; old
  // projectId fields are kept as aliases for specificationId in saved Gantt data.
  if (!planningState || !directoryState) return;

  const legacyProjects = Array.isArray(planningState.projects) ? planningState.projects : [];
  const legacyProjectById = byId(legacyProjects);
  const specifications = Array.isArray(directoryState.specifications) ? directoryState.specifications : [];
  const projectToSpecificationId = new Map();
  let changed = false;

  specifications.forEach((specification) => {
    if (specification.projectId) projectToSpecificationId.set(specification.projectId, specification.id);
    projectToSpecificationId.set(specification.id, specification.id);
  });

  const nextSpecifications = [...specifications];
  legacyProjects.forEach((project) => {
    let specificationId = projectToSpecificationId.get(project.id);
    const legacySuffix = String(project.id || "").replace(/^p-/, "");
    const derivedSpecificationId = legacySuffix ? `spec-${legacySuffix}` : "";
    if (!specificationId && nextSpecifications.some((specification) => specification.id === derivedSpecificationId)) {
      specificationId = derivedSpecificationId;
      projectToSpecificationId.set(project.id, specificationId);
      changed = true;
    }
    if (!specificationId) {
      specificationId = derivedSpecificationId || `spec-${makeId("legacy")}`;
      let uniqueId = specificationId;
      let suffix = 1;
      while (nextSpecifications.some((specification) => specification.id === uniqueId)) {
        suffix += 1;
        uniqueId = `${specificationId}-${suffix}`;
      }
      specificationId = uniqueId;
      nextSpecifications.push({
        id: specificationId,
        name: project.name || `Состав изделия ${project.orderNumber || project.id}`,
        outputItem: project.name || "",
        bomListA: "",
        bomQtyA: 0,
        bomListB: "",
        bomQtyB: 0,
        extraItems: "",
        status: "Активен",
        structureManaged: true,
        structureItems: [],
        createdAt: project.createdAt || new Date().toISOString(),
      });
      projectToSpecificationId.set(project.id, specificationId);
      changed = true;
    }
  });

  const stamp = new Date().toISOString();
  directoryState.specifications = nextSpecifications.map((specification) => {
    const legacyProject = specification.projectId ? legacyProjectById[specification.projectId] : null;
    const next = {
      ...specification,
      projectId: "",
      productionQuantity: normalizeOptionalPositiveInteger(specification.productionQuantity || legacyProject?.totalQuantity) || "",
      dueDate: specification.dueDate || legacyProject?.dueDate || "",
      orderNumber: specification.orderNumber || legacyProject?.orderNumber || "",
      customer: specification.customer || legacyProject?.customer || "",
      updatedAt: specification.updatedAt || legacyProject?.updatedAt || stamp,
    };
    if (specification.projectId || legacyProject) changed = true;
    const synced = syncSpecificationDerivedFields(next);
    if (JSON.stringify(synced) !== JSON.stringify(specification)) changed = true;
    return synced;
  });

  directoryState.bomLists = (directoryState.bomLists || []).map((bom) => {
    if (!bom.projectId) return bom;
    changed = true;
    return { ...bom, projectId: "" };
  });

  const routeByLegacyProjectId = new Map((planningState.routes || [])
    .filter((route) => route.projectId)
    .map((route) => [route.projectId, route]));
  const routeById = new Map();

  planningState.routes = (planningState.routes || []).map((route) => {
    const specificationId = route.specificationId
      || projectToSpecificationId.get(route.projectId)
      || (getSpecificationById(route.projectId) ? route.projectId : "");
    if (route.specificationId === specificationId && route.projectId === specificationId) {
      routeById.set(route.id, route);
      return route;
    }
    changed = true;
    const specification = getSpecificationById(specificationId);
    const nextRoute = {
      ...route,
      specificationId,
      specificationName: specification?.name || route.specificationName || "",
      projectId: specificationId || route.projectId || "",
      updatedAt: route.updatedAt || stamp,
    };
    routeById.set(nextRoute.id, nextRoute);
    return nextRoute;
  });

  const routeByLegacyAfterMigration = new Map((planningState.routes || [])
    .map((route) => [route.projectId, route]));

  const routeByStepId = new Map((planningState.routeSteps || []).map((step) => [step.id, routeById.get(step.routeId)]));
  planningState.slots = (planningState.slots || []).map((slot) => {
    const route = routeByStepId.get(slot.routeStepId)
      || routeById.get(slot.routeId)
      || routeByLegacyProjectId.get(slot.projectId)
      || routeByLegacyAfterMigration.get(projectToSpecificationId.get(slot.projectId) || slot.projectId);
    const specificationId = slot.specificationId
      || route?.specificationId
      || projectToSpecificationId.get(slot.projectId)
      || (getSpecificationById(slot.projectId) ? slot.projectId : "");
    const currentRouteId = slot.routeId || "";
    const currentSpecificationId = slot.specificationId || "";
    const currentProductionId = slot.projectId || "";
    if (currentRouteId === (route?.id || "") && currentSpecificationId === specificationId && currentProductionId === specificationId) return slot;
    changed = true;
    return {
      ...slot,
      routeId: route?.id || slot.routeId || "",
      specificationId,
      projectId: specificationId || slot.projectId || "",
      updatedAt: slot.updatedAt || stamp,
    };
  });

  if (planningState.projects?.length) {
    planningState.projects = [];
    changed = true;
  } else {
    planningState.projects = [];
  }

  planningState = normalizePlanningState(planningState);
  directoryState = normalizeDirectoryState(directoryState, { mergeFallback: false });

  if (changed) {
    persistState();
    persistDirectoryState();
  }
}

function loadCalculatorState() {
  try {
    const raw = localStorage.getItem(CALCULATOR_STORAGE_KEY);
    if (!raw) return createDefaultCalculatorState();
    return normalizeCalculatorState(JSON.parse(raw));
  } catch {
    return createDefaultCalculatorState();
  }
}

function persistCalculatorState() {
  localStorage.setItem(CALCULATOR_STORAGE_KEY, JSON.stringify(calculatorState));
}

function notifySaveSuccess(message = "Сохранено") {
  pendingSaveFeedback = {
    message: String(message || "Сохранено"),
    createdAt: Date.now(),
  };
  window.clearTimeout(saveFeedbackTimer);
  window.setTimeout(renderPendingSaveFeedback, 0);
}

function renderPendingSaveFeedback() {
  document.querySelectorAll(".global-save-toast").forEach((element) => element.remove());
  if (!pendingSaveFeedback) return;
  window.clearTimeout(saveFeedbackTimer);

  const toast = document.createElement("div");
  toast.className = "global-save-toast";
  toast.setAttribute("role", "status");
  toast.setAttribute("aria-live", "polite");
  toast.innerHTML = `${icon("check")}<span>${escapeHtml(pendingSaveFeedback.message)}</span>`;
  document.body.appendChild(toast);

  saveFeedbackTimer = window.setTimeout(() => {
    toast.classList.add("is-hiding");
    window.setTimeout(() => toast.remove(), 180);
    pendingSaveFeedback = null;
  }, 2600);
}

function scheduleGlobalSaveUxRefresh() {
  window.clearTimeout(saveUxRefreshTimer);
  saveUxRefreshTimer = window.setTimeout(() => {
    bindGlobalFormDirtyTracking();
    renderPendingSaveFeedback();
  }, 0);
}

function getMesSignalMeta(signalType = "neutral") {
  return MES_SIGNAL_TYPES[signalType] || MES_SIGNAL_TYPES.neutral;
}

function resetVisualQaInspectorState() {
  visualQaInspectorActive = false;
  visualQaHoveredElementReport = null;
  visualQaPendingPointerReport = null;
  visualQaSuppressClickUntil = 0;
  document.body.classList.remove("is-mes-visual-qa-enabled", "is-mes-visual-qa-inspecting");
  document.querySelectorAll(".visual-debug-marker-layer").forEach((element) => element.remove());
}

function setVisualQaEnabled(enabled) {
  const nextEnabled = Boolean(enabled);
  ui.visualQaEnabled = nextEnabled;
  if (!nextEnabled) {
    resetVisualQaInspectorState();
    return;
  }
  visualQaInspectorActive = true;
  visualQaHoveredElementReport = null;
}

function mountGlobalVisualSystem() {
  const shell = app.querySelector(".app-shell");
  if (ui.visualQaEnabled) {
    visualQaInspectorActive = true;
  }
  document.body.classList.toggle("is-mes-focus-mode", Boolean(ui.focusMode));
  document.body.classList.toggle("is-mes-visual-qa-enabled", Boolean(ui.visualQaEnabled));
  document.body.classList.toggle("is-mes-visual-qa-inspecting", Boolean(ui.visualQaEnabled && visualQaInspectorActive));
  if (!ui.visualQaEnabled) {
    resetVisualQaInspectorState();
  }
  if (shell) {
    shell.classList.toggle("is-focus-mode", Boolean(ui.focusMode));
    shell.classList.toggle("is-visual-qa-enabled", Boolean(ui.visualQaEnabled));
  }
  mountVisualModeTray();
  mountVisualDebugOverlay();
}

function scheduleVisualQaRefresh() {
  if (!ui.visualQaEnabled) return;
  window.requestAnimationFrame(() => renderVisualQaMarkers());
}

function mountVisualModeTray() {
  document.querySelectorAll(".mes-visual-mode-tray").forEach((element) => element.remove());
  const topbar = app.querySelector(".app-topbar");
  const topbarRect = topbar?.getBoundingClientRect();
  const topbarVisible = topbar
    && window.getComputedStyle(topbar).display !== "none"
    && topbarRect?.width > 0
    && topbarRect?.height > 0;
  if (ui.activeModule !== "gantt" || topbarVisible) return;

  const tray = document.createElement("div");
  tray.className = "mes-visual-mode-tray";
  tray.setAttribute("aria-label", "Режимы интерфейса");
  tray.innerHTML = `
    <button class="app-topbar-action ${ui.focusMode ? "is-active" : ""}" data-toggle-focus-mode type="button" aria-pressed="${ui.focusMode ? "true" : "false"}" title="Режим фокуса">
      ${icon("focus")}
      <span>Фокус</span>
    </button>
    <button class="app-topbar-action ${ui.visualQaEnabled ? "is-active is-qa-active" : ""}" data-toggle-visual-qa type="button" aria-pressed="${ui.visualQaEnabled ? "true" : "false"}" title="QA: клик - компактный отчет, Shift+клик - полный">
      ${icon("bug")}
      <span>QA</span>
    </button>
  `;
  document.body.appendChild(tray);
}

function mountVisualDebugOverlay() {
  document.querySelectorAll(".visual-debug-marker-layer").forEach((element) => element.remove());
  if (!ui.visualQaEnabled) {
    resetVisualQaInspectorState();
    return;
  }

  const markerLayer = document.createElement("div");
  markerLayer.className = "visual-debug-marker-layer";
  markerLayer.setAttribute("aria-hidden", "true");
  document.body.append(markerLayer);
  renderVisualQaMarkers();
}

function isElementVisibleForQa(element) {
  if (!element || element.closest?.(".visual-debug-marker-layer")) return false;
  if (element.closest?.("details:not([open])")) return false;
  const rect = element.getBoundingClientRect();
  if (rect.width < 1 || rect.height < 1) return false;
  const style = window.getComputedStyle(element);
  return style.display !== "none" && style.visibility !== "hidden" && Number(style.opacity || 1) !== 0;
}

function getVisualQaSelector(element) {
  if (!element) return "";
  const id = element.id ? `#${element.id}` : "";
  if (id) return id;
  if (element.dataset?.hierarchyId) return `[data-hierarchy-id="${element.dataset.hierarchyId}"]`;
  if (element.dataset?.hierarchyRoot !== undefined) return "[data-hierarchy-root]";
  if (element.dataset?.connectorTo) return `[data-connector-to="${element.dataset.connectorTo}"]`;
  if (element.dataset?.connectorKind && element.dataset?.connectorFrom) return `[data-connector-kind="${element.dataset.connectorKind}"][data-connector-from="${element.dataset.connectorFrom}"]`;
  if (element.dataset?.visualQaTarget) return `[data-visual-qa-target="${element.dataset.visualQaTarget}"]`;
  const classes = [...element.classList || []]
    .filter((className) => !className.startsWith("is-") && !className.startsWith("has-"))
    .slice(0, 3)
    .map((className) => `.${className}`)
    .join("");
  const dataKey = element.dataset?.layout
    ? `[data-layout="${element.dataset.layout}"]`
    : element.dataset?.module
      ? `[data-module="${element.dataset.module}"]`
      : "";
  return `${element.tagName.toLowerCase()}${classes}${dataKey}`;
}

function getVisualQaElementLabel(element) {
  const label = element.getAttribute?.("aria-label") || element.getAttribute?.("title") || element.textContent || "";
  return String(label).replace(/\s+/g, " ").trim().slice(0, 90) || getVisualQaSelector(element);
}

function getVisualQaElementText(element, options = {}) {
  if (!element) return "";
  const detailed = Boolean(options.detailed);
  const limit = detailed ? 260 : 120;
  const visibleText = "innerText" in element ? element.innerText : "";
  const rawText = String(visibleText || element.value || element.textContent || "").replace(/\s+/g, " ").trim();
  if (detailed || rawText.length <= limit) return rawText.slice(0, limit);
  const semanticText = [
    element.getAttribute?.("aria-label") || "",
    element.getAttribute?.("title") || "",
    element.querySelector?.([
      ".ui-panel-head h1",
      ".ui-panel-head h2",
      ".ui-panel-head strong",
      "header h1",
      "header h2",
      "header strong",
      "h1",
      "h2",
      "h3",
      "legend",
      "label",
    ].join(","))?.innerText || "",
  ]
    .map((value) => String(value || "").replace(/\s+/g, " ").trim())
    .filter(Boolean);
  const compactText = [...new Set(semanticText)].join(" · ");
  return (compactText || rawText).slice(0, limit);
}

function isVisualQaUiElement(element) {
  return Boolean(element?.closest?.(".visual-debug-marker-layer"));
}

function isVisualQaNavigationElement(element) {
  return Boolean(element?.closest?.([
    ".module-menu",
    ".mobile-module-switcher",
    ".mes-visual-mode-tray",
    "[data-module]",
    "[data-save-workflow-preset]",
    "[data-restore-workflow-preset]",
    "[data-auth-logout]",
    "[data-toggle-focus-mode]",
    "[data-toggle-visual-qa]",
  ].join(",")));
}

function getVisualQaModuleLabel(moduleId = ui.activeModule) {
  return getModuleDefinitions().find((moduleItem) => moduleItem.id === moduleId)?.label || moduleId || "unknown";
}

function getVisualQaNodeSignature(element) {
  if (!element) return "";
  const classes = [...element.classList || []]
    .filter((className) => !className.startsWith("is-") && !className.startsWith("has-"))
    .slice(0, 4)
    .map((className) => `.${className}`)
    .join("");
  const id = element.id ? `#${element.id}` : "";
  const dataAttrs = ["layout", "module", "layoutPage", "hierarchyId", "hierarchyRoot", "visualQaTarget", "connectorKind", "connectorFrom", "connectorTo", "visualQaFocus", "routeStepId", "supplyDemandId", "shopMapWidgetId"]
    .map((key) => element.dataset?.[key] ? `[data-${key.replace(/[A-Z]/g, (char) => `-${char.toLowerCase()}`)}="${element.dataset[key]}"]` : "")
    .filter(Boolean)
    .slice(0, 2)
    .join("");
  return `${element.tagName.toLowerCase()}${id}${classes}${dataAttrs}`;
}

function getVisualQaParentChain(element, limit = 5) {
  const chain = [];
  let current = element?.parentElement || null;
  while (current && current !== document.body && chain.length < limit) {
    if (!isVisualQaUiElement(current)) chain.push(getVisualQaNodeSignature(current));
    current = current.parentElement;
  }
  return chain.filter(Boolean);
}

function getVisualQaClosestScrollContainer(element) {
  let current = element?.parentElement || null;
  while (current && current !== document.body) {
    const style = window.getComputedStyle(current);
    const canScrollX = ["auto", "scroll", "hidden", "clip"].includes(style.overflowX)
      && current.scrollWidth > current.clientWidth + 2;
    const canScrollY = ["auto", "scroll", "hidden", "clip"].includes(style.overflowY)
      && current.scrollHeight > current.clientHeight + 2;
    if (canScrollX || canScrollY) return current;
    current = current.parentElement;
  }
  return null;
}

function getInspectableVisualQaElement(target) {
  if (
    !target
    || target.nodeType !== Node.ELEMENT_NODE
    || isVisualQaUiElement(target)
    || isVisualQaNavigationElement(target)
  ) return null;
  const element = target.closest([
    "button",
    "input",
    "select",
    "textarea",
    "summary",
    "a[href]",
    "[role='button']",
    "[role='dialog']",
    "[data-visual-qa-target]",
    "[popover]",
    ".operation-slot",
    ".supply-demand-bar",
    ".dense-inline-select",
    ".dense-inline-options",
    ".supply-detail-popover",
    ".employee-hierarchy-node",
    ".employee-root-card",
    ".employee-hierarchy-connector",
    ".employee-hierarchy-layer-label",
    ".employees-org-annotation",
    ".route-object-table td",
    ".speki-structure-table td",
    ".directory-table td",
    ".supply-table td",
    ".module-panel",
    ".module-card",
    ".form-field",
    "[data-layout='table']",
    "[data-layout='sidebar']",
    "[data-layout='main-content']",
  ].join(","));
  return element && !isVisualQaUiElement(element) && !isVisualQaNavigationElement(element) ? element : target;
}

function getVisualQaRectSummary(element) {
  const rect = element.getBoundingClientRect();
  return {
    x: Math.round(rect.left),
    y: Math.round(rect.top),
    width: Math.round(rect.width),
    height: Math.round(rect.height),
    right: Math.round(rect.right),
    bottom: Math.round(rect.bottom),
  };
}

function collectVisualQaElementReport(element, options = {}) {
  if (!element) return null;
  const detailed = Boolean(options.detailed);
  const rect = element.getBoundingClientRect();
  const style = window.getComputedStyle(element);
  const viewportWidth = document.documentElement.clientWidth;
  const viewportHeight = document.documentElement.clientHeight;
  const scroller = getVisualQaClosestScrollContainer(element);
  const parent = element.parentElement;
  const parentRect = parent?.getBoundingClientRect?.();
  const parentStyle = parent ? window.getComputedStyle(parent) : null;
  const controlType = String(element.type || element.getAttribute?.("type") || "").toLowerCase();
  const touchMin = viewportWidth <= 768 ? 36 : 28;
  const flags = [];
  const text = getVisualQaElementText(element, { detailed });
  const xOverflow = element.scrollWidth > element.clientWidth + 2;
  const yOverflow = element.scrollHeight > element.clientHeight + 2;
  const isFloatingLayer = element.matches?.(".modal, .slot-drawer, .dense-inline-options, .supply-detail-popover, [popover]");
  const isViewportAnchored = isFloatingLayer || ["fixed", "sticky"].includes(style.position);

  if (rect.right > viewportWidth + 1 || rect.left < -1) flags.push("element-outside-viewport-x");
  if (rect.top < -1 || (rect.bottom > viewportHeight + 1 && isViewportAnchored)) flags.push("element-outside-viewport-y");
  if (xOverflow || yOverflow) flags.push(`self-overflow-${xOverflow ? "x" : ""}${yOverflow ? "y" : ""}`);
  if (!element.disabled && (rect.width < touchMin || rect.height < touchMin) && controlType !== "hidden") flags.push("small-touch-target");
  if (style.whiteSpace === "nowrap" && xOverflow) flags.push("nowrap-text-overflow");
  if (parentRect && parentStyle && ["hidden", "clip"].includes(parentStyle.overflowX) && rect.right > parentRect.right + 1) flags.push("clipped-by-parent-x");
  if (parentRect && parentStyle && ["hidden", "clip"].includes(parentStyle.overflowY) && rect.bottom > parentRect.bottom + 1) flags.push("clipped-by-parent-y");
  if (isFloatingLayer) flags.push("floating-layer");

  const report = {
    generatedAt: new Date().toISOString(),
    type: "visual-qa-inspector",
    detailLevel: detailed ? "full" : "compact",
    module: ui.activeModule,
    moduleLabel: getVisualQaModuleLabel(),
    viewport: { width: viewportWidth, height: viewportHeight },
    selector: getVisualQaSelector(element),
    signature: getVisualQaNodeSignature(element),
    label: getVisualQaElementLabel(element),
    text,
    rect: getVisualQaRectSummary(element),
    scroll: {
      scrollWidth: Math.round(element.scrollWidth || 0),
      clientWidth: Math.round(element.clientWidth || 0),
      scrollHeight: Math.round(element.scrollHeight || 0),
      clientHeight: Math.round(element.clientHeight || 0),
    },
    style: {
      display: style.display,
      position: style.position,
      zIndex: style.zIndex,
      overflowX: style.overflowX,
      overflowY: style.overflowY,
      whiteSpace: style.whiteSpace,
      textOverflow: style.textOverflow,
      fontSize: style.fontSize,
      fontWeight: style.fontWeight,
      lineHeight: style.lineHeight,
    },
    parentChain: getVisualQaParentChain(element, detailed ? 5 : 3),
    scrollContainer: scroller ? {
      selector: getVisualQaSelector(scroller),
      signature: getVisualQaNodeSignature(scroller),
      rect: getVisualQaRectSummary(scroller),
      scrollWidth: Math.round(scroller.scrollWidth || 0),
      clientWidth: Math.round(scroller.clientWidth || 0),
      scrollHeight: Math.round(scroller.scrollHeight || 0),
      clientHeight: Math.round(scroller.clientHeight || 0),
      overflowX: window.getComputedStyle(scroller).overflowX,
      overflowY: window.getComputedStyle(scroller).overflowY,
    } : null,
    flags,
  };
  window.__mesVisualQaInspectorReport = report;
  return report;
}

function formatVisualQaInspectorReport(report = null) {
  if (!report) return "Visual QA Inspector: элемент не выбран.";
  const detailed = report.detailLevel === "full";
  const hasSelfOverflow = report.scroll
    && (report.scroll.scrollWidth > report.scroll.clientWidth + 2 || report.scroll.scrollHeight > report.scroll.clientHeight + 2);
  const lines = [
    "Visual QA Inspector report",
    `Режим: ${detailed ? "полный" : "компактный"}`,
    `Модуль: ${report.moduleLabel} (${report.module})`,
    `Viewport: ${report.viewport.width}x${report.viewport.height}`,
    `Элемент: ${report.label}`,
    `Selector: ${report.selector}`,
    `Signature: ${report.signature}`,
    `Rect: x=${report.rect.x}, y=${report.rect.y}, w=${report.rect.width}, h=${report.rect.height}, right=${report.rect.right}, bottom=${report.rect.bottom}`,
  ];
  if (detailed || hasSelfOverflow) {
    lines.push(`Scroll: ${report.scroll.scrollWidth}x${report.scroll.scrollHeight} / client ${report.scroll.clientWidth}x${report.scroll.clientHeight}`);
  }
  lines.push(detailed
    ? `CSS: display=${report.style.display}; position=${report.style.position}; z-index=${report.style.zIndex}; overflow=${report.style.overflowX}/${report.style.overflowY}; white-space=${report.style.whiteSpace}; text-overflow=${report.style.textOverflow}; font=${report.style.fontWeight} ${report.style.fontSize}/${report.style.lineHeight}`
    : `CSS: position=${report.style.position}; overflow=${report.style.overflowX}/${report.style.overflowY}; white-space=${report.style.whiteSpace}; font=${report.style.fontWeight} ${report.style.fontSize}/${report.style.lineHeight}`);
  lines.push(`Flags: ${report.flags.length ? report.flags.join(", ") : "нет автоматических флагов"}`);
  if (report.scrollContainer) {
    lines.push(`Scroll container: ${report.scrollContainer.signature} (${report.scrollContainer.clientWidth}x${report.scrollContainer.clientHeight}, scroll ${report.scrollContainer.scrollWidth}x${report.scrollContainer.scrollHeight}, overflow ${report.scrollContainer.overflowX}/${report.scrollContainer.overflowY})`);
  } else if (detailed) {
    lines.push("Scroll container: не найден");
  }
  lines.push(`Parent chain: ${report.parentChain.join(" > ") || "нет"}`);
  lines.push(report.text ? `Text: ${report.text}` : "Text: нет");
  if (detailed) {
    lines.push("Что проверить: визуальное положение элемента, переполнение, ближайший scroll-контейнер, z-index/dropdown и размеры touch target.");
  }
  return lines.filter(Boolean).join("\n");
}

function renderVisualQaMarkers() {
  const layer = document.querySelector(".visual-debug-marker-layer");
  if (!layer) return;
  const report = visualQaInspectorActive ? visualQaHoveredElementReport : null;
  if (!report) {
    layer.innerHTML = "";
    return;
  }
  const rect = report.rect || {};
  const left = Math.max(0, Math.min(rect.x || 0, window.innerWidth - 10));
  const top = Math.max(0, Math.min(rect.y || 0, window.innerHeight - 10));
  const width = Math.max(6, Math.min(rect.width || 6, window.innerWidth - left));
  const height = Math.max(6, Math.min(rect.height || 6, window.innerHeight - top));
  layer.innerHTML = `
    <span
      class="visual-debug-marker is-inspector is-hover"
      style="left:${left}px; top:${top}px; width:${width}px; height:${height}px;"
      title="${escapeAttribute(`QA · ${report.label}`)}"
    ></span>
  `;
}

function copyTextToClipboard(text, successMessage, fallbackMessage) {
  const legacyCopy = ({ notify = true } = {}) => {
    let copiedByEvent = false;
    const handleCopy = (event) => {
      if (!event.clipboardData) return;
      event.clipboardData.setData("text/plain", text);
      event.preventDefault();
      copiedByEvent = true;
    };
    document.addEventListener("copy", handleCopy, true);
    try {
      document.execCommand("copy");
    } catch {
      copiedByEvent = false;
    }
    document.removeEventListener("copy", handleCopy, true);
    if (copiedByEvent) {
      if (notify) notifySaveSuccess(successMessage);
      return true;
    }

    const textarea = document.createElement("textarea");
    textarea.value = text;
    textarea.setAttribute("readonly", "");
    textarea.style.position = "fixed";
    textarea.style.left = "-9999px";
    textarea.style.top = "0";
    document.body.appendChild(textarea);
    textarea.focus();
    textarea.select();
    let copied = false;
    try {
      copied = document.execCommand("copy");
    } catch {
      copied = false;
    }
    textarea.remove();
    if (notify) notifySaveSuccess(copied ? successMessage : fallbackMessage);
    return copied;
  };

  if (legacyCopy({ notify: false })) {
    notifySaveSuccess(successMessage);
    return;
  }
  if (navigator.clipboard?.writeText) {
    navigator.clipboard.writeText(text)
      .then(() => notifySaveSuccess(successMessage))
      .catch(() => legacyCopy());
    return;
  }
  legacyCopy();
}

function copyVisualQaInspectorReport(report) {
  if (!report) {
    notifySaveSuccess("Сначала выбери проблемный элемент");
    return;
  }
  const text = formatVisualQaInspectorReport(report);
  window.__mesVisualQaInspectorReport = report;
  window.__mesVisualQaSmartReport = {
    report,
    text,
  };
  try {
    sessionStorage.setItem("mes-visual-qa-last-report", text);
  } catch {
    // Session storage is only a QA fallback; clipboard remains the primary path.
  }
  copyTextToClipboard(text, "QA отчет скопирован", "QA отчет доступен в window.__mesVisualQaSmartReport");
}

function armVisualQaFollowupClickSuppression() {
  visualQaSuppressClickUntil = Date.now() + 1200;
}

function rememberVisualQaRuntimeDebug(payload = {}) {
  try {
    sessionStorage.setItem("mes-visual-qa-last-debug", JSON.stringify({
      at: new Date().toISOString(),
      ...payload,
    }));
  } catch {
    // Debug storage is best-effort and must never affect QA picking.
  }
}

function consumeVisualQaFollowupClick(event, options = {}) {
  if (!visualQaSuppressClickUntil) return false;
  if (Date.now() > visualQaSuppressClickUntil) {
    visualQaSuppressClickUntil = 0;
    visualQaPendingPointerReport = null;
    return false;
  }
  const report = visualQaPendingPointerReport;
  visualQaSuppressClickUntil = options.keepSuppressWindow ? Date.now() + 450 : 0;
  visualQaPendingPointerReport = null;
  rememberVisualQaRuntimeDebug({
    eventType: event.type,
    reason: report ? "copy-pending-pointer-report" : "suppressed-followup-click",
    module: report?.module || "",
  });
  event.stopImmediatePropagation();
  if (report) finalizeVisualQaInspection(report);
  event.preventDefault();
  return true;
}

function finalizeVisualQaInspection(report) {
  visualQaHoveredElementReport = null;
  copyVisualQaInspectorReport(report);
  setVisualQaEnabled(false);
  persistUiState();
  render();
}

function consumeVisualQaInspectorEvent(event) {
  if (!ui.visualQaEnabled || !visualQaInspectorActive) return false;
  const target = event.target;
  if (isVisualQaUiElement(target)) {
    rememberVisualQaRuntimeDebug({ eventType: event.type, reason: "visual-qa-ui-target", target: getVisualQaNodeSignature(target) });
    return false;
  }
  if (isVisualQaNavigationElement(target)) {
    rememberVisualQaRuntimeDebug({ eventType: event.type, reason: "navigation-target", target: getVisualQaNodeSignature(target) });
    return false;
  }
  const element = getInspectableVisualQaElement(event.target);
  if (!element) {
    rememberVisualQaRuntimeDebug({ eventType: event.type, reason: "inspectable-not-found", target: getVisualQaNodeSignature(target) });
    return false;
  }

  event.preventDefault();
  event.stopImmediatePropagation();
  const report = collectVisualQaElementReport(element, { detailed: event.shiftKey });
  if (event.type === "pointerdown") {
    visualQaPendingPointerReport = report;
    visualQaHoveredElementReport = report;
    armVisualQaFollowupClickSuppression();
    renderVisualQaMarkers();
    rememberVisualQaRuntimeDebug({
      eventType: event.type,
      reason: "pending-pointer-report",
      target: getVisualQaNodeSignature(target),
      selected: getVisualQaNodeSignature(element),
      detailLevel: report?.detailLevel || "",
      module: report?.module || "",
    });
    return true;
  }
  rememberVisualQaRuntimeDebug({
    eventType: event.type,
    reason: "report-created",
    target: getVisualQaNodeSignature(target),
    selected: getVisualQaNodeSignature(element),
    detailLevel: report?.detailLevel || "",
    module: report?.module || "",
  });
  finalizeVisualQaInspection(report);
  return true;
}

function getFormControlSignatureEntry(control) {
  if (!control?.name || control.disabled) return null;
  const type = String(control.type || "").toLowerCase();
  if (["button", "submit", "reset", "file"].includes(type)) return null;
  if (type === "checkbox" || type === "radio") {
    return [control.name, control.checked ? String(control.value || "on") : ""];
  }
  if (control.tagName === "SELECT" && control.multiple) {
    return [control.name, [...control.selectedOptions].map((option) => option.value).join("|")];
  }
  return [control.name, String(control.value ?? "")];
}

function getFormSignature(form) {
  return JSON.stringify([...form.elements]
    .map((control) => getFormControlSignatureEntry(control))
    .filter(Boolean)
    .sort((left, right) => String(left[0]).localeCompare(String(right[0]))));
}

function isUnsavedCreateForm(form) {
  const isNewValue = form.querySelector('[name="isNew"]')?.value;
  const rowIndexValue = form.querySelector('[name="rowIndex"]')?.value;
  if (isNewValue === "yes" || rowIndexValue === "-1") return true;
  if (form.id === "slotForm" && !form.querySelector('[name="slotId"]')?.value) return true;
  return ["splitForm"].includes(form.id);
}

function setSaveButtonDisabled(button, disabled) {
  if (!button) return;
  if (!Object.prototype.hasOwnProperty.call(button.dataset, "saveOriginalTitle")) {
    button.dataset.saveOriginalTitle = button.getAttribute("title") || "";
  }
  button.toggleAttribute("disabled", Boolean(disabled));
  button.classList.toggle("is-save-disabled", Boolean(disabled));
  if (disabled) {
    button.setAttribute("title", "Измените данные, чтобы сохранить");
    return;
  }
  if (button.dataset.saveOriginalTitle) {
    button.setAttribute("title", button.dataset.saveOriginalTitle);
  } else {
    button.removeAttribute("title");
  }
}

function bindGlobalFormDirtyTracking() {
  app.querySelectorAll("form").forEach((form) => {
    if (form.matches("[data-command-form]")) return;
    const saveButtons = [...form.querySelectorAll('button[type="submit"], input[type="submit"]')];
    if (!saveButtons.length) return;
    form.dataset.initialSaveSignature = getFormSignature(form);

    const syncDirtyState = () => {
      const isDirty = isUnsavedCreateForm(form) || getFormSignature(form) !== form.dataset.initialSaveSignature;
      form.classList.toggle("is-dirty", isDirty);
      saveButtons.forEach((button) => setSaveButtonDisabled(button, !isDirty));
    };
    const guardCleanSubmit = (event) => {
      if (isUnsavedCreateForm(form)) return;
      if (getFormSignature(form) !== form.dataset.initialSaveSignature) return;
      event.preventDefault();
      event.stopImmediatePropagation();
    };

    if (!form.dataset.saveUxBound) {
      form.addEventListener("input", syncDirtyState);
      form.addEventListener("change", syncDirtyState);
      form.addEventListener("submit", guardCleanSubmit, true);
      form.dataset.saveUxBound = "yes";
    }
    syncDirtyState();
  });
}

function createDefaultCalculatorState() {
  return normalizeCalculatorState({
    ...defaultCalculatorState,
    componentCounts: {},
  });
}

function normalizeCalculatorState(state) {
  const project = getProject(state?.projectId || state?.specificationId) || null;
  const noSpecification = Boolean(state?.noSpecification);
  const specification = noSpecification ? null : directoryState?.specifications?.find((item) => item.id === state?.specificationId) || null;
  const bomList = directoryState?.bomLists?.find((item) => item.id === state?.bomListId) || null;
  const boardQuantity = normalizeOptionalPositiveInteger(state?.boardQuantity);
  const boardsPerPanel = normalizeOptionalPositiveInteger(state?.boardsPerPanel);
  const routeOperations = (Array.isArray(state?.routeOperations) ? state.routeOperations : [])
    .map((operation, index) => normalizeRouteOperation(operation, index + 1, boardsPerPanel || 1));
  const selectedOperationId = routeOperations.some((operation) => operation.id === state?.selectedOperationId)
    ? state.selectedOperationId
    : routeOperations[0]?.id || "";
  const componentCountsByOperation = {
    ...(state?.componentCountsByOperation || {}),
  };
  for (const operation of routeOperations) {
    if (operation.calculationType === "components" && !componentCountsByOperation[operation.id]) {
      const operationBom = getBomList(operation.bomListId) || bomList;
      componentCountsByOperation[operation.id] = {
        ...(operationBom ? getBomComponentCounts(operationBom) : {}),
        ...(state?.componentCounts || {}),
      };
    }
  }

  return {
    ...defaultCalculatorState,
    ...state,
    projectId: project?.id || "",
    noSpecification,
    specificationId: noSpecification ? "" : specification?.id || "",
    bomListId: bomList?.id || "",
    selectedOperationId,
    routeOperations,
    boardQuantity,
    boardsPerPanel,
    efficiency: Math.max(10, Math.min(150, Number(state?.efficiency || defaultCalculatorState.efficiency))),
    componentCounts: {
      ...(bomList ? getBomComponentCounts(bomList) : {}),
      ...(state?.componentCounts || {}),
    },
    componentCountsByOperation,
    machineSplitByBom: normalizeSmtMachineSplitStore(state?.machineSplitByBom),
    smtPackageCoefficientsByMachine: normalizeSmtPackageCoefficientStore(state?.smtPackageCoefficientsByMachine),
    lastSavedAt: String(state?.lastSavedAt || ""),
    inputsSavedAt: String(state?.inputsSavedAt || ""),
    inputsSavedSignature: String(state?.inputsSavedSignature || ""),
    routeSavedSignature: String(state?.routeSavedSignature || ""),
  };
}

function normalizeSmtMachineSplitStore(store = {}) {
  if (!store || typeof store !== "object" || Array.isArray(store)) return {};
  return Object.fromEntries(Object.entries(store)
    .map(([key, value]) => {
      if (!value || typeof value !== "object" || Array.isArray(value)) return [key, {}];
      return [key, Object.fromEntries(Object.entries(value)
        .map(([componentId, count]) => [componentId, Math.max(0, Math.round(Number(count || 0)))])
        .filter(([, count]) => Number.isFinite(count)))];
    })
    .filter(([key]) => key));
}

function normalizeSmtPackageCoefficientStore(store = {}) {
  if (!store || typeof store !== "object" || Array.isArray(store)) return {};
  return Object.fromEntries(Object.entries(store)
    .map(([machineId, packageValues]) => {
      if (!packageValues || typeof packageValues !== "object" || Array.isArray(packageValues)) return [machineId, {}];
      return [machineId, Object.fromEntries(Object.entries(packageValues)
        .map(([packageKey, coefficient]) => {
          const normalizedCoefficient = normalizeSmtPackageCoefficientValue(coefficient);
          return [
            normalizeSmtPackageCoefficientKey(packageKey),
            normalizedCoefficient ?? 0,
          ];
        })
        .filter(([packageKey, coefficient]) => packageKey && coefficient > 0))];
    })
    .filter(([machineId]) => machineId));
}

function normalizeSmtPackageCoefficientValue(value) {
  const number = typeof value === "number"
    ? value
    : Number(String(value ?? "").trim().replace(",", "."));
  if (!Number.isFinite(number) || number <= 0) return null;
  const scale = 100;
  return Math.max(SMT_MIN_PACKAGE_COEFFICIENT, Math.trunc((number + 1e-9) * scale) / scale);
}

function normalizeOptionalPositiveInteger(value) {
  if (value === "" || value === null || value === undefined) return "";
  const number = Math.round(Number(value));
  if (!Number.isFinite(number) || number <= 0) return "";
  return number;
}

function normalizeGanttDependencyRouteStore(value = {}) {
  if (!value || typeof value !== "object" || Array.isArray(value)) return {};

  return Object.fromEntries(Object.entries(value).flatMap(([routeKey, route]) => {
    if (Number(route?.version || 0) !== GANTT_DEPENDENCY_ROUTE_VERSION) return [];
    const offsets = route?.offsets && typeof route.offsets === "object" && !Array.isArray(route.offsets)
      ? route.offsets
      : {};
    const normalizedOffsets = Object.fromEntries(Object.entries(offsets).flatMap(([pointIndex, offset]) => {
      const index = Number(pointIndex);
      const x = Number(offset?.x || 0);
      const y = Number(offset?.y || 0);
      if (!Number.isInteger(index) || index < 0 || (!Number.isFinite(x) && !Number.isFinite(y))) return [];
      const normalized = {
        x: Number.isFinite(x) ? round(x) : 0,
        y: Number.isFinite(y) ? round(y) : 0,
      };
      if (Math.abs(normalized.x) < 0.1 && Math.abs(normalized.y) < 0.1) return [];
      return [[String(index), normalized]];
    }));

    return [[String(routeKey), { version: GANTT_DEPENDENCY_ROUTE_VERSION, offsets: normalizedOffsets }]];
  }).filter(([, route]) => Object.keys(route.offsets).length));
}

function cloneGanttDependencyRouteStore(value = {}) {
  return normalizeGanttDependencyRouteStore(JSON.parse(JSON.stringify(value || {})));
}

function normalizeSupplyCollapsedGroups(value = {}) {
  if (!value || typeof value !== "object" || Array.isArray(value)) return {};
  return Object.fromEntries(Object.entries(value).flatMap(([routeId, groupIds]) => {
    const ids = Array.isArray(groupIds)
      ? [...new Set(groupIds.map((id) => String(id || "").trim()).filter(Boolean))]
      : [];
    return routeId && ids.length ? [[String(routeId), ids]] : [];
  }));
}

function normalizePlanningLaborNoteByRow(value = {}) {
  if (!value || typeof value !== "object" || Array.isArray(value)) return {};
  return Object.fromEntries(Object.entries(value).flatMap(([key, labor]) => {
    const normalizedKey = String(key || "").trim();
    const normalizedLabor = String(labor || "").trim().slice(0, 80);
    return normalizedKey && normalizedLabor ? [[normalizedKey, normalizedLabor]] : [];
  }));
}

function normalizePlanningOrderLaborByStepId(value = {}) {
  if (!value || typeof value !== "object" || Array.isArray(value)) return {};
  return Object.fromEntries(Object.entries(value).flatMap(([key, settings]) => {
    const normalizedKey = String(key || "").trim();
    if (!normalizedKey || !settings || typeof settings !== "object" || Array.isArray(settings)) return [];
    const next = {};
    const mode = String(settings.mode || "").trim();
    if (mode === "calculator" || mode === "fixed" || mode === "unit" || mode === "panel" || mode === "shift") next.mode = mode;
    [
      ["minutesPerUnit", 0.001, 100000],
      ["minutesPerPanel", 0.001, 100000],
      ["fixedMinutes", 0.001, 1000000],
      ["shiftQuantity", 1, 100000000],
    ].forEach(([field, min, max]) => {
      const rawValue = settings[field];
      if (rawValue === "" || rawValue === null || rawValue === undefined) return;
      const number = Number(String(rawValue).trim().replace(",", "."));
      if (!Number.isFinite(number)) return;
      next[field] = Math.min(max, Math.max(min, number));
    });
    return Object.keys(next).length ? [[normalizedKey, next]] : [];
  }));
}

function normalizePlanningLegacyManualLaborByStep(value = {}) {
  return normalizePlanningOrderLaborByStepId(value);
}

function isDeepLinkDirectorySectionId(sectionId = "") {
  return [
    "operations",
    "componentTypes",
    "nomenclatureTypes",
    "statuses",
  ].includes(String(sectionId || "").trim());
}

function normalizeDeepLinkModuleId(moduleId = "") {
  const candidate = String(moduleId || "").trim();
  const aliases = {
    bomLists: "nomenclature",
    specifications: "products",
    speki: "products",
    planning2: "planning",
    planningWorkbench: "planning",
    calculator: "planning",
    warehouse: "gantt",
    shiftMaster: "shiftMasterBoard",
    shiftMasterContext: "shiftMasterBoard",
    shiftMasterV2: "shiftMasterBoard",
  };
  const normalized = aliases[candidate] || candidate;
  return getModuleDefinitions().some((moduleItem) => moduleItem.id === normalized) ? normalized : "";
}

function normalizeStoredModuleId(moduleId = "") {
  const normalized = normalizeDeepLinkModuleId(moduleId);
  return normalized || defaultUiState.activeModule;
}

function getAuthGateSessionDateKey(date = new Date()) {
  const value = date instanceof Date ? date : new Date(date);
  const year = value.getFullYear();
  const month = String(value.getMonth() + 1).padStart(2, "0");
  const day = String(value.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function getAuthGateSessionExpiresAt(date = new Date()) {
  const value = date instanceof Date ? date : new Date(date);
  return new Date(value.getFullYear(), value.getMonth(), value.getDate(), 23, 59, 59, 999);
}

function getAuthGateSession() {
  const session = parseJsonObject(localStorage.getItem(AUTH_GATE_SESSION_STORAGE_KEY));
  if (!session?.unlocked) {
    localStorage.removeItem(AUTH_GATE_SESSION_STORAGE_KEY);
    return null;
  }

  const todayKey = getAuthGateSessionDateKey();
  const expiresAtMs = Date.parse(session.expiresAt || "");
  const isExpired = session.dateKey !== todayKey || (Number.isFinite(expiresAtMs) && expiresAtMs < Date.now());
  if (isExpired) {
    localStorage.removeItem(AUTH_GATE_SESSION_STORAGE_KEY);
    return null;
  }

  return {
    unlocked: true,
    userId: String(session.userId || ""),
    roleId: normalizeInterfaceRoleId(session.roleId || DEFAULT_INTERFACE_ROLE_ID),
    dateKey: todayKey,
    expiresAt: session.expiresAt || getAuthGateSessionExpiresAt().toISOString(),
  };
}

function getAuthGateSessionUnlocked() {
  return Boolean(getAuthGateSession());
}

function setAuthGateSessionUnlocked(value) {
  if (!value) {
    localStorage.removeItem(AUTH_GATE_SESSION_STORAGE_KEY);
    return;
  }

  const now = new Date();
  const roleId = normalizeInterfaceRoleId(ui?.activeRole || DEFAULT_INTERFACE_ROLE_ID);
  localStorage.setItem(AUTH_GATE_SESSION_STORAGE_KEY, JSON.stringify({
    unlocked: true,
    userId: String(ui?.authCurrentUserId || ""),
    roleId,
    dateKey: getAuthGateSessionDateKey(now),
    startedAt: now.toISOString(),
    expiresAt: getAuthGateSessionExpiresAt(now).toISOString(),
    version: APP_VERSION,
  }));
}

function applyAuthGateSession(state = {}) {
  const session = getAuthGateSession();
  if (!session) {
    return {
      ...state,
      authGateUnlocked: false,
      authCurrentUserId: "",
    };
  }

  return {
    ...state,
    authGateUnlocked: true,
    authCurrentUserId: session.userId,
    activeRole: session.roleId,
    authPrototypeAttemptsLeft: AUTH_GATE_MAX_ATTEMPTS,
  };
}

function isAuthGateQaBypassEnabled() {
  try {
    const params = new URLSearchParams(window.location.search || "");
    return params.get("qa-auth-bypass") === "1";
  } catch {
    return false;
  }
}

function isAuthGateUnlocked() {
  return Boolean(ui?.authGateUnlocked) || getAuthGateSessionUnlocked() || isAuthGateQaBypassEnabled();
}

function lockAuthGate() {
  cancelAuthPrototypePinFeedback();
  ui.authGateUnlocked = false;
  ui.authPrototypeResult = "";
  ui.authPrototypeDepartment = "";
  ui.authPrototypeUnit = "";
  ui.authPrototypePersonId = "";
  ui.authCurrentUserId = "";
  ui.authPrototypeAttemptsLeft = AUTH_GATE_MAX_ATTEMPTS;
  resetAuthPrototypePinEntry();
  setAuthGateSessionUnlocked(false);
}

function unlockAuthGate(options = {}) {
  ui.authGateUnlocked = true;
  ui.authCurrentUserId = String(options.personId || ui.authCurrentUserId || "");
  ui.activeRole = normalizeInterfaceRoleId(options.roleId || ui.activeRole || DEFAULT_INTERFACE_ROLE_ID);
  ui.activeModule = getAccessRoleById(ui.activeRole).defaultModule || AUTH_GATE_DEFAULT_MODULE;
  ui.authPrototypeAttemptsLeft = AUTH_GATE_MAX_ATTEMPTS;
  resetAuthPrototypePinEntry();
  setAuthGateSessionUnlocked(true);
}

function ensureAuthGateModule() {
  if (isAuthGateUnlocked()) return false;
  ui.activeModule = "authPrototype";
  return true;
}

function getUrlUiOverrides() {
  if (typeof window === "undefined") return {};
  const params = new URLSearchParams(window.location.search || "");
  const overrides = {};
  const rawModuleId = String(params.get("module") || params.get("m") || "").trim();
  const moduleId = normalizeDeepLinkModuleId(rawModuleId);
  const directoryId = String(params.get("directory") || params.get("dir") || "").trim();
  if (moduleId) overrides.activeModule = moduleId;
  if (rawModuleId === "bomLists") overrides.activeNomenclaturePane = "boards";
  if (directoryId && isDeepLinkDirectorySectionId(directoryId)) {
    overrides.activeDirectory = directoryId;
    if (!overrides.activeModule) overrides.activeModule = "directories";
  }
  return overrides;
}

function applyUrlUiOverrides(state = {}) {
  return {
    ...state,
    ...getUrlUiOverrides(),
  };
}

function normalizeShiftMasterBoardSwimlane(value = "") {
  const candidate = String(value || "").trim();
  return SHIFT_MASTER_BOARD_SWIMLANES.some((item) => item.id === candidate) ? candidate : "order";
}

function normalizeShiftMasterBoardFocus(value = "") {
  const candidate = String(value || "").trim();
  return SHIFT_MASTER_BOARD_FOCUS_MODES.some((item) => item.id === candidate) ? candidate : "all";
}

function normalizeShiftMasterBoardLane(value = "") {
  const candidate = String(value || "").trim();
  if (candidate === "ready") return "intake";
  if (candidate === "issued") return "assigned";
  return SHIFT_MASTER_BOARD_LANES.some((item) => item.id === candidate) ? candidate : "";
}

function normalizePlainRecord(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function normalizeShiftMasterAssignmentScopeMode(value = "") {
  const id = String(value || "").trim();
  return SHIFT_MASTER_ASSIGNMENT_SCOPE_MODES.some((mode) => mode.id === id) ? id : "department";
}

function normalizeIdList(value = []) {
  return [...new Set((Array.isArray(value) ? value : [])
    .map((item) => String(item || "").trim())
    .filter(Boolean))];
}

function normalizeShiftMasterAssignmentMatrix(value = {}) {
  return Object.fromEntries(Object.entries(normalizePlainRecord(value))
    .map(([masterId, config]) => {
      const normalizedMasterId = String(masterId || "").trim();
      if (!normalizedMasterId) return null;
      const record = normalizePlainRecord(config);
      return [normalizedMasterId, {
        mode: normalizeShiftMasterAssignmentScopeMode(record.mode),
        employeeIds: normalizeIdList(record.employeeIds),
        updatedAt: String(record.updatedAt || ""),
      }];
    })
    .filter(Boolean));
}

function normalizeShiftMasterBoardRiskReason(value = "") {
  const id = String(value || "").trim();
  return SHIFT_MASTER_BOARD_RISK_REASONS.some((item) => item.id === id) ? id : "";
}

function getShiftMasterBoardRiskLabel(value = "") {
  const id = normalizeShiftMasterBoardRiskReason(value);
  return SHIFT_MASTER_BOARD_RISK_REASONS.find((item) => item.id === id)?.label || "Нет риска";
}

function syncUiWithUrlParams() {
  const overrides = getUrlUiOverrides();
  if (overrides.activeModule) ui.activeModule = overrides.activeModule;
  if (overrides.activeDirectory) ui.activeDirectory = overrides.activeDirectory;
}

function updateModuleUrlParam(moduleId = "") {
  if (typeof window === "undefined" || !window.history?.replaceState) return;
  const url = new URL(window.location.href);
  if (moduleId) {
    url.searchParams.set("module", moduleId);
  } else {
    url.searchParams.delete("module");
  }
  window.history.replaceState(null, "", `${url.pathname}${url.search}${url.hash}`);
}

function loadUiState() {
  try {
    const raw = localStorage.getItem(UI_STORAGE_KEY);
    if (!raw) return applyUrlUiOverrides(applyAuthGateSession({
      ...defaultUiState,
      expandedProjects: new Set(defaultUiState.expandedProjects),
    }));
    const parsed = JSON.parse(raw);
    const accessRoleProfiles = normalizeAccessRoleProfiles(parsed.accessRoleProfiles);
    const accessRoleAssignments = normalizeAccessRoleAssignments(parsed.accessRoleAssignments);
    const storedModule = normalizeStoredModuleId(parsed.activeModule);
    return applyUrlUiOverrides(applyAuthGateSession({
      ...defaultUiState,
      ...parsed,
      activeRole: normalizeInterfaceRoleId(parsed.activeRole, accessRoleProfiles),
      activeModule: storedModule,
      scale: parsed.scale === "weeks" ? "days" : scaleConfig[parsed.scale] ? parsed.scale : defaultUiState.scale,
      expandedProjects: new Set(parsed.expandedProjects || defaultUiState.expandedProjects),
      selectedDirectoryRows: parsed.selectedDirectoryRows || {},
      directoryColumnFilters: normalizeDirectoryColumnFilters(parsed.directoryColumnFilters),
      spekiStaleItemIds: Array.isArray(parsed.spekiStaleItemIds) ? parsed.spekiStaleItemIds : [],
      spekiCollapsedBomIds: Array.isArray(parsed.spekiCollapsedBomIds) ? parsed.spekiCollapsedBomIds : [],
      supplyCollapsedGroups: normalizeSupplyCollapsedGroups(parsed.supplyCollapsedGroups),
      routeBindingMode: parsed.routeBindingMode === "bom" ? "bom" : "product",
      planningWorkItem: String(parsed.planningWorkItem || ""),
      planningLaborNoteByRow: normalizePlanningLaborNoteByRow({
        ...(parsed.planningDemoLaborByRow || {}),
        ...(parsed.planningLaborNoteByRow || {}),
      }),
      planningLegacyManualLaborByStep: normalizePlanningLegacyManualLaborByStep({
        ...(parsed.planningThtDemoByStep || {}),
        ...(parsed.planningManualDemoByStep || {}),
        ...(parsed.planningLegacyManualLaborByStep || {}),
      }),
      shiftMasterScope: parsed.shiftMasterScope === "master" ? "master" : "all",
      shiftMasterBoardSelectedSlotId: String(parsed.shiftMasterBoardSelectedSlotId || ""),
      shiftMasterBoardSwimlane: normalizeShiftMasterBoardSwimlane(parsed.shiftMasterBoardSwimlane),
      shiftMasterBoardFocus: normalizeShiftMasterBoardFocus(parsed.shiftMasterBoardFocus),
      shiftMasterBoardLaneBySlot: normalizePlainRecord(parsed.shiftMasterBoardLaneBySlot),
      shiftMasterBoardAssignments: normalizePlainRecord(parsed.shiftMasterBoardAssignments),
      shiftMasterBoardFacts: normalizePlainRecord(parsed.shiftMasterBoardFacts),
      shiftMasterBoardCarryovers: normalizePlainRecord(parsed.shiftMasterBoardCarryovers),
      shiftMasterBoardPrintPreviewId: String(parsed.shiftMasterBoardPrintPreviewId || ""),
      shiftWorkOrderJournalSelectedId: String(parsed.shiftWorkOrderJournalSelectedId || ""),
      shiftWorkOrderPrintPreviewId: "",
      shiftMasterAssignmentMatrix: normalizeShiftMasterAssignmentMatrix(parsed.shiftMasterAssignmentMatrix),
      timesheetView: normalizeTimesheetView(parsed.timesheetView),
      timesheetPeriodAnchor: normalizeDateInput(parsed.timesheetPeriodAnchor || defaultUiState.timesheetPeriodAnchor) || defaultUiState.timesheetPeriodAnchor,
      timesheetCellOverrides: normalizePlainRecord(parsed.timesheetCellOverrides),
      timesheetScheduleOverrides: normalizePlainRecord(parsed.timesheetScheduleOverrides),
      timesheetEditor: null,
      productionStructureMatrixOverrides: normalizePlainRecord(parsed.productionStructureMatrixOverrides),
      accessRoleProfiles,
      accessRoleAssignments,
      accessRolesSelectedRoleId: normalizeInterfaceRoleId(parsed.accessRolesSelectedRoleId || parsed.activeRole, accessRoleProfiles),
      accessRolesSelectedEmployeeId: String(parsed.accessRolesSelectedEmployeeId || ""),
      authCurrentUserId: String(parsed.authCurrentUserId || ""),
      authPrototypeDepartment: "",
      authPrototypeUnit: "",
      authPrototypeSearch: "",
      authPrototypePersonId: "",
      authPrototypeResult: "",
      authPrototypeAttemptsLeft: AUTH_GATE_MAX_ATTEMPTS,
      authSessionViewedPersonId: String(parsed.authSessionViewedPersonId || ""),
      authSessionSelectedTaskId: String(parsed.authSessionSelectedTaskId || ""),
      authSessionFactDrafts: normalizePlainRecord(parsed.authSessionFactDrafts),
      authSessionActiveFactField: parsed.authSessionActiveFactField === "defect" ? "defect" : "actual",
      authSessionModal: null,
      activeNomenclaturePane: parsed.activeModule === "bomLists" || parsed.activeNomenclaturePane === "boards" ? "boards" : "items",
      shopMapEditMode: Boolean(parsed.shopMapEditMode),
      shopMapWidgetLayouts: normalizeShopMapLayoutStore(parsed.shopMapWidgetLayouts),
      ganttDependencyEditMode: false,
      ganttDependencyRoutes: normalizeGanttDependencyRouteStore(parsed.ganttDependencyRoutes),
      ganttDependencyRouteDrafts: null,
      ganttDependencyDrag: null,
      directoryEditor: null,
      directoryReader: null,
      confirmDialog: null,
      selectedSlotId: null,
      editor: null,
      splitSlotId: null,
      ganttOptimizationDialog: null,
      routeSmtPopup: null,
      routePrintPreviewId: "",
      workOrderPrintPreviewId: "",
      drag: null,
      timelineCounts: {
        ...defaultUiState.timelineCounts,
        ...(parsed.timelineCounts || {}),
      },
      ganttZoom: normalizeGanttZoom(parsed.ganttZoom),
      ganttSlotContent: normalizeGanttSlotContent(parsed.ganttSlotContent),
      ganttShowQuantity: typeof parsed.ganttShowQuantity === "boolean" ? parsed.ganttShowQuantity : defaultUiState.ganttShowQuantity,
      hideSharedNonWorkingZones: Boolean(parsed.hideSharedNonWorkingZones),
      focusMode: Boolean(parsed.focusMode),
      // Visual QA is a one-shot picker, not a persistent work mode. Keeping it
      // restored from localStorage makes ordinary buttons look like they
      // flicker on hover and consumes the first click for inspection.
      visualQaEnabled: false,
      now: new Date(),
    }));
  } catch {
    return applyUrlUiOverrides(applyAuthGateSession({
      ...defaultUiState,
      expandedProjects: new Set(defaultUiState.expandedProjects),
    }));
  }
}

