function normalizeSupplyControlStatus(value = "") {
  const normalized = String(value || "").trim();
  return SUPPLY_CONTROL_STATUS_OPTIONS.some((option) => option.id === normalized)
    ? normalized
    : "not_purchased";
}

function normalizeSupplyControlQuantity(value) {
  if (value === "" || value === null || typeof value === "undefined") return 0;
  const normalized = Number(String(value).replace(",", "."));
  if (!Number.isFinite(normalized) || normalized < 0) return 0;
  return Math.round(normalized * 1000) / 1000;
}

function normalizeSupplyControlDate(value = "") {
  const normalized = String(value || "").trim();
  if (!normalized) return "";
  const date = normalized.includes("T") ? toDate(normalized) : toDate(fromDateInput(normalized));
  return Number.isNaN(date.getTime()) ? "" : toDateInput(date);
}

function normalizeSupplyControlRecord(record = {}) {
  return {
    status: normalizeSupplyControlStatus(record.status),
    erpDoc: String(record.erpDoc || "").trim(),
    purchasedQuantity: normalizeSupplyControlQuantity(record.purchasedQuantity),
    deliveredQuantity: normalizeSupplyControlQuantity(record.deliveredQuantity),
    plannedDate: normalizeSupplyControlDate(record.plannedDate),
    actualDate: normalizeSupplyControlDate(record.actualDate),
    supplier: String(record.supplier || "").trim(),
    comment: String(record.comment || "").trim(),
  };
}

function isEmptySupplyControlRecord(record = {}) {
  const normalized = normalizeSupplyControlRecord(record);
  return normalized.status === "not_purchased"
    && !normalized.erpDoc
    && normalized.purchasedQuantity <= 0
    && normalized.deliveredQuantity <= 0
    && !normalized.plannedDate
    && !normalized.actualDate
    && !normalized.supplier
    && !normalized.comment;
}

function normalizeSupplyControlState(value = {}) {
  const sourceRows = value && typeof value === "object" && value.rows && typeof value.rows === "object"
    ? value.rows
    : {};
  return {
    rows: Object.fromEntries(Object.entries(sourceRows)
      .map(([key, record]) => [String(key), normalizeSupplyControlRecord(record)])
      .filter(([, record]) => !isEmptySupplyControlRecord(record))),
  };
}

function loadSupplyControlState() {
  try {
    return normalizeSupplyControlState(JSON.parse(localStorage.getItem(SUPPLY_CONTROL_STORAGE_KEY) || "{}"));
  } catch {
    return normalizeSupplyControlState();
  }
}

function persistSupplyControlState() {
  supplyControlState = normalizeSupplyControlState(supplyControlState);
  localStorage.setItem(SUPPLY_CONTROL_STORAGE_KEY, JSON.stringify(supplyControlState));
  scheduleSharedStatePush("supply-control");
}

function getSupplyControlKey(route = {}, row = {}) {
  return `${route?.id || "route"}::${row?.id || "row"}`;
}

function getSupplyControlRecord(key = "") {
  return normalizeSupplyControlRecord(supplyControlState.rows?.[key] || {});
}

function deriveSupplyControlStatus(record = {}, row = {}) {
  const normalized = normalizeSupplyControlRecord(record);
  if (normalized.status === "blocked") return "blocked";
  const requiredQuantity = Math.max(0, Number(row.requiredQuantity || 0));
  if (requiredQuantity > 0 && normalized.deliveredQuantity >= requiredQuantity) return "delivered";
  if (normalized.deliveredQuantity > 0) return "partial";
  if (normalized.status !== "not_purchased") return normalized.status;
  if (normalized.purchasedQuantity > 0 || normalized.erpDoc) return "ordered";
  if (normalized.plannedDate || normalized.supplier) return "requested";
  return "not_purchased";
}

function getSupplyControlStatusVisual(status = "not_purchased") {
  return SUPPLY_CONTROL_STATUS_OPTIONS.find((option) => option.id === status)
    || SUPPLY_CONTROL_STATUS_OPTIONS[0];
}

function applySupplyControlRows(route, rows = []) {
  return rows.map((row) => {
    const controlKey = getSupplyControlKey(route, row);
    const control = getSupplyControlRecord(controlKey);
    const status = deriveSupplyControlStatus(control, row);
    const visual = getSupplyControlStatusVisual(status);
    return {
      ...row,
      controlKey,
      control,
      erpDocs: control.erpDoc ? [control.erpDoc] : [],
      purchasedQuantity: control.purchasedQuantity,
      deliveredQuantity: control.deliveredQuantity,
      controlStatus: status,
      controlStatusLabel: visual.label,
      controlTone: visual.tone,
    };
  });
}

function updateSupplyControlField(key = "", field = "", value = "") {
  if (!key || !field) return;
  const current = getSupplyControlRecord(key);
  const next = normalizeSupplyControlRecord({
    ...current,
    [field]: value,
  });
  if (isEmptySupplyControlRecord(next)) {
    delete supplyControlState.rows[key];
  } else {
    supplyControlState.rows[key] = next;
  }
  persistSupplyControlState();
  render();
}

function clearSupplyControlForRoute(routeId = "") {
  if (!routeId) return;
  const prefix = `${routeId}::`;
  Object.keys(supplyControlState.rows || {}).forEach((key) => {
    if (key.startsWith(prefix)) delete supplyControlState.rows[key];
  });
  persistSupplyControlState();
  render();
}

function getSupplyDateValue(value = "") {
  const normalized = normalizeSupplyControlDate(value);
  if (!normalized) return null;
  const date = toDate(fromDateInput(normalized));
  return Number.isNaN(date.getTime()) ? null : startOfDay(date);
}

function getSupplyOrderRoutes() {
  return getRoutesForModule()
    .filter((route) => route?.id)
    .filter((route) => getRouteProductionContext(route) || getRouteSpecification(route) || getRouteBomList(route));
}

function getActiveSupplyRoute(routes = getSupplyOrderRoutes()) {
  const active = routes.find((route) => route.id === ui.activeSupplyRouteId)
    || routes.find((route) => route.id === ui.activeRouteId)
    || routes[0]
    || null;
  if (active && ui.activeSupplyRouteId !== active.id) ui.activeSupplyRouteId = active.id;
  return active;
}

function getSupplyRouteDueDate(route = null) {
  const production = getRouteProductionContext(route);
  const raw = production?.dueDate || route?.dueDate || "";
  if (!raw) return null;
  const value = String(raw).includes("T") ? toDate(raw) : toDate(fromDateInput(raw));
  return Number.isNaN(value.getTime()) ? null : startOfDay(value);
}

function getSupplyDayScale(route = null) {
  const dueDate = getSupplyRouteDueDate(route);
  const now = startOfWeek(ui.now || new Date());
  const dueAnchor = dueDate && dueDate < now ? startOfWeek(dueDate) : now;
  const rawScale = buildTimeScale("days", dueAnchor, SUPPLY_DAY_COUNT);
  return {
    ...rawScale,
    cellWidth: SUPPLY_DAY_WIDTH,
    width: SUPPLY_DAY_COUNT * SUPPLY_DAY_WIDTH,
  };
}

function getSupplyBomEntries(route, transferSummary = null) {
  if (!route) return [];
  const planningQuantity = normalizeQuantity(transferSummary?.planningQuantity || getPlanningRouteQuantity(route));
  const specification = getRouteSpecification(route);
  if (specification) {
    return getSpecificationBomEntries(specification.id).map((entry) => {
      const boardQuantity = Math.max(1, Math.round(planningQuantity * Math.max(1, Number(entry.quantity || 1))));
      return {
        ...entry,
        sourceId: entry.structureItemId || entry.bom.id,
        boardQuantity,
      };
    });
  }

  const bom = getRouteBomList(route);
  return bom ? [{
    bom,
    quantity: 1,
    boardsPerPanel: normalizeBoardsPerPanel(route.boardsPerPanel, 1),
    slot: "PCB",
    structureItemId: bom.id,
    sourceId: bom.id,
    boardQuantity: Math.max(1, planningQuantity),
  }] : [];
}

function getSupplyComponentKey(row = {}, nomenclatureItem = null, bom = null, rowIndex = 0) {
  if (nomenclatureItem?.id) return `rek:${nomenclatureItem.id}`;
  const identityParts = [
    row.manufacturerPart,
    row.description,
    row.manufacturer,
    row.package,
  ].map((part) => normalizeSmtComponentKeyPart(part)).filter(Boolean);
  return identityParts.length
    ? `rek:${identityParts.join(":")}`
    : `rek:${bom?.id || "bom"}:${rowIndex + 1}`;
}

function getSupplyBomEntryGroup(entry = {}, index = 0) {
  const resultItem = getBomResultNomenclatureItem(entry.bom?.id);
  const sourceLabel = entry.bom?.name || entry.bom?.boardCode || BOARD_SPEC_TERM;
  const title = resultItem?.name || entry.bom?.resultItem || entry.bom?.boardCode || entry.bom?.name || "Печатная плата";
  return {
    id: `board:${entry.sourceId || entry.structureItemId || entry.bom?.id || index + 1}`,
    title,
    article: resultItem?.article || entry.bom?.boardCode || "",
    sourceLabel,
    quantity: Math.max(0, Number(entry.boardQuantity || 0)),
    order: index,
  };
}

function buildSupplyProcurementRows(route) {
  if (!route) return [];
  const transferSummary = getPlanningRouteTransferSummary(route);
  const bomEntries = getSupplyBomEntries(route, transferSummary);
  const boardGroups = bomEntries.map((entry, index) => getSupplyBomEntryGroup(entry, index));
  const pcbRows = bomEntries.map((entry, index) => {
    const group = boardGroups[index];
    return {
      id: `pcb:${entry.sourceId}`,
      groupId: group.id,
      groupTitle: group.title,
      groupArticle: group.article,
      groupSourceLabel: group.sourceLabel,
      groupBoardQuantity: group.quantity,
      groupOrder: group.order,
      kind: "pcb",
      typeLabel: "Печатная плата",
      title: group.title,
      article: group.article,
      package: "PCB",
      manufacturer: "",
      sourceLabel: group.sourceLabel,
      bomLabels: [group.sourceLabel],
      designators: "",
      requiredQuantity: entry.boardQuantity,
      boardQuantity: entry.boardQuantity,
      perBoardQuantity: 1,
      unit: "шт.",
      erpDocs: [],
      purchasedQuantity: 0,
      deliveredQuantity: 0,
      stockQuantity: 0,
      tone: "warning",
    };
  });

  const componentMap = new Map();
  const scopeComponentsByBoard = bomEntries.length > 1;
  bomEntries.forEach((entry, entryIndex) => {
    const group = boardGroups[entryIndex];
    getBomImportRows(entry.bom)
      .filter((row) => Number(row.quantity || 0) > 0)
      .forEach((row, rowIndex) => {
        const nomenclatureItem = getBomImportRowNomenclatureItem(row, entry.bom);
        const baseKey = getSupplyComponentKey(row, nomenclatureItem, entry.bom, rowIndex);
        const key = scopeComponentsByBoard ? `${baseKey}::${entry.sourceId || group.id}` : baseKey;
        const perBoardQuantity = Math.max(0, Number(row.quantity || 0));
        const existing = componentMap.get(key) || {
          id: key,
          groupId: group.id,
          groupTitle: group.title,
          groupArticle: group.article,
          groupSourceLabel: group.sourceLabel,
          groupBoardQuantity: group.quantity,
          groupOrder: group.order,
          kind: "rek",
          typeLabel: "РЭК",
          title: nomenclatureItem?.name || row.description || row.manufacturerPart || `Компонент BOM ${row.sequence || rowIndex + 1}`,
          article: nomenclatureItem?.article || row.manufacturerPart || "",
          package: nomenclatureItem?.package || row.package || "",
          manufacturer: nomenclatureItem?.manufacturer || row.manufacturer || "",
          sourceSet: new Set(),
          designatorSet: new Set(),
          requiredQuantity: 0,
          unit: nomenclatureItem?.unit || "шт.",
          erpDocs: [],
          purchasedQuantity: 0,
          deliveredQuantity: 0,
          stockQuantity: 0,
          tone: "warning",
          bomRowCount: 0,
          boardQuantity: entry.boardQuantity,
          perBoardQuantity: 0,
        };
        existing.sourceSet.add(group.sourceLabel);
        if (row.designator) existing.designatorSet.add(row.designator);
        existing.requiredQuantity += perBoardQuantity * entry.boardQuantity;
        existing.perBoardQuantity += perBoardQuantity;
        existing.bomRowCount += 1;
        componentMap.set(key, existing);
      });
  });

  const componentRows = [...componentMap.values()].map((row) => {
    const bomLabels = [...row.sourceSet].filter(Boolean);
    const designators = [...row.designatorSet].filter(Boolean);
    return {
      ...row,
      sourceLabel: bomLabels.slice(0, 3).join(", ") + (bomLabels.length > 3 ? ` +${bomLabels.length - 3}` : ""),
      bomLabels,
      designators: designators.slice(0, 3).join(", ") + (designators.length > 3 ? ` +${designators.length - 3}` : ""),
      requiredQuantity: Math.round(row.requiredQuantity * 1000) / 1000,
      perBoardQuantity: Math.round(row.perBoardQuantity * 1000) / 1000,
    };
  });

  return [...pcbRows, ...componentRows]
    .filter((row) => row.requiredQuantity > 0)
    .sort((left, right) => {
      if (left.groupOrder !== right.groupOrder) return Number(left.groupOrder || 0) - Number(right.groupOrder || 0);
      if (left.kind !== right.kind) return left.kind === "pcb" ? -1 : 1;
      return String(left.title || "").localeCompare(String(right.title || ""), "ru");
    });
}

function getSupplyBoardGroups(rows = []) {
  const groups = [];
  const groupById = new Map();
  rows.forEach((row) => {
    const groupId = row.groupId || row.id || "board";
    let group = groupById.get(groupId);
    if (!group) {
      group = {
        id: groupId,
        title: row.groupTitle || row.title || "Печатная плата",
        article: row.groupArticle || "",
        sourceLabel: row.groupSourceLabel || row.sourceLabel || BOARD_SPEC_TERM,
        boardQuantity: Number(row.groupBoardQuantity || 0),
        order: Number(row.groupOrder || groups.length),
        rows: [],
      };
      groupById.set(groupId, group);
      groups.push(group);
    }
    group.rows.push(row);
    if (row.kind === "pcb") {
      group.pcbRow = row;
      group.boardQuantity = Number(row.requiredQuantity || group.boardQuantity || 0);
    }
  });

  return groups.sort((left, right) => left.order - right.order);
}

function getSupplyBoardGroupMeta(group = {}) {
  const titleText = String(group.title || "").toLowerCase();
  const sourceLabel = String(group.sourceLabel || "");
  const sourceInTitle = sourceLabel && titleText.includes(sourceLabel.toLowerCase());
  return [
    sourceInTitle ? "" : sourceLabel,
    group.article && group.article !== group.sourceLabel ? `PN: ${group.article}` : "",
    `${formatReportNumber(group.boardQuantity)} плат`,
    `${group.rows?.filter((row) => row.kind === "rek").length || 0} поз. РЭК`,
  ].filter(Boolean).join(" · ");
}

function getSupplyCollapsedGroupSet(route = null) {
  const routeId = String(route?.id || "");
  const store = normalizeSupplyCollapsedGroups(ui.supplyCollapsedGroups || {});
  return new Set(routeId && Array.isArray(store[routeId]) ? store[routeId] : []);
}

function isSupplyGroupCollapsed(route = null, group = {}) {
  return getSupplyCollapsedGroupSet(route).has(String(group.id || ""));
}

function toggleSupplyGroup(routeId = "", groupId = "") {
  const normalizedRouteId = String(routeId || "").trim();
  const normalizedGroupId = String(groupId || "").trim();
  if (!normalizedRouteId || !normalizedGroupId) return;

  const store = normalizeSupplyCollapsedGroups(ui.supplyCollapsedGroups || {});
  const collapsedIds = new Set(store[normalizedRouteId] || []);
  if (collapsedIds.has(normalizedGroupId)) {
    collapsedIds.delete(normalizedGroupId);
  } else {
    collapsedIds.add(normalizedGroupId);
  }

  const nextIds = [...collapsedIds];
  if (nextIds.length) {
    store[normalizedRouteId] = nextIds;
  } else {
    delete store[normalizedRouteId];
  }
  ui.supplyCollapsedGroups = store;
  persistUiState();
  render();
}

function getSupplyRouteStats(route) {
  const rows = applySupplyControlRows(route, buildSupplyProcurementRows(route));
  return {
    rows,
    total: rows.length,
    pcb: rows.filter((row) => row.kind === "pcb").length,
    rek: rows.filter((row) => row.kind === "rek").length,
    pending: rows.filter((row) => !row.erpDocs.length).length,
    controlled: rows.filter((row) => !isEmptySupplyControlRecord(row.control)).length,
    erpDocs: rows.filter((row) => row.erpDocs.length).length,
    deliveries: rows.filter((row) => Number(row.deliveredQuantity || 0) > 0 || row.control?.plannedDate || row.control?.actualDate).length,
    blocked: rows.filter((row) => row.controlStatus === "blocked").length,
    delivered: rows.filter((row) => row.controlStatus === "delivered").length,
    purchasedQuantity: rows.reduce((sum, row) => sum + Number(row.purchasedQuantity || 0), 0),
    requiredQuantity: rows.reduce((sum, row) => sum + Number(row.requiredQuantity || 0), 0),
  };
}

function renderSupplyPage() {
  const routes = getSupplyOrderRoutes();
  const activeRoute = getActiveSupplyRoute(routes);
  const production = getRouteProductionContext(activeRoute);
  const transferSummary = activeRoute ? getPlanningRouteTransferSummary(activeRoute) : null;
  const routeStats = getSupplyRouteStats(activeRoute);
  const rows = routeStats.rows;
  const scaleInfo = getSupplyDayScale(activeRoute);
  const dueDate = getSupplyRouteDueDate(activeRoute);
  const routeTitle = activeRoute
    ? getProjectDisplayName(production) || getRouteModuleSelectionName(activeRoute) || activeRoute.name || "Заказ-наряд"
    : "Заказ-наряд не выбран";
  const routeMeta = activeRoute
    ? [
      activeRoute.name || "маршрутная карта",
      `${Number(transferSummary?.planningQuantity || getPlanningRouteQuantity(activeRoute) || 0).toLocaleString("ru-RU")} шт.`,
      dueDate ? `срок ${formatDate(dueDate)}` : "срок не задан",
    ].join(" · ")
    : "Выберите заказ-наряд, чтобы увидеть потребность BOM.";

  return renderUiModulePage({
    ariaLabel: "Снабжение",
    className: "supply-page",
    workspaceClassName: "supply-workspace",
    contentClassName: "supply-content",
    sidebar: renderUiModuleSidebar({
      eyebrow: "Закупочный контур",
      title: "Снабжение",
      className: "supply-sidebar",
      body: `
        <div class="ui-sidebar-list supply-route-list">
          <div class="ui-sidebar-label">Заказ-наряды</div>
          ${routes.length ? routes.map((route) => renderSupplyRouteCard(route, route.id === activeRoute?.id)).join("") : renderModulePreviewEmpty({
            iconName: "calendar",
            title: "Заказ-нарядов нет",
            text: "Снабжение строится от сохраненных маршрутных карт и заказ-нарядов.",
          })}
        </div>
      `,
    }),
    header: renderUiModuleHeader({
      eyebrow: "Синтетический контроль",
      title: routeTitle,
      description: routeMeta,
      className: "directory-header supply-header",
      cornerMarker: renderUiDemoCornerMarker("Снабжение: синтетический контроль без влияния на систему"),
      actions: `<span class="supply-readonly-badge">${icon("edit")}<span>не влияет на систему</span></span>`,
    }),
    content: `
      ${renderUiPanel({
        title: "Гант снабжения",
        meta: "дневной горизонт с группировкой по неделям; строки закупки считаются из BOM заказ-наряда",
        className: "supply-gantt-panel",
        cornerMarker: renderUiDemoCornerMarker("Демо-блок: Гант снабжения не меняет производственный план"),
        actions: `<em class="supply-status-pill is-${escapeAttribute(routeStats.blocked ? "danger" : routeStats.pending ? "warning" : "ok")}">${routeStats.blocked ? "есть проблемы" : routeStats.pending ? "часть без счета" : "контроль заполнен"}</em>`,
        body: renderUiPanelBody({
          body: rows.length ? renderSupplyDailyGantt(activeRoute, rows, scaleInfo) : renderModulePreviewEmpty({
            iconName: "bom",
            title: "BOM-потребность не найдена",
            text: "У выбранного заказ-наряда нет плат или строк BOM для закупочного контроля.",
          }),
        }),
      })}

      ${renderUiPanel({
        title: "Реестр потребности",
        meta: rows.length ? `${rows.length} строк к контролю` : "нет строк",
        className: "supply-table-panel",
        cornerMarker: renderUiDemoCornerMarker("Демо-блок: реестр снабжения хранит синтетический контроль"),
        actions: `<button class="secondary-button supply-clear-button ui-action-button" data-supply-clear-route="${escapeAttribute(activeRoute?.id || "")}" type="button" ${routeStats.controlled ? "" : "disabled"}>${icon("refresh")}<span>Очистить контроль</span></button>`,
        body: renderUiPanelBody({
          body: rows.length ? renderSupplyRegisterTable(activeRoute, rows) : renderModulePreviewEmpty({
            iconName: "package",
            title: "Компоненты не рассчитаны",
            text: "После привязки BOM здесь появятся платы и РЭК без создания закупочных записей.",
          }),
        }),
      })}

      <section class="supply-kpi-grid is-bottom ui-demo-marker-host" aria-label="Итоги снабжения">
        ${renderUiDemoCornerMarker("Демо-блок: итоги снабжения не влияют на систему")}
        ${renderSupplyKpi("Печатные платы", routeStats.pcb, "тиражи из BOM", "pcb")}
        ${renderSupplyKpi("РЭК", routeStats.rek, "компоненты BOM", "rek")}
        ${renderSupplyKpi("ERP документы", routeStats.erpDocs, routeStats.erpDocs ? "внесено вручную" : "счета не внесены", routeStats.erpDocs ? "primary" : "warning")}
        ${renderSupplyKpi("Поставки", routeStats.deliveries, routeStats.delivered ? `${routeStats.delivered} закрыто` : "контроль план/факт", routeStats.deliveries ? "ok" : "neutral")}
      </section>
      ${renderSupplyDemandPopover(activeRoute, rows)}
    `,
  });
}

function renderSupplyRouteCard(route, isActive = false) {
  const production = getRouteProductionContext(route);
  const dueDate = getSupplyRouteDueDate(route);
  const stats = getSupplyRouteStats(route);
  const title = getProjectDisplayName(production) || getRouteModuleSelectionName(route) || route.name || "Заказ-наряд";
  return renderUiSidebarItem({
    title,
    meta: `${route.name || "маршрутная карта"} · ${dueDate ? formatDate(dueDate) : "срок не задан"}`,
    badge: stats.total.toLocaleString("ru-RU"),
    active: isActive,
    className: "supply-route-card",
    attributes: `data-supply-route-open="${escapeAttribute(route.id)}" type="button"`,
  });
}

function renderSupplyKpi(label, value, meta, tone = "neutral") {
  const iconName = tone === "pcb" ? "bom" : tone === "rek" ? "package" : tone === "warning" ? "alert" : "supply";
  return `
    <article class="supply-kpi-card is-${escapeAttribute(tone)}">
      <span>${icon(iconName)}</span>
      <div>
        <small>${escapeHtml(label)}</small>
        <strong>${escapeHtml(String(value))}</strong>
        <em>${escapeHtml(meta)}</em>
      </div>
    </article>
  `;
}

function renderSupplyDailyGantt(route, rows, scaleInfo) {
  const groups = getSupplyBoardGroups(rows);
  return `
    <div class="supply-gantt-shell" style="--supply-left-width: 260px; --supply-day-count: ${scaleInfo.ticks.length}; --supply-day-width: ${scaleInfo.cellWidth}px; --supply-timeline-width: ${scaleInfo.width}px;">
      <div class="supply-timeline-row">
        <div class="supply-timeline-corner">
          <strong>Компоненты</strong>
          <span>дни внутри недель</span>
        </div>
        <div class="supply-timeline-cells">
          <div class="supply-week-group-row">
            ${getTimelineWeekGroups(scaleInfo).map((group) => renderSupplyWeekGroup(group, scaleInfo)).join("")}
          </div>
          <div class="supply-day-row">
            ${scaleInfo.ticks.map((tick, index) => renderSupplyDayCell(tick, index, scaleInfo)).join("")}
          </div>
        </div>
      </div>
      <div class="supply-gantt-body">
        ${groups.map((group) => renderSupplyGanttGroup(route, group, scaleInfo)).join("")}
      </div>
      <div class="supply-gantt-legend">
        <span><i class="is-demand"></i>потребность BOM</span>
        <span><i class="is-weekend"></i>выходные; праздничный календарь не подключен</span>
        <span><i class="is-empty"></i>поставки и ERP-документы не подключены</span>
      </div>
    </div>
  `;
}

function renderSupplyGanttGroup(route, group, scaleInfo) {
  const meta = getSupplyBoardGroupMeta(group);
  const collapsed = isSupplyGroupCollapsed(route, group);
  const routeId = route?.id || "";
  return `
    <section class="supply-gantt-group ${collapsed ? "is-collapsed" : ""}" aria-label="${escapeAttribute(group.title)}">
      <div class="supply-gantt-group-row">
        <div class="supply-gantt-group-label">
          <button
            class="icon-button supply-group-toggle ui-action-button"
            data-supply-group-toggle="${escapeAttribute(group.id)}"
            data-supply-route-id="${escapeAttribute(routeId)}"
            type="button"
            aria-expanded="${collapsed ? "false" : "true"}"
            title="${collapsed ? "Раскрыть группу" : "Свернуть группу"}"
          >
            ${icon(collapsed ? "chevronRight" : "chevronDown")}
          </button>
          <b>Плата</b>
          <span>
            <strong>${escapeHtml(group.title)}</strong>
            <small>${escapeHtml(meta)}</small>
          </span>
        </div>
        <div class="supply-group-lane">
          ${renderSupplyLaneGrid(scaleInfo)}
        </div>
      </div>
      ${collapsed ? "" : group.rows.map((row) => renderSupplyGanttRow(route, row, scaleInfo)).join("")}
    </section>
  `;
}

function getSupplyTimelinePercent(value, scaleInfo) {
  const width = Math.max(1, Number(scaleInfo?.width || 1));
  return `${round((Math.max(0, Math.min(width, value)) / width) * 100)}%`;
}

function getSupplyTickPercent(index, scaleInfo) {
  return `${round((index / Math.max(1, scaleInfo.ticks.length)) * 100)}%`;
}

function getSupplyTickWidthPercent(scaleInfo) {
  return `${round(100 / Math.max(1, scaleInfo.ticks.length))}%`;
}

function getSupplyTickSpanWidthPercent(dayCount, scaleInfo) {
  return `${round((dayCount / Math.max(1, scaleInfo.ticks.length)) * 100)}%`;
}

function getTimelineWeekGroups(scaleInfo) {
  const groups = [];
  scaleInfo.ticks.forEach((tick, index) => {
    const weekStart = startOfWeek(tick.start);
    const key = toDateInput(weekStart);
    const last = groups[groups.length - 1];
    if (!last || last.key !== key) {
      groups.push({
        key,
        start: weekStart,
        startIndex: index,
        dayCount: 1,
      });
    } else {
      last.dayCount += 1;
    }
  });
  return groups;
}

function renderSupplyWeekGroup(group, scaleInfo) {
  const weekEnd = addMs(group.start, (group.dayCount - 1) * DAY_MS);
  return `
    <div class="supply-week-group" style="left:${getSupplyTickPercent(group.startIndex, scaleInfo)}; width:${getSupplyTickSpanWidthPercent(group.dayCount, scaleInfo)};">
      <strong>Н${getWeekNumber(group.start)}</strong>
      <small>${escapeHtml(formatShortDate(group.start))}-${escapeHtml(formatShortDate(weekEnd))}</small>
    </div>
  `;
}

function renderSupplyDayCell(tick, index, scaleInfo) {
  const isWeekend = tick.start.getDay() === 0 || tick.start.getDay() === 6;
  const isWeekStart = tick.start.getDay() === 1 || index === 0;
  return `
    <div class="supply-day-cell ${isWeekend ? "is-weekend" : ""} ${isWeekStart ? "is-week-start" : ""}" style="left:${getSupplyTickPercent(index, scaleInfo)}; width:${getSupplyTickWidthPercent(scaleInfo)};" title="${escapeAttribute(formatDate(tick.start))}">
      <strong>${escapeHtml(formatShortDate(tick.start))}</strong>
    </div>
  `;
}

function getSupplyDemandBarStyle(route, scaleInfo) {
  const dueDate = getSupplyRouteDueDate(route);
  const barStart = scaleInfo.start;
  const defaultEnd = scaleInfo.end;
  const rawEnd = dueDate && dueDate > barStart ? addMs(dueDate, DAY_MS) : defaultEnd;
  const end = new Date(Math.min(defaultEnd.getTime(), Math.max(addMs(barStart, 7 * DAY_MS).getTime(), rawEnd.getTime())));
  const left = 8;
  const width = Math.max(44, Math.min(scaleInfo.width - left - 8, dateToX(end, scaleInfo) - left));
  return `left:${getSupplyTimelinePercent(left, scaleInfo)};width:${getSupplyTimelinePercent(width, scaleInfo)};`;
}

function renderSupplyDueMarker(route, scaleInfo) {
  const dueDate = getSupplyRouteDueDate(route);
  if (!dueDate || dueDate < scaleInfo.start || dueDate > scaleInfo.end) return "";
  const left = Math.max(0, Math.min(scaleInfo.width, dateToX(dueDate, scaleInfo)));
  return `<span class="supply-due-marker" style="left:${getSupplyTimelinePercent(left, scaleInfo)};" title="Срок заказ-наряда: ${escapeAttribute(formatDate(dueDate))}"></span>`;
}

function renderSupplyTodayMarker(scaleInfo) {
  const today = startOfDay(ui.now || new Date());
  if (today < scaleInfo.start || today > scaleInfo.end) return "";
  const left = Math.max(0, Math.min(scaleInfo.width, dateToX(today, scaleInfo)));
  return `<span class="supply-today-marker" style="left:${getSupplyTimelinePercent(left, scaleInfo)};" title="Сегодня"></span>`;
}

function renderSupplyLaneGrid(scaleInfo) {
  return scaleInfo.ticks.map((tick, index) => `
    <span
      class="supply-lane-day ${tick.start.getDay() === 0 || tick.start.getDay() === 6 ? "is-weekend" : ""} ${tick.start.getDay() === 1 || index === 0 ? "is-week-start" : ""}"
      style="left:${getSupplyTickPercent(index, scaleInfo)}; width:${getSupplyTickWidthPercent(scaleInfo)};"
      title="${escapeAttribute(formatDate(tick.start))}"
    >
    </span>
  `).join("");
}

function renderSupplyDeliveryMarker(row, scaleInfo, field, label, className = "") {
  const date = getSupplyDateValue(row.control?.[field] || "");
  if (!date || date < scaleInfo.start || date > scaleInfo.end) return "";
  const left = Math.max(0, Math.min(scaleInfo.width, dateToX(date, scaleInfo)));
  return `
    <span
      class="supply-delivery-marker ${className}"
      style="left:${getSupplyTimelinePercent(left, scaleInfo)};"
      title="${escapeAttribute(`${label}: ${formatDate(date)}`)}"
    >
      <i>${escapeHtml(label)}</i>
    </span>
  `;
}

function renderSupplyGanttRow(route, row, scaleInfo) {
  const quantityMeta = row.kind === "rek" && Number(row.perBoardQuantity || 0) > 0
    ? `на плату ${formatReportNumber(row.perBoardQuantity)}`
    : "";
  const meta = [row.article ? `PN: ${row.article}` : "", row.package, quantityMeta, row.sourceLabel].filter(Boolean).join(" · ") || row.typeLabel;
  const tagLabel = row.kind === "pcb" ? "PCB" : "РЭК";
  const purchasedLabel = Number(row.purchasedQuantity || 0) > 0
    ? `${formatReportNumber(row.purchasedQuantity)} / ${formatReportNumber(row.requiredQuantity)} ${row.unit || "шт."}`
    : `${formatReportNumber(row.requiredQuantity)} ${row.unit || "шт."}`;
  return `
    <article class="supply-gantt-row is-${escapeAttribute(row.kind)}">
      <div class="supply-gantt-label">
        <b>${escapeHtml(tagLabel)}</b>
        <span>
          <strong>${escapeHtml(row.title)}</strong>
          <small>${escapeHtml(meta)}</small>
        </span>
        <em>${escapeHtml(formatReportNumber(row.requiredQuantity))} ${escapeHtml(row.unit || "шт.")}</em>
      </div>
      <div class="supply-lane">
        ${renderSupplyLaneGrid(scaleInfo)}
        ${renderSupplyTodayMarker(scaleInfo)}
        ${renderSupplyDueMarker(route, scaleInfo)}
        ${renderSupplyDeliveryMarker(row, scaleInfo, "plannedDate", "план")}
        ${renderSupplyDeliveryMarker(row, scaleInfo, "actualDate", "факт", "is-actual")}
        <button
          class="supply-demand-bar is-${escapeAttribute(row.controlTone || "warning")} ${ui.activeSupplyDemandRowId === row.id ? "is-active" : ""}"
          data-supply-demand-open="${escapeAttribute(row.id)}"
          type="button"
          style="${getSupplyDemandBarStyle(route, scaleInfo)}"
          title="${escapeAttribute(`Двойное нажатие: ${row.title}`)}"
        >
          <strong>${escapeHtml(purchasedLabel)}</strong>
          <small>${escapeHtml(row.controlStatusLabel || "Не закуплено")}</small>
        </button>
        <span class="supply-no-delivery">${row.deliveredQuantity ? `принято ${escapeHtml(formatReportNumber(row.deliveredQuantity))}` : "поставок нет"}</span>
      </div>
    </article>
  `;
}

function renderSupplyRegisterTable(route, rows) {
  const groups = getSupplyBoardGroups(rows);
  return `
    <div class="supply-table-wrap ui-table-wrap" data-layout="table" data-scroll-contract="horizontal-only" data-ui-component="TableWrap">
      <table class="supply-table">
        <thead>
          <tr>
            <th>Позиция</th>
            <th>BOM / источник</th>
            <th>Потребность</th>
            <th>Статус</th>
            <th>ERP / поставщик</th>
            <th>Закуплено</th>
            <th>Поставка</th>
            <th>Комментарий</th>
          </tr>
        </thead>
        <tbody>
          ${groups.map((group) => `
            ${renderSupplyRegisterGroupRow(route, group)}
            ${isSupplyGroupCollapsed(route, group) ? "" : group.rows.map((row) => renderSupplyRegisterRow(row)).join("")}
          `).join("")}
        </tbody>
      </table>
    </div>
  `;
}

function renderSupplyRegisterGroupRow(route, group) {
  const meta = getSupplyBoardGroupMeta(group);
  const collapsed = isSupplyGroupCollapsed(route, group);
  return `
    <tr class="supply-table-group-row ${collapsed ? "is-collapsed" : ""}">
      <th colspan="8">
        <span>
          <button
            class="icon-button supply-group-toggle ui-action-button"
            data-supply-group-toggle="${escapeAttribute(group.id)}"
            data-supply-route-id="${escapeAttribute(route?.id || "")}"
            type="button"
            aria-expanded="${collapsed ? "false" : "true"}"
            title="${collapsed ? "Раскрыть группу" : "Свернуть группу"}"
          >
            ${icon(collapsed ? "chevronRight" : "chevronDown")}
          </button>
          <b>Плата</b>
          <strong>${escapeHtml(group.title)}</strong>
          <small>${escapeHtml(meta)}</small>
        </span>
      </th>
    </tr>
  `;
}

function renderSupplyRegisterRow(row) {
            const control = row.control || normalizeSupplyControlRecord();
  const sourceLabel = getSupplyRegisterSourceLabel(row);
            return `
            <tr>
              <td class="primary-cell">
                <strong>${escapeHtml(row.title)}</strong>
                <small>${escapeHtml([row.typeLabel, row.article ? `PN: ${row.article}` : "", row.package].filter(Boolean).join(" · "))}</small>
              </td>
              <td>${escapeHtml(sourceLabel)}</td>
              <td>${escapeHtml(formatReportNumber(row.requiredQuantity))} ${escapeHtml(row.unit || "шт.")}</td>
              <td>
                <select class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="status" aria-label="Статус закупки">
                  ${SUPPLY_CONTROL_STATUS_OPTIONS.map((option) => `
                    <option value="${escapeAttribute(option.id)}" ${option.id === (row.controlStatus || control.status) ? "selected" : ""}>${escapeHtml(option.label)}</option>
                  `).join("")}
                </select>
              </td>
              <td>
                <div class="supply-control-stack">
                  <input class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="erpDoc" value="${escapeAttribute(control.erpDoc)}" placeholder="счет / заказ 1С" aria-label="ERP документ" />
                  <input class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="supplier" value="${escapeAttribute(control.supplier)}" placeholder="поставщик" aria-label="Поставщик" />
                </div>
              </td>
              <td>
                <label class="supply-quantity-field">
                  <input class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="purchasedQuantity" type="number" min="0" step="1" value="${escapeAttribute(control.purchasedQuantity || "")}" aria-label="Закупленное количество" />
                  <span>/ ${escapeHtml(formatReportNumber(row.requiredQuantity))}</span>
                </label>
              </td>
              <td>
                <div class="supply-control-stack is-delivery">
                  <label><span>план</span><input class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="plannedDate" type="date" value="${escapeAttribute(control.plannedDate)}" aria-label="Плановая поставка" /></label>
                  <label><span>факт</span><input class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="actualDate" type="date" value="${escapeAttribute(control.actualDate)}" aria-label="Фактическая поставка" /></label>
                  <label><span>принято</span><input class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="deliveredQuantity" type="number" min="0" step="1" value="${escapeAttribute(control.deliveredQuantity || "")}" aria-label="Принятое количество" /></label>
                </div>
              </td>
              <td>
                <input class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="comment" value="${escapeAttribute(control.comment)}" placeholder="комментарий снабжения" aria-label="Комментарий снабжения" />
              </td>
            </tr>
          `;
}

function getSupplyRegisterSourceLabel(row = {}) {
  return row.kind === "rek" && Number(row.perBoardQuantity || 0) > 0
    ? `${row.sourceLabel || "-"} · на плату ${formatReportNumber(row.perBoardQuantity)}`
    : row.sourceLabel || "-";
}

function renderSupplyDemandPopover(route, rows = []) {
  if (!ui.activeSupplyDemandRowId) return "";
  const row = rows.find((item) => item.id === ui.activeSupplyDemandRowId);
  if (!row) return "";

  const control = row.control || normalizeSupplyControlRecord();
  const sourceLabel = getSupplyRegisterSourceLabel(row);
  const positionMeta = [row.typeLabel, row.article ? `PN: ${row.article}` : "", row.package].filter(Boolean).join(" · ");
  const demandMeta = row.kind === "rek" && Number(row.perBoardQuantity || 0) > 0
    ? `на плату ${formatReportNumber(row.perBoardQuantity)} ${row.unit || "шт."}`
    : row.kind === "pcb" ? "тираж платы" : "";
  const deliveryMeta = row.deliveredQuantity
    ? `принято ${formatReportNumber(row.deliveredQuantity)} ${row.unit || "шт."}`
    : "план / факт / принято";

  return `
    <div class="supply-demand-popover-layer" role="presentation">
      <button class="supply-demand-popover-backdrop" data-supply-detail-close type="button" aria-label="Закрыть карточку потребности"></button>
      <section class="supply-demand-popover" role="dialog" aria-modal="true" aria-label="Потребность снабжения">
        <header class="supply-demand-popover-head">
          <div>
            <span class="eyebrow">Потребность компонента</span>
            <strong>${escapeHtml(row.title)}</strong>
            <small>${escapeHtml([row.groupTitle, sourceLabel].filter(Boolean).join(" · "))}</small>
          </div>
          <button class="icon-button ui-action-button" data-supply-detail-close type="button" title="Закрыть">${icon("close")}</button>
        </header>

        <div class="supply-detail-grid">
          <article class="supply-detail-cell is-wide">
            <span>Позиция</span>
            <strong>${escapeHtml(row.title)}</strong>
            <small>${escapeHtml(positionMeta || "позиция BOM")}</small>
          </article>

          <article class="supply-detail-cell">
            <span>BOM / источник</span>
            <strong>${escapeHtml(sourceLabel)}</strong>
            <small>${escapeHtml(row.designators || row.groupTitle || "")}</small>
          </article>

          <article class="supply-detail-cell">
            <span>Потребность</span>
            <strong>${escapeHtml(formatReportNumber(row.requiredQuantity))} ${escapeHtml(row.unit || "шт.")}</strong>
            <small>${escapeHtml(demandMeta)}</small>
          </article>

          <label class="supply-detail-cell is-control">
            <span>Статус</span>
            <select class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="status" aria-label="Статус закупки">
              ${SUPPLY_CONTROL_STATUS_OPTIONS.map((option) => `
                <option value="${escapeAttribute(option.id)}" ${option.id === (row.controlStatus || control.status) ? "selected" : ""}>${escapeHtml(option.label)}</option>
              `).join("")}
            </select>
          </label>

          <article class="supply-detail-cell is-wide">
            <span>ERP / поставщик</span>
            <div class="supply-detail-inline-fields">
              <input class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="erpDoc" value="${escapeAttribute(control.erpDoc)}" placeholder="счет / заказ 1С" aria-label="ERP документ" />
              <input class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="supplier" value="${escapeAttribute(control.supplier)}" placeholder="поставщик" aria-label="Поставщик" />
            </div>
          </article>

          <article class="supply-detail-cell">
            <span>Закуплено</span>
            <label class="supply-detail-quantity">
              <input class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="purchasedQuantity" type="number" min="0" step="1" value="${escapeAttribute(control.purchasedQuantity || "")}" aria-label="Закупленное количество" />
              <small>/ ${escapeHtml(formatReportNumber(row.requiredQuantity))}</small>
            </label>
          </article>

          <article class="supply-detail-cell is-wide">
            <span>Поставка</span>
            <div class="supply-detail-delivery-fields">
              <label><small>план</small><input class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="plannedDate" type="date" value="${escapeAttribute(control.plannedDate)}" aria-label="Плановая поставка" /></label>
              <label><small>факт</small><input class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="actualDate" type="date" value="${escapeAttribute(control.actualDate)}" aria-label="Фактическая поставка" /></label>
              <label><small>принято</small><input class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="deliveredQuantity" type="number" min="0" step="1" value="${escapeAttribute(control.deliveredQuantity || "")}" aria-label="Принятое количество" /></label>
            </div>
            <small>${escapeHtml(deliveryMeta)}</small>
          </article>

          <label class="supply-detail-cell is-comment">
            <span>Комментарий</span>
            <textarea class="supply-control-field" data-supply-control-key="${escapeAttribute(row.controlKey)}" data-supply-control-field="comment" rows="3" placeholder="комментарий снабжения" aria-label="Комментарий снабжения">${escapeHtml(control.comment)}</textarea>
          </label>
        </div>
      </section>
    </div>
  `;
}

function bindSupplyEvents() {
  app.querySelectorAll("[data-supply-route-open]").forEach((button) => {
    button.addEventListener("click", () => {
      const routeId = button.dataset.supplyRouteOpen || "";
      if (!routeId) return;
      ui.activeSupplyRouteId = routeId;
      ui.activeRouteId = routeId;
      ui.activeSupplyDemandRowId = "";
      persistUiState();
      render();
    });
  });

  app.querySelectorAll("[data-supply-demand-open]").forEach((button) => {
    const openDemandDetail = (event) => {
      event.preventDefault();
      ui.activeSupplyDemandRowId = button.dataset.supplyDemandOpen || "";
      render();
    };

    button.addEventListener("click", (event) => {
      if (event.detail < 2) return;
      openDemandDetail(event);
    });

    button.addEventListener("dblclick", (event) => {
      openDemandDetail(event);
    });
  });

  app.querySelectorAll("[data-supply-detail-close]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      ui.activeSupplyDemandRowId = "";
      render();
    });
  });

  app.querySelectorAll("[data-supply-group-toggle]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      toggleSupplyGroup(
        button.dataset.supplyRouteId || ui.activeSupplyRouteId || "",
        button.dataset.supplyGroupToggle || "",
      );
    });
  });

  app.querySelectorAll("[data-supply-control-field]").forEach((field) => {
    const commit = () => {
      updateSupplyControlField(
        field.dataset.supplyControlKey || "",
        field.dataset.supplyControlField || "",
        field.value,
      );
    };
    field.addEventListener("change", commit);
    field.addEventListener("keydown", (event) => {
      if (event.key !== "Enter") return;
      event.preventDefault();
      field.blur();
      commit();
    });
  });

  app.querySelector("[data-supply-clear-route]")?.addEventListener("click", (event) => {
    event.preventDefault();
    clearSupplyControlForRoute(event.currentTarget.dataset.supplyClearRoute || "");
  });
}

function getPlanningWorkItemId(type, id = "") {
  return id ? `${type}:${id}` : type;
}

function parsePlanningWorkItemId(value = "") {
  const [type, ...rest] = String(value || "").split(":");
  return { type: type === "batches" ? "schedule" : type || "task", id: rest.join(":") };
}

function getPlanningWorkItemSet(route, tasks, routeSteps) {
  const itemIds = new Set(["supply", "chain", "manualLabor", "schedule", "shifts"]);
  tasks.forEach((task) => itemIds.add(getPlanningWorkItemId("task", task.id)));
  routeSteps.forEach((step) => itemIds.add(getPlanningWorkItemId("step", step.id)));
  return itemIds;
}

function getDefaultPlanningWorkItem(route, tasks, routeSteps) {
  const mainTask = tasks.find((task) => task.isMain) || tasks[0];
  if (mainTask?.id) return getPlanningWorkItemId("task", mainTask.id);
  const firstUnconfiguredSmtStep = routeSteps.find((step) => (
    (routeStepRequiresManualPlanningLine(step, planningState) || isSmtOperationWorkCenter(step.workCenterId, step, planningState))
    && !getRouteStepSelectedPlanningWorkCenterId(step, planningState)
  ));
  if (firstUnconfiguredSmtStep) return getPlanningWorkItemId("step", firstUnconfiguredSmtStep.id);
  const firstSmtStep = routeSteps.find((step) => (
    routeStepRequiresManualPlanningLine(step, planningState)
    || isSmtOperationWorkCenter(step.workCenterId, step, planningState)
  ));
  if (firstSmtStep) return getPlanningWorkItemId("step", firstSmtStep.id);
  return "schedule";
}

function getPlanningActiveWorkItem(route, tasks, routeSteps) {
  const availableItems = getPlanningWorkItemSet(route, tasks, routeSteps);
  const currentItem = String(ui.planningWorkItem || "");
  if (availableItems.has(currentItem)) return currentItem;
  const nextItem = getDefaultPlanningWorkItem(route, tasks, routeSteps);
  ui.planningWorkItem = nextItem;
  return nextItem;
}

function renderPlanningLaborReadinessDetail(route, transferSummary, routeSteps) {
  const planningQuantity = normalizeQuantity(transferSummary?.planningQuantity || getPlanningRouteQuantity(route), 1);
  const readiness = getPlanningRouteLaborReadiness(route, routeSteps);
  const missingRows = readiness.missingSteps.map((step) => {
    const quantity = getRouteStepQuantityForBatch(step, { quantity: planningQuantity });
    const context = getPlanningOrderStepContext(step, {
      isSmtStep: routeStepRequiresManualPlanningLine(step, planningState) || isSmtOperationWorkCenter(step.workCenterId, step, planningState),
      isManualStep: isManualLaborRouteStep(step),
      isMachineStep: isMachineLaborRouteStep(step),
    });
    return `
      <div class="planning-order-register-row is-warning" role="row">
        <span>${escapeHtml(step.operationName || "Операция")}</span>
        <span>${escapeHtml(context.label)}</span>
        <span>${Number(quantity || 0).toLocaleString("ru-RU")} шт.</span>
        <span>нет оценки</span>
      </div>
    `;
  }).join("");

  return `
    <section class="module-panel planning-work-detail-panel" data-ui-component="Panel">
      ${renderUiPanelHead({
        title: "Трудозатраты заказ-наряда",
        meta: "обязательный расчетный слой перед передачей в Гант",
        className: "planning-section-head",
        actions: `<em class="planning-section-tag is-${escapeAttribute(readiness.tone)}">${escapeHtml(readiness.label)}</em>`,
      })}
      ${renderUiPanelBody({ body: `
      <div class="planning-work-detail-grid">
        <article class="planning-work-metric">
          <span>Подтверждено</span>
          <strong>${Number(readiness.confirmed || 0).toLocaleString("ru-RU")}</strong>
          <small>из ${formatPlanningOperationCount(readiness.total || 0)}</small>
        </article>
        <article class="planning-work-metric">
          <span>Не заполнено</span>
          <strong>${Number(readiness.missing || 0).toLocaleString("ru-RU")}</strong>
          <small>блокирует передачу в Гант</small>
        </article>
      </div>
      ${readiness.missing ? `
        <div class="planning-order-register-table" role="table" aria-label="Операции без оценки трудозатрат">
          <div class="planning-order-register-row is-head" role="row">
            <span>Операция</span>
            <span>Контекст</span>
            <span>Кол-во</span>
            <span>Состояние</span>
          </div>
          ${missingRows}
        </div>
      ` : `
        <div class="planning-muted-state">
          ${icon("check")}
          <span>Все операции заказ-наряда имеют подтвержденные трудозатраты.</span>
        </div>
      `}
      ` })}
    </section>
  `;
}

function getPlanningSupplyRows(route, transferSummary = null, routeSteps = null, tasks = null) {
  const planningQuantity = normalizeQuantity(transferSummary?.planningQuantity || getPlanningRouteQuantity(route));
  const specification = getRouteSpecification(route);
  const steps = routeSteps || getRouteStepsForModule(route?.id || "");
  const taskList = tasks || getPlanningTasksForRoute(route, steps);

  if (!specification) {
    const bom = getRouteBomList(route);
    if (!bom) return [];
    const task = taskList.find((item) => item.bomListId === bom.id) || null;
    const stats = task ? getPlanningTaskOperationStats(route, task, steps) : { stepsCount: steps.length, steps };
    const profile = getRouteStepFulfillmentProfile(stats);
    const mode = "produce";
    return [{
      id: `bom:${bom.id}`,
      number: "01",
      level: 0,
      title: bom.resultItem || bom.name || "Плата",
      typeLabel: BOARD_SPEC_TERM,
      sourceLabel: bom.boardCode || BOARD_BOM_TERM,
      nomenclatureItemId: getBomResultNomenclatureItem(bom.id)?.id || "",
      quantity: planningQuantity,
      unit: "шт.",
      mode,
      modeLabel: getFulfillmentLabel(mode),
      modeMeta: getFulfillmentMeta(mode),
      tone: getFulfillmentTone(mode),
      task,
      stats,
      profile,
      status: !stats.stepsCount ? "нужен маршрут" : profile.productionCount ? "операции заданы" : "нет производственной операции",
      statusTone: stats.stepsCount && profile.productionCount ? "ok" : "warning",
      editable: false,
    }];
  }

  return getSpekiStructureTableRows(specification).map(({ item, number, level }) => {
    const mode = getSpecificationItemFulfillmentMode(item);
    const task = taskList.find((candidate) => candidate.sourceItemId === item.id) || null;
    const stats = task ? getPlanningTaskOperationStats(route, task, steps) : { steps: [], stepsCount: 0, smtCount: 0, outputCount: 0 };
    const profile = getRouteStepFulfillmentProfile(stats);
    const requiredQuantity = Math.max(0, Math.round(planningQuantity * Number(item.quantity || 0)));
    const isSchedulable = isSchedulableFulfillmentMode(mode);
    let status = "вне маршрута";
    let statusTone = "neutral";

    if (mode === "not_selected") {
      status = "выберите обеспечение";
      statusTone = "critical";
    } else if (mode === "produce") {
      if (!stats.stepsCount) {
        status = "нужен маршрут";
        statusTone = "warning";
      } else if (!profile.productionCount) {
        status = "нет производственной операции";
        statusTone = "warning";
      } else {
        status = "производственная ветка";
        statusTone = "ok";
      }
    } else if (mode === "from_stock") {
      if (profile.productionCount) {
        status = "уберите производственные операции";
        statusTone = "warning";
      } else if (!profile.warehouseIssueCount) {
        status = "нужна складская выдача";
        statusTone = "warning";
      } else {
        status = "складская выдача";
        statusTone = "ok";
      }
    } else if (!isSchedulable) {
      status = mode === "purchase" ? "закупка вне Ганта" : "внешнее обеспечение";
      statusTone = "neutral";
    }

    return {
      id: item.id,
      number,
      level,
      title: getSpekiStructureItemLabel(item),
      typeLabel: getRouteTaskTypeLabel({ type: item.type, fulfillmentMode: mode }),
      sourceLabel: getPlanningSupplySourceLabel(item),
      nomenclatureItemId: getWarehouseNomenclatureIdForSpecificationItem(item),
      quantity: requiredQuantity,
      unit: item.unit || "шт.",
      mode,
      modeLabel: getFulfillmentLabel(mode),
      modeMeta: getFulfillmentMeta(mode),
      tone: getFulfillmentTone(mode),
      task,
      stats,
      profile,
      status,
      statusTone,
      editable: true,
    };
  });
}

function getWarehouseNomenclatureIdForSpecificationItem(item = {}) {
  if (item.type === "nomenclature" || item.type === "part") return item.nomenclatureId || "";
  if (item.type === "bom") return getBomResultNomenclatureItem(getSpecificationItemBomId(item))?.id || "";
  return "";
}

function getPlanningSupplySourceLabel(item = {}) {
  if (item.type === "bom") {
    const bom = getBomList(getSpecificationItemBomId(item));
    return bom?.boardCode || bom?.name || "плата не выбрана";
  }
  if (item.type === "specification") {
    const specification = getSpecificationById(item.specificationId);
    return specification?.outputItem || specification?.name || "изделие не выбрано";
  }
  if (item.type === "nomenclature" || item.type === "part") {
    const nomenclature = (directoryState.nomenclature || []).find((entry) => entry.id === item.nomenclatureId);
    return [nomenclature?.article, nomenclature?.type].filter(Boolean).join(" · ") || "номенклатура";
  }
  return "внутренний узел";
}

function getPlanningSupplySummary(route, transferSummary = null, routeSteps = null) {
  const rows = getPlanningSupplyRows(route, transferSummary, routeSteps);
  return {
    rows,
    total: rows.length,
    produce: rows.filter((row) => row.mode === "produce").length,
    stock: rows.filter((row) => row.mode === "from_stock").length,
    external: rows.filter((row) => row.mode === "purchase" || row.mode === "external").length,
    blocking: rows.filter((row) => row.statusTone === "critical" || row.statusTone === "warning").length,
  };
}

function getPlanningSupplyBlockingIssues(route, transferSummary = null, routeSteps = null) {
  return getPlanningSupplyRows(route, transferSummary, routeSteps)
    .filter((row) => row.statusTone === "critical" || row.statusTone === "warning")
    .map((row) => {
      if (row.mode === "not_selected") return `${row.number}. ${row.title}: способ обеспечения не выбран.`;
      if (row.mode === "produce" && !row.stats.stepsCount) return `${row.number}. ${row.title}: нужна производственная операция в маршрутной карте.`;
      if (row.mode === "produce" && !row.profile?.productionCount) return `${row.number}. ${row.title}: нужна не складская производственная операция.`;
      if (row.mode === "from_stock" && row.profile?.productionCount) return `${row.number}. ${row.title}: выбрано «Со склада», но в маршруте остались производственные операции.`;
      if (row.mode === "from_stock" && !row.profile?.warehouseIssueCount) return `${row.number}. ${row.title}: нужна складская операция выдачи в маршрутной карте.`;
      return `${row.number}. ${row.title}: ${row.status}.`;
    });
}

function getProductionChainStepFlowLabel(route, steps = [], kind = "input") {
  const orderedSteps = [...(steps || [])].sort((left, right) => Number(left.stepOrder || 0) - Number(right.stepOrder || 0));
  const candidates = kind === "output" ? orderedSteps.reverse() : orderedSteps;
  const step = candidates.find((item) => item?.id);
  if (!step) return "";
  const flow = getRouteStepFlowModel(route, step);
  return kind === "output" ? flow.outputLabel : flow.inputLabel;
}

function getProductionChainOperationRows(route, steps = []) {
  return [...(steps || [])]
    .sort((left, right) => Number(left.stepOrder || 0) - Number(right.stepOrder || 0))
    .map((step) => ({
      id: step.id,
      order: Number(step.stepOrder || 0),
      name: step.operationName || "Операция",
      line: getPlanningStepLineLabel(step),
      tone: getPlanningStepTone(step),
      isSmt: routeStepRequiresManualPlanningLine(step, planningState) || isSmtOperationWorkCenter(step.workCenterId, step, planningState),
      isOutput: isManufacturingOutputReceiptRouteStep(step),
      missingLine: routeStepRequiresManualPlanningLine(step, planningState) && !getRouteStepSelectedPlanningWorkCenterId(step, planningState),
    }));
}

function getProductionChainSourceInputLabel(row, route) {
  const taskInputLabel = getRouteTaskInputObjectLabel(route, row.task, "");
  if (row.mode === "produce" && taskInputLabel) return taskInputLabel;
  const fromStep = getProductionChainStepFlowLabel(route, row.stats?.steps || [], "input");
  if (fromStep) return fromStep;
  if (row.mode === "from_stock") return `Остаток склада: ${row.title}`;
  if (row.mode === "purchase") return `Закупка: ${row.title}`;
  if (row.mode === "external") return `Внешнее обеспечение: ${row.title}`;
  if (row.mode === "not_selected") return "Способ обеспечения не выбран";
  return `Материалы: ${row.title}`;
}

function getProductionChainSourceOutputLabel(row, route) {
  const producedLabel = getRouteTaskProducedObjectLabel(route, row.task, getBomList(row.task?.bomListId || ""), getRoutePlanningContext(route));
  if (row.mode === "produce" && producedLabel) return producedLabel;
  const fromStep = getProductionChainStepFlowLabel(route, row.stats?.steps || [], "output");
  if (fromStep) return fromStep;
  if (row.mode === "from_stock") return `Выдано в производство: ${row.title}`;
  if (row.mode === "purchase") return `Поставка: ${row.title}`;
  if (row.mode === "external") return `Внешний результат: ${row.title}`;
  if (row.mode === "not_selected") return "Выход не определен";
  return row.title || "Результат составной части";
}

function buildPlanningProductionChain(route, transferSummary = null, tasks = null, routeSteps = null) {
  const steps = routeSteps || getRouteStepsForModule(route?.id || "");
  const taskList = tasks || getPlanningTasksForRoute(route, steps);
  const rows = getPlanningSupplyRows(route, transferSummary, steps, taskList);
  const planningQuantity = normalizeQuantity(transferSummary?.planningQuantity || getPlanningRouteQuantity(route));
  const production = getRoutePlanningContext(route);
  const supplyIssues = getPlanningSupplyBlockingIssues(route, transferSummary, steps);
  const sourceNodes = rows.map((row) => {
    const operations = getProductionChainOperationRows(route, row.stats?.steps || []);
    return {
      id: row.id,
      kind: "source",
      number: row.number,
      title: row.title || "Составная часть",
      typeLabel: row.typeLabel || "часть",
      sourceLabel: row.sourceLabel || "",
      mode: row.mode,
      modeLabel: row.modeLabel,
      quantity: row.quantity,
      unit: row.unit || "шт.",
      status: row.status,
      tone: row.statusTone || "neutral",
      inputLabel: getProductionChainSourceInputLabel(row, route),
      outputLabel: getProductionChainSourceOutputLabel(row, route),
      operations,
      smtCount: row.stats?.smtCount || 0,
      outputCount: row.stats?.outputCount || 0,
      missingLineCount: operations.filter((item) => item.missingLine).length,
      isSchedulable: isSchedulableFulfillmentMode(row.mode),
    };
  });

  const mainTask = taskList.find((task) => task.isMain) || null;
  const mainSteps = getRouteStepsForTask(steps, MAIN_ROUTE_TASK_ID);
  const mainStats = mainTask
    ? getPlanningTaskOperationStats(route, mainTask, steps)
    : {
      steps: mainSteps,
      stepsCount: mainSteps.length,
      smtCount: mainSteps.filter((step) => isSmtOperationWorkCenter(step.workCenterId, step, planningState) || routeStepRequiresManualPlanningLine(step, planningState)).length,
      outputCount: mainSteps.filter((step) => isManufacturingOutputReceiptRouteStep(step)).length,
    };
  const shouldShowFinalNode = sourceNodes.length > 1 || mainStats.stepsCount > 0;
  const finalInputNodes = sourceNodes.filter((node) => node.mode !== "not_selected");
  const finalOutputLabel = getProjectDisplayOutput(production)
    || getProjectDisplayName(production)
    || route?.name
    || getProductionChainStepFlowLabel(route, mainStats.steps || [], "output")
    || "Готовое изделие";
  const finalNode = shouldShowFinalNode ? {
    id: "final",
    kind: "final",
    number: "Финиш",
    title: mainTask?.title || "Финальные операции маршрута",
    typeLabel: "маршрут",
    sourceLabel: getProjectDisplayName(production) || route?.name || "",
    mode: "produce",
    modeLabel: "Произвести",
    quantity: planningQuantity,
    unit: "шт.",
    status: mainStats.stepsCount ? "операции заданы" : "нужна финальная операция",
    tone: mainStats.stepsCount ? "ok" : "warning",
    inputLabel: getProductionChainStepFlowLabel(route, mainStats.steps || [], "input")
      || joinRouteStepFlowLabels(finalInputNodes.map((node) => node.outputLabel), "Полуфабрикаты состава изделия"),
    outputLabel: finalOutputLabel,
    operations: getProductionChainOperationRows(route, mainStats.steps || []),
    smtCount: mainStats.smtCount || 0,
    outputCount: mainStats.outputCount || 0,
    missingLineCount: 0,
    isSchedulable: true,
  } : null;

  const links = finalNode
    ? sourceNodes
      .filter((node) => node.mode !== "not_selected")
      .map((node) => ({
        id: `${node.id}->${finalNode.id}`,
        from: node.title,
        to: finalNode.title,
        label: node.mode === "from_stock" ? "через склад" : node.isSchedulable ? "в производство" : "вне Ганта",
        tone: node.isSchedulable ? "ok" : "neutral",
      }))
    : [];
  const lineIssues = steps
    .filter((step) => routeStepRequiresManualPlanningLine(step, planningState) && !getRouteStepSelectedPlanningWorkCenterId(step, planningState))
    .map((step) => `${step.operationName || "SMT-операция"}: выберите конкретный SMT-участок.`);
  const finalIssues = sourceNodes.length > 1 && !mainStats.stepsCount
    ? ["Для нескольких составных частей нужна финальная операция сборки или приемки в маршрутной карте."]
    : [];
  const issues = [...new Set([...supplyIssues, ...lineIssues, ...finalIssues])];

  return {
    nodes: sourceNodes,
    finalNode,
    allNodes: finalNode ? [...sourceNodes, finalNode] : sourceNodes,
    links,
    issues,
    summary: {
      branches: sourceNodes.length,
      links: links.length,
      smt: steps.filter((step) => routeStepRequiresManualPlanningLine(step, planningState) || isSmtOperationWorkCenter(step.workCenterId, step, planningState)).length,
      issues: issues.length,
    },
  };
}

function renderPlanningProductionChainNode(node) {
  const visibleOperations = node.operations.slice(0, 4);
  const hiddenCount = Math.max(0, node.operations.length - visibleOperations.length);
  return `
    <article class="planning-chain-node is-${escapeAttribute(node.tone)} ${node.kind === "final" ? "is-final" : ""}">
      <header>
        <span>${escapeHtml(node.number)} · ${escapeHtml(node.typeLabel)}</span>
        <strong>${escapeHtml(node.title)}</strong>
        <em>${escapeHtml(node.status)}</em>
      </header>
      <div class="planning-chain-node-flow">
        <span>
          <b>Вход</b>
          <strong>${escapeHtml(node.inputLabel)}</strong>
        </span>
        <i aria-hidden="true">&rarr;</i>
        <span>
          <b>Выход</b>
          <strong>${escapeHtml(node.outputLabel)}</strong>
        </span>
      </div>
      <div class="planning-chain-node-facts">
        <span>${escapeHtml(node.modeLabel || "обеспечение")}</span>
        <span>${Number(node.quantity || 0).toLocaleString("ru-RU")} ${escapeHtml(node.unit || "шт.")}</span>
        <span>${node.operations.length ? `${node.operations.length} оп.` : "нет операций"}</span>
        ${node.smtCount ? `<span>SMT ${node.smtCount}</span>` : ""}
      </div>
      ${visibleOperations.length ? `
        <div class="planning-chain-steps">
          ${visibleOperations.map((operation) => `
            <button class="is-${escapeAttribute(operation.tone)}" data-planning-work-item="${escapeAttribute(getPlanningWorkItemId("step", operation.id))}" type="button">
              <b>${operation.order}</b>
              <span>${escapeHtml(operation.name)}</span>
              <em>${escapeHtml(operation.line)}</em>
            </button>
          `).join("")}
          ${hiddenCount ? `<small>+${hiddenCount} оп.</small>` : ""}
        </div>
      ` : ""}
    </article>
  `;
}

function getPlanningFlowReadinessSummary(route = null) {
  const production = getRoutePlanningContext(route);
  const batches = route && production ? getRoutePlanningBatches(route, production) : [];
  const settings = getRouteFlowLaunchSettings(route, batches[0] || null);
  const details = batches.map((batch) => {
    const readiness = getMainRouteDependencyReadiness(route.id, production.id, batch.id);
    const branchDetails = readiness?.branchDetails || getRoutePlanningOrderWipBranchDetails(route.id, production.id, batch.id, ui.now);
    return {
      batch,
      readiness,
      branchDetails,
      availableKitsNow: readiness?.availableKitsNow || getRoutePlanningOrderAvailableKitCount(route.id, production.id, batch.id, ui.now),
    };
  });
  const readyDates = details
    .map((detail) => detail.readiness?.readyAt)
    .filter(Boolean)
    .sort((left, right) => toDate(left) - toDate(right));
  const branchCount = details[0]?.readiness?.sourceSlots?.length || getRouteConcreteTasksForPlanning(route).length;

  return {
    settings,
    batches: details,
    branchDetails: details[0]?.branchDetails || [],
    branchCount,
    availableKitsNow: details.reduce((sum, detail) => sum + normalizeQuantity(detail.availableKitsNow), 0),
    nextReadyAt: readyDates[0] || null,
  };
}

function renderPlanningWipBranchCards(summary) {
  const branches = summary.branchDetails || [];
  if (!branches.length) {
    return `
      <div class="planning-flow-wip-empty">
        ${icon("info")}
        <span>WIP появится после передачи входных веток в Гант.</span>
      </div>
    `;
  }

  return `
    <div class="planning-flow-wip-list" aria-label="WIP по входным веткам сборки">
      ${branches.map((branch) => {
        const produced = Number(branch.producedQuantity || 0);
        const available = Number(branch.availableQuantity || 0);
        const required = Math.max(1, Number(branch.requiredQuantity || summary.settings.transferBatchQuantity || 1));
        const progress = Math.max(0, Math.min(100, Math.round((produced / required) * 100)));
        const tone = available >= required ? "ok" : progress > 0 ? "warning" : "neutral";
        return `
          <article class="planning-flow-wip-card is-${escapeAttribute(tone)}">
            <header>
              <span>${escapeHtml(branch.outputLabel || "Выход ветки")}</span>
              <strong>${available.toLocaleString("ru-RU")} свободно</strong>
            </header>
            <div class="planning-flow-wip-bar" style="--wip-progress:${progress}%;">
              <i></i>
            </div>
            <footer>
              <span>${produced.toLocaleString("ru-RU")} выпущено · передача ${required.toLocaleString("ru-RU")}</span>
              <em>${escapeHtml([branch.transferLabel, branch.readyAt ? formatDateTimeShort(branch.readyAt) : ""].filter(Boolean).join(" · ") || "нет даты")}</em>
            </footer>
          </article>
        `;
      }).join("")}
    </div>
  `;
}

function renderPlanningFlowRulePanel(route, chain) {
  const summary = getPlanningFlowReadinessSummary(route);
  const { settings } = summary;
  const canUseTransfer = summary.branchCount > 1 && chain.finalNode;
  const ruleHint = canUseTransfer
    ? "Ручного режима запуска больше нет: передача появляется по окончанию операции или по закрытию смены."
    : "Правило доступно для маршрута с несколькими входными ветками и общей сборкой.";

  return `
    <div class="planning-flow-rule ${canUseTransfer ? "" : "is-muted"}">
      <div class="planning-flow-rule-head">
        <div>
          <strong>Системная передача</strong>
          <span>${canUseTransfer
            ? "когда следующий участок может брать готовый объем из входных веток"
            : "передаточный объем доступен, когда есть несколько входных веток и общая сборка"}</span>
        </div>
        <em class="planning-section-tag is-calculated">
          ${escapeHtml(settings.modeLabel)}
        </em>
      </div>
      <div class="planning-flow-rule-body">
        <div class="planning-flow-system-events" aria-label="События передачи">
          <article>
            <strong>Конец смены</strong>
            <span>Передается фактически выполненный объем смены.</span>
          </article>
          <article>
            <strong>Окончание операции</strong>
            <span>Если операция закрылась раньше, следующий участок получает объем сразу.</span>
          </article>
        </div>
        <div class="planning-flow-live">
          <article>
            <span>Можно собрать сейчас</span>
            <strong>${summary.availableKitsNow.toLocaleString("ru-RU")} компл.</strong>
            <small>минимум по входным веткам</small>
          </article>
          <article>
            <span>Ближайший старт</span>
            <strong>${summary.nextReadyAt ? escapeHtml(formatDateTimeShort(summary.nextReadyAt)) : "после Ганта"}</strong>
            <small>по ближайшему событию передачи</small>
          </article>
        </div>
        ${renderPlanningWipBranchCards(summary)}
      </div>
      <p class="planning-flow-rule-note">${escapeHtml(ruleHint)}</p>
    </div>
  `;
}

function getPlanningTaskOperationStats(route, task, steps = null) {
  const routeSteps = steps || getRouteStepsForModule(route?.id || "");
  const taskSteps = getRouteStepsForPlanningTask(route, task, routeSteps);
  const smtSteps = taskSteps.filter((step) => (
    isSmtOperationWorkCenter(step.workCenterId, step, planningState)
    || routeStepRequiresManualPlanningLine(step, planningState)
  ));
  const outputSteps = taskSteps.filter((step) => isManufacturingOutputReceiptRouteStep(step));
  return {
    steps: taskSteps,
    smtSteps,
    outputSteps,
    stepsCount: taskSteps.length,
    smtCount: smtSteps.length,
    outputCount: outputSteps.length,
  };
}

function isWarehouseIssueRouteStep(step = {}) {
  return isWarehouseWorkCenterId(step.workCenterId) && !isManufacturingOutputReceiptRouteStep(step);
}

function getRouteStepFulfillmentProfile(stats = {}) {
  const steps = Array.isArray(stats.steps) ? stats.steps : [];
  const warehouseIssueSteps = steps.filter((step) => isWarehouseIssueRouteStep(step));
  const outputReceiptSteps = steps.filter((step) => isManufacturingOutputReceiptRouteStep(step));
  const productionSteps = steps.filter((step) => !isWarehouseWorkCenterId(step.workCenterId));
  return {
    warehouseIssueCount: warehouseIssueSteps.length,
    outputReceiptCount: outputReceiptSteps.length,
    productionCount: productionSteps.length,
  };
}

function getPlanningTaskBomLabel(task) {
  const fulfillmentMode = normalizeStructureFulfillmentMode(task?.fulfillmentMode || "", task?.isMain ? "produce" : "not_selected");
  if (task && !task.isMain) {
    const prefix = getFulfillmentLabel(fulfillmentMode);
    const bom = getBomList(task?.bomListId || "");
    if (bom) return `${prefix} · ${bom.resultItem || bom.name || "BOM"}`;
    if (task?.type === "bom") return `${prefix} · BOM не привязан`;
    if (task?.type === "assembly") return `${prefix} · Сборочная ветка`;
    if (task?.type === "specification") return `${prefix} · Вложенная спецификация`;
    if (task?.type === "nomenclature" || task?.type === "part") return `${prefix} · Производимая позиция`;
    return `${prefix} · Производимый объект`;
  }
  const bom = getBomList(task?.bomListId || "");
  if (bom) return bom.resultItem || bom.name || "BOM";
  if (task?.type === "bom") return "BOM не привязан";
  if (task?.isMain) return "маршрут";
  if (task?.type === "assembly") return "Сборочная ветка";
  if (task?.type === "specification") return "Вложенная спецификация";
  if (task?.type === "nomenclature" || task?.type === "part") return "Производимая позиция";
  return "Производимый объект";
}

function getPlanningTaskReadiness(task, stats) {
  if (task?.isOrphan) return { label: "проверьте связь", tone: "critical" };
  const fulfillmentMode = normalizeStructureFulfillmentMode(task?.fulfillmentMode || "", task?.isMain ? "produce" : "not_selected");
  if (!task?.isMain && fulfillmentMode === "not_selected") return { label: "обеспечение не выбрано", tone: "critical" };
  if (!task?.isMain && !isSchedulableFulfillmentMode(fulfillmentMode)) return { label: "вне маршрута", tone: "neutral" };
  if (!stats.stepsCount) return { label: "нет операций", tone: "warning" };
  const fulfillmentProfile = getRouteStepFulfillmentProfile(stats);
  if (!task?.isMain && fulfillmentMode === "produce" && !fulfillmentProfile.productionCount) {
    return { label: "нет производственной операции", tone: "warning" };
  }
  if (fulfillmentMode === "from_stock") {
    if (fulfillmentProfile.productionCount) return { label: "лишние производственные операции", tone: "warning" };
    if (!fulfillmentProfile.warehouseIssueCount) return { label: "нужна складская выдача", tone: "warning" };
  }
  if (stats.smtSteps.some((step) => routeStepRequiresManualPlanningLine(step, planningState) && !getRouteStepSelectedPlanningWorkCenterId(step, planningState))) {
    return { label: "выберите SMT-участок", tone: "warning" };
  }
  if (task?.type === "bom" && !task.bomListId) return { label: "BOM не привязан", tone: "warning" };
  return { label: "готово к плану", tone: "ok" };
}

function getPlanningStepTone(step) {
  if (!getOperationMapItem(step.operationId)) return "warning";
  if (routeStepRequiresManualPlanningLine(step, planningState) && !getRouteStepSelectedPlanningWorkCenterId(step, planningState)) return "warning";
  if (isManufacturingOutputReceiptRouteStep(step)) return "output";
  if (routeStepRequiresManualPlanningLine(step, planningState) || isSmtOperationWorkCenter(step.workCenterId, step, planningState)) return "smt";
  return "regular";
}

function getPlanningStepLineLabel(step) {
  const selectedLineId = getRouteStepSelectedPlanningWorkCenterId(step, planningState);
  if (selectedLineId) return getWorkCenter(selectedLineId)?.name || selectedLineId;
  if (routeStepRequiresManualPlanningLine(step, planningState)) return "SMT-участок не выбран";
  return getWorkCenter(step.workCenterId)?.name || step.workCenterId || "Отдел не выбран";
}

