function getPlanningTableSlotRows() {
  const stepById = new Map((planningState.routeSteps || []).map((step) => [step.id, step]));
  const warningsContext = getSlotWarnings(planningState);
  const slotWarningMap = warningsContext.slotWarningMap || {};

  return (planningState.slots || [])
    .map((slot) => {
      const step = stepById.get(slot.routeStepId) || null;
      const route = getSlotRoute(slot);
      const routeId = route?.id || getSlotRouteId(slot, planningState);
      const task = route && step ? getRouteStepPlanningTask(route, step) : null;
      const status = getGanttSlotStatusView(slot);
      const workCenterId = mapLegacyWorkCenterId(getSlotGanttWorkCenterId(slot) || slot.workCenterId || step?.workCenterId || "");
      const workCenter = getWorkCenter(workCenterId) || getWorkCenter(slot.workCenterId) || null;
      const resource = getGanttResourceForSlot(slot);
      const plannedStart = toDate(slot.plannedStart);
      const plannedEnd = toDate(slot.plannedEnd);
      const warningCount = (slotWarningMap[slot.id] || []).length;
      const quantity = normalizeQuantity(slot.quantity || route?.planningQuantity || 1, 1);

      return {
        id: slot.id,
        slot,
        step,
        route,
        task,
        status,
        warningCount,
        plannedStart,
        plannedEnd,
        quantity,
        unit: slot.unit || task?.unit || "шт.",
        routeLabel: getPlanningOrderObjectLabel(route) || route?.name || "Заказ-наряд",
        routeName: route?.name || routeId || "Маршрутная карта не найдена",
        taskLabel: task ? [task.number, task.title].filter(Boolean).join(" · ") : step?.specTaskName || "Общий маршрут",
        operationName: slot.operationName || step?.operationName || "Операция",
        workCenterId,
        workCenterLabel: workCenter?.name || workCenterId || "Участок не задан",
        resourceLabel: resource?.name || workCenter?.name || "Ресурс не назначен",
        workingMs: getSlotWorkingDurationMs(slot),
        calendarMs: getSlotCalendarDurationMs(slot),
      };
    })
    .sort((left, right) => (
      left.plannedStart - right.plannedStart
      || left.workCenterLabel.localeCompare(right.workCenterLabel, "ru")
      || left.operationName.localeCompare(right.operationName, "ru")
    ));
}

function getPlanningTableDayBuckets(rows = []) {
  const firstSlotStart = rows.length
    ? rows.reduce((earliest, row) => new Date(Math.min(earliest.getTime(), row.plannedStart.getTime())), rows[0].plannedStart)
    : null;
  const currentWindowStart = startOfDay(fromDateInput(ui.windowStart));
  const hasSlotInCurrentWindow = rows.some((row) => row.plannedStart < addMs(currentWindowStart, 14 * DAY_MS) && row.plannedEnd > currentWindowStart);
  const start = startOfDay(hasSlotInCurrentWindow ? currentWindowStart : firstSlotStart || currentWindowStart);
  return Array.from({ length: 14 }, (_, index) => {
    const date = addMs(start, index * DAY_MS);
    return {
      id: toDateInput(date),
      date,
      end: addMs(date, DAY_MS),
      label: formatShortDate(date),
      weekday: date.toLocaleDateString("ru-RU", { weekday: "short" }),
      isWeekend: date.getDay() === 0 || date.getDay() === 6,
    };
  });
}

function getPlanningTableViewModel() {
  const rows = getPlanningTableSlotRows();
  const days = getPlanningTableDayBuckets(rows);
  const resourceGroups = getPlanningTableResourceGroups(rows);
  const statusGroups = getPlanningTableStatusGroups(rows);
  const totalWorkingMs = rows.reduce((sum, row) => sum + row.workingMs, 0);
  const warningCount = rows.reduce((sum, row) => sum + row.warningCount, 0);

  return {
    rows,
    days,
    resourceGroups,
    issueRows: getPlanningTableIssueRows(rows, days),
    dailyLoads: getPlanningTableDailyLoads(rows, days),
    queueRows: getPlanningTableQueueRows(rows),
    orderGroups: getPlanningTableOrderGroups(rows),
    bufferRows: getPlanningTableBufferRows(rows),
    planFactRows: getPlanningTablePlanFactRows(rows),
    densityDays: getPlanningTableDensityDays(rows, days),
    dependencyRows: getPlanningTableDependencyRows(rows),
    statusGroups,
    totalWorkingMs,
    warningCount,
  };
}

function getPlanningTableResourceGroups(rows = []) {
  const resourceMap = new Map();

  rows.forEach((row) => {
    if (!resourceMap.has(row.workCenterId || row.workCenterLabel)) {
      resourceMap.set(row.workCenterId || row.workCenterLabel, {
        id: row.workCenterId || row.workCenterLabel,
        label: row.workCenterLabel,
        resourceLabel: row.resourceLabel,
        rows: [],
        totalWorkingMs: 0,
      });
    }
    const group = resourceMap.get(row.workCenterId || row.workCenterLabel);
    group.rows.push(row);
    group.totalWorkingMs += row.workingMs;
  });

  return [...resourceMap.values()]
    .sort((left, right) => (
      right.totalWorkingMs - left.totalWorkingMs
      || left.label.localeCompare(right.label, "ru")
    ));
}

function getPlanningTableStatusGroups(rows = []) {
  const statusMap = new Map();
  rows.forEach((row) => {
    statusMap.set(row.status.value, {
      status: row.status,
      count: (statusMap.get(row.status.value)?.count || 0) + 1,
    });
  });
  return [...statusMap.values()].sort((left, right) => right.count - left.count);
}

function getPlanningTableModelSubset(model, rows, options = {}) {
  const days = Array.isArray(options.days) && options.days.length ? options.days : model.days;
  return {
    ...model,
    rows,
    days,
    resourceGroups: getPlanningTableResourceGroups(rows),
    statusGroups: getPlanningTableStatusGroups(rows),
    totalWorkingMs: rows.reduce((sum, row) => sum + row.workingMs, 0),
    warningCount: rows.reduce((sum, row) => sum + row.warningCount, 0),
  };
}

function planningTableSlotOverlapsDay(row, day) {
  return row.plannedStart < day.end && row.plannedEnd > day.date;
}

