function renderModulePreviewEmpty({ iconName = "info", title, text, action = "" }) {
  return renderUiEmptyState({ iconName, title, text, action });
}

function renderNomenclaturePage() {
  const activePane = getActiveNomenclaturePane();
  if (activePane === "boards") return renderBomListsPage({ embeddedInNomenclature: true });

  const allItems = directoryState.nomenclature || [];
  const items = getFilteredNomenclatureItems(allItems);
  const typeOptions = getNomenclatureTypeOptions(allItems);
  const typeCounts = getNomenclatureTypeCounts(allItems);
  const activeFilter = getNomenclatureTypeFilterValue(allItems);
  const activeItem = getActiveNomenclatureItem();
  const isNewItem = ui.activeNomenclatureId === "__new__";
  const hasPreviewObject = isNewItem || Boolean(activeItem);
  const rawItemType = normalizeNomenclatureType(activeItem?.type || NOMENCLATURE_REA_COMPONENT_TYPE);
  const itemType = typeOptions.some((type) => type.value === rawItemType)
    ? rawItemType
    : typeOptions[0]?.value || rawItemType;
  const item = activeItem || {
    id: "",
    name: "",
    article: "",
    type: NOMENCLATURE_REA_COMPONENT_TYPE,
    package: "",
    unit: "шт.",
    manufacturer: "",
    description: "",
    status: "Активен",
  };

  return renderUiModulePage({
    ariaLabel: "Номенклатура",
    className: "nomenclature-page",
    sidebar: renderUiModuleSidebar({
      eyebrow: "Материалы и компоненты",
      title: "Номенклатура",
      actions: renderUiActionButton({
        label: "Новая позиция",
        iconName: "plus",
        tone: "primary",
        attributes: "data-nomenclature-create type=\"button\"",
      }),
      body: `
        ${renderNomenclatureSectionFilter({ activePane, activeFilter, typeOptions, typeCounts, allCount: allItems.length })}
      `,
    }),
    header: renderUiModuleHeader({
      eyebrow: "Список компонентов",
      title: hasPreviewObject ? (isNewItem ? "Новая позиция номенклатуры" : item.name || "Позиция без названия") : "Объект не выбран",
      description: hasPreviewObject ? "Номенклатура разделяется по типам: РЭА для BOM, платы, механика, кабели, расходники и другие производственные позиции." : "Выберите позицию в таблице или создайте новую, чтобы открыть карточку редактирования.",
    }),
    contentClassName: "nomenclature-module-content",
    content: `
      ${hasPreviewObject ? renderUiPanel({
        title: "Предпросмотр позиции",
        meta: isNewItem ? "создание новой позиции" : "редактирование номенклатуры",
        className: "nomenclature-editor-panel",
        body: renderUiPanelBody({
          body: `
            <form id="nomenclatureForm" class="module-form">
              <input type="hidden" name="itemId" value="${escapeAttribute(item.id)}" />
              <input type="hidden" name="isNew" value="${isNewItem ? "yes" : "no"}" />
              <input type="hidden" name="type" value="${escapeAttribute(itemType)}" data-nomenclature-type-hidden />
              <label class="form-field full ui-form-field"><span>Наименование</span><input name="name" value="${escapeAttribute(item.name)}" placeholder="Например: Резистор 10 кОм 0603 1%" /></label>
              <label class="form-field ui-form-field"><span>Артикул</span><input name="article" value="${escapeAttribute(item.article)}" placeholder="PN / MPN / внутренний код" /></label>
              <label class="form-field ui-form-field"><span>Раздел</span>${renderDenseInlineSelect("type", itemType, typeOptions, { type: "nomenclatureType" })}</label>
              <label class="form-field ui-form-field"><span>Новый раздел</span><input name="customType" value="" placeholder="если нужен отдельный тип" /></label>
              <label class="form-field ui-form-field"><span>Корпус / размер</span><input name="package" value="${escapeAttribute(item.package)}" placeholder="0603, QFN-32, PCB" /></label>
              <label class="form-field ui-form-field"><span>Ед. изм.</span><input name="unit" value="${escapeAttribute(item.unit)}" placeholder="шт." /></label>
              <label class="form-field ui-form-field"><span>Производитель</span><input name="manufacturer" value="${escapeAttribute(item.manufacturer)}" placeholder="Yageo, Murata, TI..." /></label>
              <label class="form-field ui-form-field"><span>Статус</span><input name="status" value="${escapeAttribute(item.status)}" placeholder="Активен" /></label>
              <label class="form-field full ui-form-field"><span>Описание</span><textarea name="description" rows="3" placeholder="Параметры, допуски, замены, комментарии">${escapeHtml(item.description)}</textarea></label>
              <div class="module-form-actions full">
                ${isNewItem ? "" : `<button class="secondary-button danger ui-action-button" data-nomenclature-delete="${escapeAttribute(item.id)}" type="button">${icon("trash")}<span>Удалить</span></button>`}
                <button class="primary-button ui-action-button" type="submit">${icon("save")}<span>${isNewItem ? "Создать позицию" : "Сохранить позицию"}</span></button>
              </div>
            </form>
          `,
        }),
      }) : ""}

      ${renderUiPanel({
        title: `${hasPreviewObject ? "02" : "01"} · Список номенклатуры`,
        meta: items.length ? `${items.length} из ${allItems.length} позиций` : "список пуст",
        className: "nomenclature-list-panel",
        body: renderUiPanelBody({ body: renderNomenclatureTable(items, activeItem) }),
      })}
    `,
  });
}

function renderNomenclatureTable(items, activeItem) {
  if (!items.length) {
    return `
      <div class="bom-import-empty">
        ${icon("book")}
        <strong>Позиций пока нет</strong>
        <span>Нажмите «Новая позиция», заполните карточку и сохраните номенклатуру.</span>
      </div>
    `;
  }

  return `
    <div class="directory-table-wrap nomenclature-table-wrap ui-table-wrap" data-layout="table" data-scroll-contract="horizontal-only" data-ui-component="TableWrap">
      <table class="directory-table nomenclature-table">
        <thead>
          <tr>
            <th>Наименование</th>
            <th>Артикул</th>
            <th>Раздел</th>
            <th>Корпус</th>
            <th>Ед.</th>
            <th>Производитель</th>
            <th>Статус</th>
            <th class="actions-cell">Действия</th>
          </tr>
        </thead>
        <tbody>
          ${items.map((entry) => `
            <tr class="${entry.id === activeItem?.id ? "is-selected" : ""}" data-nomenclature-row-open="${escapeAttribute(entry.id)}">
              <td class="primary-cell" title="${escapeAttribute(entry.name || "Позиция без названия")}">${escapeHtml(entry.name || "Позиция без названия")}</td>
              <td title="${escapeAttribute(entry.article || "-")}">${escapeHtml(entry.article || "-")}</td>
              <td title="${escapeAttribute(entry.type || "-")}">${escapeHtml(entry.type || "-")}</td>
              <td title="${escapeAttribute(entry.package || "-")}">${escapeHtml(entry.package || "-")}</td>
              <td>${escapeHtml(entry.unit || "шт.")}</td>
              <td title="${escapeAttribute(entry.manufacturer || "-")}">${escapeHtml(entry.manufacturer || "-")}</td>
              <td>${escapeHtml(entry.status || "Активен")}</td>
              <td class="actions-cell">
                <button class="table-icon-button danger-soft ui-action-button" data-nomenclature-row-delete="${escapeAttribute(entry.id)}" type="button" title="Удалить позицию">${icon("trash")}</button>
              </td>
            </tr>
          `).join("")}
        </tbody>
      </table>
    </div>
  `;
}

function renderBomListsPage(options = {}) {
  const embeddedInNomenclature = Boolean(options.embeddedInNomenclature);
  const activeBom = getActiveBomForModule();
  const isNewBom = ui.activeBomId === "__new__";
  const hasPreviewBom = isNewBom || Boolean(activeBom);
  const bom = activeBom || {
    id: "",
    name: "",
    projectId: "",
    boardCode: "",
    resultItem: "",
    status: "Черновик",
    ...Object.fromEntries(BOM_COMPONENT_FIELDS.map((field) => [field.key, 0])),
  };
  const componentCounts = hasPreviewBom ? getBomComponentCounts(bom) : {};
  const componentTotal = Object.values(componentCounts).reduce((sum, count) => sum + Number(count || 0), 0);
  const importRows = hasPreviewBom ? getBomImportRows(bom) : [];
  const importHeaders = hasPreviewBom ? getBomImportHeaders(bom) : [];

  return renderUiModulePage({
    ariaLabel: embeddedInNomenclature ? "Номенклатура · Платы" : BOARD_SPEC_LIST_TERM,
    className: `bom-lists-page ${embeddedInNomenclature ? "nomenclature-page is-boards-pane" : ""}`,
    sidebar: renderUiModuleSidebar({
      eyebrow: embeddedInNomenclature ? "Материалы и компоненты" : "Печатные платы",
      title: embeddedInNomenclature ? "Номенклатура" : BOARD_SPEC_LIST_TERM,
      actions: renderUiActionButton({
        label: "Новая плата",
        iconName: "plus",
        tone: "primary",
        attributes: "data-bom-create type=\"button\"",
      }),
      body: `
        ${embeddedInNomenclature ? renderNomenclatureSectionFilter({
          activePane: "boards",
          activeFilter: getNomenclatureTypeFilterValue(directoryState.nomenclature || []),
          typeOptions: getNomenclatureTypeOptions(directoryState.nomenclature || []),
          typeCounts: getNomenclatureTypeCounts(directoryState.nomenclature || []),
          allCount: (directoryState.nomenclature || []).length,
        }) : ""}
        <div class="ui-sidebar-list">
          <div class="ui-sidebar-label">${BOARD_SPEC_LIST_TERM}</div>
          ${isNewBom ? renderUiSidebarItem({
            title: "Новая плата",
            meta: "компонентный состав / BOM",
            badge: "new",
            active: true,
          }) : ""}
          ${(directoryState.bomLists || []).map((item) => {
            const hasImportRows = getBomImportRows(item).length > 0;
            const total = hasImportRows ? Object.values(getBomComponentCounts(item)).reduce((sum, count) => sum + Number(count || 0), 0) : 0;
            return renderUiSidebarItem({
              title: item.name,
              meta: `${item.boardCode || "децимальный номер не задан"} · ${item.resultItem || "результат платы не задан"}${hasImportRows ? "" : " · Черновик"}`,
              badge: String(total),
              active: item.id === activeBom?.id,
              attributes: `data-bom-open="${escapeAttribute(item.id)}" type="button"`,
            });
          }).join("")}
        </div>
      `,
    }),
    header: renderUiModuleHeader({
      eyebrow: BOARD_BOM_TERM,
      title: hasPreviewBom ? (isNewBom ? "Новая плата" : bom.name || "Плата без названия") : "Плата не выбрана",
      description: hasPreviewBom ? "Плата хранит код, результат производства и BOM с компонентным составом. В изделии и маршруте она используется как существующий объект." : "Выберите плату в левом перечне или создайте новую, чтобы открыть карточку и таблицу компонентов.",
    }),
    contentClassName: "bom-module-content",
    content: hasPreviewBom ? renderUiPanel({
      title: "Плата и BOM",
      meta: isNewBom ? "создание компонентного состава" : `${importRows.length ? `${importRows.length} строк` : "таблица пока пустая"} · покомпонентный расчет платы`,
      className: "bom-editor-panel bom-combined-panel",
      body: renderUiPanelBody({
        body: `
            <div class="bom-board-card-layout">
              <form id="bomModuleForm" class="module-form bom-board-form">
                <input type="hidden" name="bomId" value="${escapeAttribute(bom.id)}" />
                <input type="hidden" name="isNew" value="${isNewBom ? "yes" : "no"}" />
                <label class="form-field ui-form-field"><span>Название платы</span><input name="name" value="${escapeAttribute(bom.name)}" placeholder="Плата PCB" /></label>
                <label class="form-field ui-form-field"><span>Децимальный номер</span><input name="boardCode" value="${escapeAttribute(bom.boardCode)}" placeholder="Например АБВГ.123456.001" /></label>
                <label class="form-field ui-form-field"><span>Результат производства</span><input name="resultItem" value="${escapeAttribute(bom.resultItem)}" placeholder="Смонтированная печатная плата" /></label>
                <div class="module-form-actions full">
                  <button class="primary-button ui-action-button" type="submit">${icon("save")}<span>${isNewBom ? "Создать плату" : "Сохранить плату"}</span></button>
                  ${isNewBom ? "" : `<button class="secondary-button danger ui-action-button" data-bom-delete="${escapeAttribute(bom.id)}" type="button">${icon("trash")}<span>Удалить плату</span></button>`}
                </div>
              </form>
            </div>
            <div class="bom-combined-table-block">
              <div class="bom-combined-table-head">
                <strong>Таблица BOM</strong>
                <span>${importRows.length ? `${escapeHtml(bom.sourceFileName || bom.name)} · ${importRows.length} строк` : "стандартные поля Excel A:I"}</span>
              </div>
              ${renderBomImportTable(bom, importHeaders, importRows, componentCounts, componentTotal, isNewBom)}
              <div class="bom-combined-table-actions">
                ${renderBomImportButton()}
              </div>
            </div>
            ${importRows.length ? `
              <div class="bom-card-component-summary">
                <div class="ui-sidebar-label">Подсчет импортированных компонентов</div>
                ${renderBomComponentSummary(componentCounts, componentTotal)}
              </div>
            ` : ""}
          `,
      }),
    }) : "",
  });
}

function renderBomImportButton() {
  return `
    <label class="primary-button bom-file-import-button ui-action-button">
      ${icon("upload")}
      <span>Импортировать *.xlsx</span>
      <input data-bom-import-file type="file" accept=".xlsx,.xls" />
    </label>
  `;
}

function renderBomComponentSummary(componentCounts, componentTotal) {
  const counts = getBomComponentFieldCounts(componentCounts);
  const total = Object.values(counts).reduce((sum, count) => sum + Number(count || 0), 0);
  const activeTypes = Object.values(counts).filter((count) => Number(count || 0) > 0).length;
  return `
    <div class="bom-component-summary">
      <article>
        <span>Компонентов</span>
        <strong>${Number(total || componentTotal || 0).toLocaleString("ru-RU")}</strong>
        <small>на одну плату</small>
      </article>
      <article>
        <span>Типов</span>
        <strong>${activeTypes.toLocaleString("ru-RU")}</strong>
        <small>заполненных категорий</small>
      </article>
      ${BOM_COMPONENT_FIELDS.map((field) => `
        <article>
          <span>${escapeHtml(field.label)}</span>
          <strong>${Number(counts[field.key] || 0).toLocaleString("ru-RU")}</strong>
          <small>шт.</small>
        </article>
      `).join("")}
    </div>
  `;
}

function renderBomNomenclatureAddControl(bom, isNewBom = false) {
  const reaItems = getReaNomenclatureItems();
  if (isNewBom || !bom?.id) {
    return `
      <div class="bom-nomenclature-add is-disabled">
        ${icon("package")}
        <span>Сначала сохраните карточку платы, затем можно будет добавлять РЭА-компоненты из номенклатуры.</span>
      </div>
    `;
  }

  if (!reaItems.length) {
    return `
      <div class="bom-nomenclature-add is-disabled">
        ${icon("package")}
        <span>В номенклатуре пока нет позиций типа «${NOMENCLATURE_REA_COMPONENT_TYPE}». Импортируйте BOM или создайте компонент в модуле «Номенклатура».</span>
      </div>
    `;
  }

  const options = [
    { value: "", label: "Добавить РЭА компонент", meta: "выберите позицию номенклатуры" },
    ...reaItems.map((item) => ({
      value: item.id,
      label: item.name || "Компонент без названия",
      meta: `${item.article || "артикул не задан"} · ${item.package || "корпус не задан"}`,
    })),
  ];

  return `
    <div class="bom-nomenclature-add">
      <div>
        ${icon("package")}
        <span>Добавить строку из номенклатуры</span>
      </div>
      ${renderDenseInlineSelect("nomenclatureId", "", options, { type: "bomNomenclature", bomId: bom.id })}
    </div>
  `;
}

function renderBomImportCellInput(bomId, rowIndex, columnIndex, value) {
  const isQuantity = columnIndex === 6;
  return `
    <input
      class="bom-edit-input"
      data-bom-import-cell="${escapeAttribute(bomId)}"
      data-bom-row-index="${rowIndex}"
      data-bom-column-index="${columnIndex}"
      ${isQuantity ? `type="number" min="0" step="1"` : `type="text"`}
      value="${escapeAttribute(value)}"
      aria-label="Поле BOM ${rowIndex + 1}.${columnIndex + 1}"
    />
  `;
}

function renderBomImportPreviewTable() {
  return `
    <div class="bom-import-table-wrap bom-import-preview-wrap ui-table-wrap" data-layout="table" data-scroll-contract="horizontal-only" data-ui-component="TableWrap">
      <div class="bom-import-preview-note" role="note">
        ${icon("info")}
        <div>
          <strong>Предпросмотр шаблона BOM</strong>
          <span>Данных пока нет. После импорта Excel здесь появятся реальные строки компонентного состава платы.</span>
        </div>
      </div>
      <table class="directory-table bom-import-table bom-import-preview-table">
        <thead>
          <tr>
            ${BOM_IMPORT_FALLBACK_HEADERS.map((header) => `<th>${escapeHtml(header)}</th>`).join("")}
          </tr>
        </thead>
        <tbody>
          <tr class="is-preview-row">
            <td class="bom-import-preview-empty-cell" colspan="${BOM_IMPORT_FALLBACK_HEADERS.length}">
              <span>Пока нет импортированных строк</span>
              <small>Это только структура колонок, а не сохраненные данные BOM.</small>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  `;
}

function renderBomImportTable(bom, headers, rows, componentCounts, componentTotal, isNewBom = false) {
  if (!rows.length) {
    return renderBomImportPreviewTable();
  }

  return `
    <div class="bom-import-table-wrap ui-table-wrap" data-layout="table" data-scroll-contract="horizontal-only" data-ui-component="TableWrap">
      <table class="directory-table bom-import-table">
        <thead>
          <tr>
            ${headers.map((header) => `<th>${escapeHtml(header)}</th>`).join("")}
            <th class="actions-cell">Действия</th>
          </tr>
        </thead>
        <tbody>
          ${rows.map((row, rowIndex) => `
            <tr>
              ${row.values.map((value, columnIndex) => `
                <td class="${columnIndex === 1 ? "primary-cell" : ""}">
                  ${renderBomImportCellInput(bom.id, rowIndex, columnIndex, value)}
                </td>
              `).join("")}
              <td class="actions-cell bom-row-action-cell">
                <button class="table-icon-button danger-soft ui-action-button" data-bom-import-delete="${escapeAttribute(bom.id)}" data-bom-row-index="${rowIndex}" type="button" title="Удалить строку BOM">${icon("trash")}</button>
              </td>
            </tr>
          `).join("")}
        </tbody>
        <tfoot>
          <tr>
            <td colspan="${BOM_IMPORT_COLUMN_COUNT + 1}">
              <div class="bom-import-table-footer">
                ${renderBomNomenclatureAddControl(bom, isNewBom)}
              </div>
            </td>
          </tr>
        </tfoot>
      </table>
    </div>
  `;
}

function getDirectoryRows(sectionId) {
  return Array.isArray(directoryState?.[sectionId]) ? directoryState[sectionId] : [];
}

function getSpecificationById(specificationId) {
  return getDirectoryRows("specifications")
    .find((specification) => specification.id === specificationId) || null;
}

function getRouteSpecification(route) {
  return getSpecificationById(route?.specificationId)
    || getSpecificationByProjectId(route?.projectId)
    || null;
}

function getRouteBomList(route) {
  return getBomList(route?.bomListId || "");
}

function getRouteBindingContext(value = "") {
  const rawValue = String(value || "").trim();
  if (!rawValue) return { kind: "", id: "", value: "", specification: null, bom: null };

  const [rawKind, ...rest] = rawValue.split(":");
  const hasKindPrefix = ["spec", "bom"].includes(rawKind);
  const kind = hasKindPrefix ? rawKind : "";
  const id = hasKindPrefix ? rest.join(":") : rawValue;
  const specification = kind !== "bom" ? getSpecificationById(id) || getSpecificationByProjectId(id) : null;
  if (specification) {
    return {
      kind: "spec",
      id: specification.id,
      value: `spec:${specification.id}`,
      specification,
      bom: null,
    };
  }

  const bom = kind !== "spec" ? getBomList(id) : null;
  if (bom) {
    return {
      kind: "bom",
      id: bom.id,
      value: `bom:${bom.id}`,
      specification: null,
      bom,
    };
  }

  return { kind, id, value: rawValue, specification: null, bom: null };
}

function normalizeRouteBindingValue(value = "") {
  return getRouteBindingContext(value).value || "";
}

function normalizeRouteBindingMode(value = "") {
  return value === "bom" ? "bom" : "product";
}

function getRouteBindingModeForSelection(value = "", route = null) {
  const binding = getRouteBindingContext(value);
  if (binding.kind === "bom" || binding.bom || route?.bomListId) return "bom";
  return "product";
}

function getRouteBindingOptions() {
  const productOptions = (directoryState.specifications || []).map((item) => ({
    value: `spec:${item.id}`,
    label: item.name || "Изделие без названия",
    meta: `${PRODUCT_COMPOSITION_TERM} · ${getSpecificationProductionOrder(item) || "заказ не задан"}`,
  }));
  const bomOptions = (directoryState.bomLists || []).map((item) => ({
    value: `bom:${item.id}`,
    label: item.name || "Плата без названия",
    meta: `${BOARD_BOM_TERM} · ${getBomImportRows(item).length || Object.values(getBomComponentCounts(item)).reduce((sum, count) => sum + Number(count || 0), 0)} поз.`,
  }));

  return [
    { value: "", label: "Связь не выбрана", meta: "маршрутная карта как самостоятельный документ" },
    ...productOptions,
    ...bomOptions,
  ];
}

function ensureRouteModuleProjectForSpecification(specification) {
  if (!specification) return "";
  const specificationId = ensureSpecificationPlanningUnit(specification);
  if (!specificationId) return "";
  if (!specification.projectId) return specificationId;

  const stamp = new Date().toISOString();
  directoryState.specifications = (directoryState.specifications || []).map((item) => (
    item.id === specification.id
      ? syncSpecificationDerivedFields({ ...item, projectId: "", updatedAt: stamp })
      : item
  ));
  directoryState = normalizeDirectoryState(directoryState, { mergeFallback: false });
  persistDirectoryState();
  return specificationId;
}

function resolveRouteModuleProjectId(selectionValue, options = {}) {
  const binding = getRouteBindingContext(selectionValue);
  if (binding.bom) return "";
  const value = binding.specification?.id || String(selectionValue || "");
  if (!value) return "";

  const specification = binding.specification || getSpecificationById(value) || getSpecificationByProjectId(value);
  if (specification) {
    if (getProject(specification.id)) return specification.id;
    return options.createPlanningUnit === false
      ? ""
      : ensureRouteModuleProjectForSpecification(specification);
  }

  return getProject(value)?.id || value;
}

function getRouteModuleSelectionValue(route, fallbackSpecification = null) {
  const routeBom = getRouteBomList(route);
  if (routeBom) return `bom:${routeBom.id}`;
  if (route?.bomListId) return `bom:${route.bomListId}`;
  const routeSpecification = getRouteSpecification(route);
  if (routeSpecification) return `spec:${routeSpecification.id}`;
  if (route?.specificationId) return normalizeRouteBindingValue(route.specificationId) || `spec:${route.specificationId}`;
  if (route?.projectId) return normalizeRouteBindingValue(route.projectId) || `spec:${route.projectId}`;
  if (fallbackSpecification) return `spec:${fallbackSpecification.id}`;
  return "";
}

function getRouteModuleSelectionName(route, fallbackSpecification = null) {
  const bom = getRouteBomList(route);
  if (bom) return bom.name || "Плата без названия";
  const specification = getRouteSpecification(route) || fallbackSpecification;
  if (specification) return specification.name || "Состав изделия без названия";
  return getProjectDisplayName(getRouteProductionContext(route)) || "";
}

function getRouteDocumentKind(route = null) {
  const rawKind = String(route?.routeDocumentKind || route?.documentKind || "").trim();
  if (ROUTE_DOCUMENT_KIND_LABELS[rawKind]) return rawKind;
  if (route?.shiftParentRouteId || route?.shiftDate || route?.shiftRouteId) return "shift";
  if (route?.parentRouteId || route?.routeTaskId || route?.routeTaskSourceItemId) return "child";
  return "main";
}

function getRouteDocumentKindLabel(route = null) {
  return ROUTE_DOCUMENT_KIND_LABELS[getRouteDocumentKind(route)] || ROUTE_DOCUMENT_KIND_LABELS.main;
}

function getRouteDocumentKindShortLabel(route = null) {
  return ROUTE_DOCUMENT_KIND_SHORT_LABELS[getRouteDocumentKind(route)] || ROUTE_DOCUMENT_KIND_SHORT_LABELS.main;
}

function getRouteRootRoute(route = null) {
  if (!route) return null;
  const kind = getRouteDocumentKind(route);
  const rootRouteId = route.rootRouteId || (kind === "main" ? route.id : "");
  return (planningState.routes || []).find((item) => item.id === rootRouteId)
    || (kind === "main" ? route : null);
}

function getRouteParentRoute(route = null) {
  if (!route) return null;
  return (planningState.routes || []).find((item) => item.id === route.parentRouteId)
    || getRouteRootRoute(route)
    || null;
}

function getRouteSortRootId(route = null) {
  const kind = getRouteDocumentKind(route);
  return route?.rootRouteId || (kind === "main" ? route?.id : route?.parentRouteId) || route?.id || "";
}

function getRouteScopeSourceItemId(route = null) {
  return String(route?.routeTaskSourceItemId || route?.routeScopeSourceItemId || route?.specTaskSourceItemId || "").trim();
}

function getRouteScopeRootTask(route = null, tasks = getRouteUnscopedBaseTasks(route)) {
  const routeTaskId = String(route?.routeTaskId || "").trim();
  const sourceItemId = getRouteScopeSourceItemId(route);
  const sourceSpecificationId = String(route?.routeTaskSourceSpecificationId || "").trim();
  if (routeTaskId) {
    const task = tasks.find((item) => item.id === routeTaskId);
    if (task) return task;
  }
  if (!sourceItemId) return null;
  return tasks.find((item) => (
    item.sourceItemId === sourceItemId
    && (!sourceSpecificationId || item.sourceSpecificationId === sourceSpecificationId)
  )) || null;
}

function scopeRouteTasks(route = null, tasks = []) {
  const scopeRootTask = getRouteScopeRootTask(route, tasks);
  if (!scopeRootTask) return tasks;
  return [{
    ...scopeRootTask,
    level: 0,
    continuationLevels: [],
    routeScopeRoot: true,
    hasChildren: false,
    isLast: true,
    parentTitle: "",
  }];
}

function getRouteLineageSubjectName(route = null) {
  const taskName = String(route?.routeTaskName || "").trim();
  if (taskName) return taskName;
  const task = getRouteScopeRootTask(route);
  if (task?.title) return task.title;
  return getRouteModuleSelectionName(route) || "Объект не выбран";
}

function getRoutesForModule() {
  return [...(planningState.routes || [])].sort((left, right) => {
    const leftRoot = (planningState.routes || []).find((route) => route.id === getRouteSortRootId(left)) || left;
    const rightRoot = (planningState.routes || []).find((route) => route.id === getRouteSortRootId(right)) || right;
    const leftProject = getProjectDisplayName(getRouteProductionContext(leftRoot)) || getRouteModuleSelectionName(leftRoot) || "";
    const rightProject = getProjectDisplayName(getRouteProductionContext(rightRoot)) || getRouteModuleSelectionName(rightRoot) || "";
    const leftKind = getRouteDocumentKind(left);
    const rightKind = getRouteDocumentKind(right);
    return leftProject.localeCompare(rightProject, "ru")
      || String(leftRoot.name || "").localeCompare(String(rightRoot.name || ""), "ru")
      || (ROUTE_DOCUMENT_KIND_ORDER[leftKind] ?? 9) - (ROUTE_DOCUMENT_KIND_ORDER[rightKind] ?? 9)
      || String(left.routeTaskNumber || "").localeCompare(String(right.routeTaskNumber || ""), "ru", { numeric: true })
      || String(left.name || "").localeCompare(String(right.name || ""), "ru");
  });
}

function getRouteStepsForModule(routeId) {
  return (planningState.routeSteps || [])
    .filter((step) => step.routeId === routeId)
    .sort((left, right) => {
      const taskDelta = getRouteStepTaskId(left).localeCompare(getRouteStepTaskId(right), "ru");
      return taskDelta || Number(left.stepOrder || 0) - Number(right.stepOrder || 0);
    });
}

function getRouteStepTaskId(step) {
  return step?.specTaskId || MAIN_ROUTE_TASK_ID;
}

function getRouteStepsForTask(steps, taskId) {
  return (steps || [])
    .filter((step) => getRouteStepTaskId(step) === taskId)
    .sort((left, right) => Number(left.stepOrder || 0) - Number(right.stepOrder || 0));
}

function getRouteBaseTasks(route) {
  return scopeRouteTasks(route, getRouteUnscopedBaseTasks(route));
}

function getRouteUnscopedBaseTasks(route) {
  const specification = getRouteSpecification(route);
  return specification ? getSpecificationRouteTasks(specification) : getRouteBomTasks(route);
}

function getRouteBaseTaskIds(route) {
  return new Set(getRouteBaseTasks(route).map((task) => task.id));
}

function isRouteStepLinkedToCurrentRouteTask(route, step) {
  const taskId = String(step?.specTaskId || "").trim();
  if (!route?.id || !taskId || taskId === MAIN_ROUTE_TASK_ID) return false;
  return getRouteBaseTaskIds(route).has(taskId);
}

function pruneRouteStepsOutsideCurrentRouteTasks(state = planningState) {
  if (!state || !Array.isArray(state.routeSteps)) return new Set();
  const routesById = new Map((state.routes || []).map((route) => [route.id, route]));
  const taskIdsByRouteId = new Map();
  const removedStepIds = new Set();
  const stepsByRouteId = new Map();

  state.routeSteps.forEach((step) => {
    const routeId = step?.routeId || "";
    if (!stepsByRouteId.has(routeId)) stepsByRouteId.set(routeId, []);
    stepsByRouteId.get(routeId).push(step);
  });

  const nextSteps = [];
  stepsByRouteId.forEach((steps, routeId) => {
    const route = routesById.get(routeId);
    if (!route) {
      steps.forEach((step) => removedStepIds.add(step.id));
      return;
    }
    if (!taskIdsByRouteId.has(route.id)) {
      taskIdsByRouteId.set(route.id, getRouteBaseTaskIds(route));
    }
    const routeTaskIds = taskIdsByRouteId.get(route.id);
    const kept = [];
    const removed = [];
    steps.forEach((step) => {
      const taskId = String(step?.specTaskId || "").trim();
      if (taskId && taskId !== MAIN_ROUTE_TASK_ID && routeTaskIds.has(taskId)) {
        kept.push(step);
      } else {
        removed.push(step);
      }
    });

    if (!kept.length && steps.length) {
      nextSteps.push(...steps);
      return;
    }

    nextSteps.push(...kept);
    removed.forEach((step) => removedStepIds.add(step.id));
  });

  state.routeSteps = nextSteps;

  return removedStepIds;
}

function getRouteProductionId(route = null) {
  return route?.specificationId || route?.projectId || "";
}

function getRouteProductionContext(route = null) {
  const productionId = getRouteProductionId(route);
  return productionId ? getProject(productionId) : null;
}

function getRoutePlanningContext(route = null) {
  const production = getRouteProductionContext(route);
  if (production) return production;

  const bom = getRouteBomList(route);
  if (!bom) return null;
  const title = bom.resultItem || bom.boardCode || bom.name || "Печатная плата";
  return {
    id: `bom:${bom.id}`,
    name: title,
    productName: title,
    orderNumber: route?.name || bom.name || title,
    customer: "",
    totalQuantity: normalizeOptionalPositiveInteger(route?.planningQuantity) || 1,
    status: getWorkOrderPlanningStatusValue(route),
    dueDate: toDateInput(addMs(new Date(), 21 * 24 * 60 * 60 * 1000)),
    bomListId: bom.id,
    sourceType: "bom",
  };
}

function getRouteConcreteTasksForPlanning(route) {
  return getRouteTasksForModule(route)
    .filter((task) => !task.isMain && !task.isOrphan);
}

function getPlanningTasksForRoute(route, steps = null) {
  return getRouteTasksForModule(route);
}

function getRouteStepsForPlanningTask(route, task, steps = null) {
  const routeSteps = steps || getRouteStepsForModule(route?.id || "");
  return getRouteStepsForTask(routeSteps, task?.id || "");
}

function getRouteForStep(step = {}) {
  return (planningState.routes || []).find((route) => route.id === step?.routeId) || null;
}

function getRouteStepPlanningTask(route, step, steps = null) {
  if (!route?.id || !step?.id) return null;
  const taskId = getRouteStepTaskId(step);
  const tasks = getRouteTasksForModule(route);
  return tasks.find((task) => task.id === taskId) || null;
}

function getRouteStepEffectiveQuantityMultiplier(step = {}, route = null) {
  const explicitMultiplier = Math.max(1, Number(step.quantityMultiplier || step.specTaskQuantity || 1));
  const resolvedRoute = route || getRouteForStep(step);
  const task = getRouteStepPlanningTask(resolvedRoute, step);
  return Math.max(1, Number(task?.quantity || explicitMultiplier));
}

function getRouteStepEffectiveBoardsPerPanel(route, step = {}) {
  const task = getRouteStepPlanningTask(route, step);
  const sourceId = task?.sourceItemId || task?.id || step.specTaskSourceItemId || step.bomListId || "";
  const fallback = task?.boardsPerPanel || step.boardsPerPanel || 1;
  return sourceId && route
    ? getPlanningBoardsPerPanel(route, sourceId, fallback)
    : normalizeBoardsPerPanel(fallback, 1);
}

function getRouteStepEffectiveBomListId(route, step = {}) {
  return step.bomListId || getRouteStepPlanningTask(route, step)?.bomListId || "";
}

function getRouteStepEffectiveOperationContext(route, step = {}, planningWorkCenterId = "", resourceId = "") {
  const task = getRouteStepPlanningTask(route, step);
  return {
    ...step,
    specTaskId: step.specTaskId || task?.id || "",
    specTaskSourceItemId: step.specTaskSourceItemId || task?.sourceItemId || "",
    specTaskName: step.specTaskName || task?.title || "",
    specTaskQuantity: Math.max(1, Number(step.specTaskQuantity || task?.quantity || 1)),
    fulfillmentMode: task?.fulfillmentMode || step.fulfillmentMode || "produce",
    quantityMultiplier: getRouteStepEffectiveQuantityMultiplier(step, route),
    bomListId: getRouteStepEffectiveBomListId(route, step),
    boardsPerPanel: getRouteStepEffectiveBoardsPerPanel(route, step),
    routeWorkCenterId: step.workCenterId,
    workCenterId: planningWorkCenterId || step.workCenterId || "",
    resourceId: resourceId || step.resourceId || "",
  };
}

function normalizeRouteStepFlowItems(items, kind = "input") {
  if (!Array.isArray(items)) return [];
  return items
    .map((item, index) => {
      const label = String(item?.label || item?.name || item?.title || "").trim();
      if (!label) return null;
      return {
        id: String(item.id || `${kind}-${index + 1}`),
        kind,
        sourceType: String(item.sourceType || item.type || "manual"),
        sourceId: String(item.sourceId || ""),
        label,
        quantity: Number.isFinite(Number(item.quantity)) && Number(item.quantity) > 0 ? Number(item.quantity) : null,
        unit: String(item.unit || "").trim(),
      };
    })
    .filter(Boolean);
}

function makeManualRouteStepFlowItems(kind, rawValue) {
  const label = String(rawValue || "").trim();
  return label ? [{
    id: `${kind}-manual`,
    kind,
    sourceType: "manual",
    sourceId: "",
    label,
    quantity: null,
    unit: "",
  }] : [];
}

function getRouteStepManualFlowLabel(step = {}, kind = "input") {
  const field = kind === "output" ? "operationOutputs" : "operationInputs";
  const items = normalizeRouteStepFlowItems(step[field], kind);
  return items.length === 1 && items[0].sourceType === "manual" ? items[0].label : "";
}

function makeRouteStepFlowItem(kind, label, sourceType = "derived", sourceId = "", extra = {}) {
  const cleanLabel = String(label || "").trim();
  if (!cleanLabel) return null;
  return {
    id: `${kind}-${sourceType}-${sourceId || cleanLabel}`.slice(0, 96),
    kind,
    sourceType,
    sourceId: String(sourceId || ""),
    label: cleanLabel,
    quantity: extra.quantity ?? null,
    unit: extra.unit || "",
  };
}

function getRouteTaskSourceSpecification(route = null, task = {}) {
  return getSpecificationById(task?.sourceSpecificationId || "")
    || getRouteSpecification(route)
    || null;
}

function getRouteTaskSourceStructureItem(route = null, task = {}) {
  const specification = getRouteTaskSourceSpecification(route, task);
  const sourceItemId = String(task?.sourceItemId || "").trim();
  if (!specification || !sourceItemId) return null;
  return getSpecificationStructureItems(specification).find((item) => item.id === sourceItemId) || null;
}

function getRouteTaskChildStructureItems(route = null, task = {}) {
  const specification = getRouteTaskSourceSpecification(route, task);
  const sourceItemId = String(task?.sourceItemId || "").trim();
  if (!specification || !sourceItemId) return [];
  return getSpecificationStructureItems(specification)
    .filter((item) => (item.parentId || "root") === sourceItemId);
}

function getRouteTaskProducedObjectLabel(route = null, task = null, bom = null, production = null) {
  if (task?.isMain) {
    return getProjectDisplayOutput(production)
      || getProjectDisplayName(production)
      || route?.name
      || "Готовое изделие";
  }

  const sourceItem = getRouteTaskSourceStructureItem(route, task);
  const sourceLabel = sourceItem ? getSpekiStructureItemDisplayName(sourceItem) : "";
  const taskTitle = String(task?.title || sourceLabel || "").trim();
  const sourceSpecification = getRouteTaskSourceSpecification(route, task);
  const isRootAssembly = task?.type === "assembly" && (sourceItem?.parentId || "root") === "root";

  if (isRootAssembly) {
    const technicalOutput = /^изделие\s*\d+$/i.test(String(sourceSpecification?.outputItem || "").trim());
    return technicalOutput
      ? sourceSpecification?.name || sourceSpecification?.outputItem || getProjectDisplayName(production) || getProjectDisplayOutput(production) || taskTitle || "Готовое изделие"
      : sourceSpecification?.outputItem || sourceSpecification?.name || getProjectDisplayOutput(production) || getProjectDisplayName(production) || taskTitle || "Готовое изделие";
  }
  if (task?.type === "assembly") return `Узел: ${taskTitle || "производимый узел"}`;
  if (task?.type === "bom") return bom?.resultItem || taskTitle || bom?.name || "Печатная плата";
  if (task?.type === "specification") {
    const specification = getSpecificationById(sourceItem?.specificationId || task?.sourceSpecificationId || "");
    return specification?.outputItem || taskTitle || specification?.name || "Состав изделия";
  }
  if (task?.type === "nomenclature" || task?.type === "part") {
    return taskTitle || "Производимая позиция";
  }

  return taskTitle || bom?.resultItem || bom?.name || getProjectDisplayOutput(production) || "Результат ветки";
}

function renderRouteTaskOutputHint(route = null, task = null, options = {}) {
  if (!task || task.isOrphan) return "";
  const fulfillmentMode = normalizeStructureFulfillmentMode(task.fulfillmentMode || "", task.isMain ? "produce" : "not_selected");
  if (fulfillmentMode !== "produce") return "";
  const label = getRouteTaskProducedObjectLabel(
    route,
    task,
    getBomList(task.bomListId || ""),
    getRoutePlanningContext(route),
  );
  if (!label) return "";
  const prefix = options.prefix || "Выход";
  return `<small class="route-task-output-hint" title="${escapeAttribute(`${prefix}: ${label}`)}">${escapeHtml(prefix)}: ${escapeHtml(label)}</small>`;
}

function getRouteTaskInputObjectLabel(route = null, task = null, fallback = "") {
  if (task?.isMain) {
    const childLabels = getRouteConcreteTasksForPlanning(route)
      .filter((item) => normalizeStructureFulfillmentMode(item.fulfillmentMode || "", "produce") === "produce")
      .map((item) => getRouteTaskProducedObjectLabel(route, item, getBomList(item.bomListId || ""), getRoutePlanningContext(route)));
    return joinRouteStepFlowLabels(childLabels, fallback || "Полуфабрикаты состава изделия");
  }

  const childLabels = getRouteTaskChildStructureItems(route, task)
    .map((item) => getSpekiStructureItemDisplayName(item));
  if (childLabels.length) return joinRouteStepFlowLabels(childLabels, fallback || "Входы узла");
  return fallback;
}

function isLastProductionStepForRouteTask(route = null, step = {}, task = null) {
  if (!route?.id || !step?.id) return false;
  const taskId = task?.id || getRouteStepTaskId(step);
  const productionSteps = getRouteStepsForTask(getRouteStepsForModule(route.id), taskId)
    .filter((item) => !isWarehouseWorkCenterId(item.workCenterId));
  if (!productionSteps.length) return false;
  return productionSteps[productionSteps.length - 1]?.id === step.id;
}

function joinRouteStepFlowLabels(labels, fallback) {
  const clean = labels.map((label) => String(label || "").trim()).filter(Boolean);
  if (!clean.length) return fallback;
  if (clean.length <= 2) return clean.join(" + ");
  return `${clean.slice(0, 2).join(" + ")} + еще ${clean.length - 2}`;
}

function getRouteStepFlowTarget(route = null, step = {}) {
  const task = getRouteStepPlanningTask(route, step);
  const bomEntry = route ? getRouteSmtStepBomEntry(route, step) : null;
  const bom = bomEntry?.bom || getBomList(getRouteStepEffectiveBomListId(route, step) || route?.bomListId || "");
  const production = getRoutePlanningContext(route);
  const producedObjectLabel = getRouteTaskProducedObjectLabel(route, task, bom, production);
  return {
    task,
    bom,
    production,
    targetLabel: task?.title
      || bom?.resultItem
      || bom?.name
      || step.specTaskName
      || production?.name
      || "объект маршрута",
    outputLabel: producedObjectLabel
      || bom?.resultItem
      || task?.title
      || production?.name
      || step.specTaskName
      || "результат операции",
  };
}

function deriveRouteStepFlowItems(route = null, step = {}, kind = "input") {
  const { task, bom, production, targetLabel, outputLabel } = getRouteStepFlowTarget(route, step);
  const operation = getOperationMapItem(step.operationId);
  const taskId = getRouteStepTaskId(step);
  const isMainTask = taskId === MAIN_ROUTE_TASK_ID || task?.isMain;
  const isSmtStep = isSmtOperationWorkCenter(step.workCenterId, step, planningState) || routeStepRequiresManualPlanningLine(step, planningState);
  const isWarehouseOutput = isManufacturingOutputReceiptRouteStep(step);
  const isWarehouseIssue = isWarehouseIssueRouteStep(step) || task?.fulfillmentMode === "from_stock";
  const producedObjectLabel = getRouteTaskProducedObjectLabel(route, task, bom, production) || outputLabel;
  const taskInputLabel = getRouteTaskInputObjectLabel(route, task, `Полуфабрикат/материал: ${targetLabel}`);

  if (kind === "input") {
    if (isWarehouseOutput) {
      return [makeRouteStepFlowItem("input", `Готовый выпуск: ${producedObjectLabel}`, "operation-result", step.id)].filter(Boolean);
    }
    if (isWarehouseIssue) {
      return [makeRouteStepFlowItem("input", `Остаток склада: ${targetLabel}`, "warehouse-stock", task?.sourceItemId || step.id)].filter(Boolean);
    }
    if (isSmtStep && bom) {
      const boardLabel = bom.boardCode || bom.resultItem || bom.name || targetLabel;
      return [makeRouteStepFlowItem("input", `${boardLabel} + компоненты BOM`, "bom", bom.id)].filter(Boolean);
    }
    if (isMainTask) {
      return [makeRouteStepFlowItem("input", taskInputLabel, "composition", route?.id || "")].filter(Boolean);
    }
    return [makeRouteStepFlowItem("input", taskInputLabel, "route-task", task?.sourceItemId || step.id)].filter(Boolean);
  }

  if (isWarehouseOutput) {
    return [makeRouteStepFlowItem("output", `Принято: ${producedObjectLabel}`, "warehouse-receipt", task?.sourceItemId || step.id)].filter(Boolean);
  }
  if (isWarehouseIssue) {
    return [makeRouteStepFlowItem("output", `Выдано в производство: ${targetLabel}`, "warehouse-issue", task?.sourceItemId || step.id)].filter(Boolean);
  }
  if (isSmtStep && bom) {
    return [makeRouteStepFlowItem("output", bom.resultItem || `Смонтированная плата: ${targetLabel}`, "bom-result", bom.id)].filter(Boolean);
  }
  if (isMainTask) {
    const finalOutput = getProjectDisplayOutput(production) || production?.name || outputLabel;
    return [makeRouteStepFlowItem("output", finalOutput || "Готовое изделие", "production-output", production?.id || route?.id || "")].filter(Boolean);
  }
  const stepOutputLabel = isLastProductionStepForRouteTask(route, step, task)
    ? producedObjectLabel
    : operation?.businessOutput || `Состояние после операции: ${targetLabel}`;
  return [makeRouteStepFlowItem("output", stepOutputLabel, "operation-output", operation?.id || step.id)].filter(Boolean);
}

function getRouteStepFlowModel(route = null, step = {}) {
  const storedInputs = normalizeRouteStepFlowItems(step.operationInputs, "input");
  const storedOutputs = normalizeRouteStepFlowItems(step.operationOutputs, "output");
  const autoInputs = deriveRouteStepFlowItems(route, step, "input");
  const autoOutputs = deriveRouteStepFlowItems(route, step, "output");
  const inputs = storedInputs.length ? storedInputs : autoInputs;
  const outputs = storedOutputs.length ? storedOutputs : autoOutputs;
  return {
    inputs,
    outputs,
    autoInputs,
    autoOutputs,
    inputLabel: joinRouteStepFlowLabels(inputs.map((item) => item.label), "Вход не определен"),
    outputLabel: joinRouteStepFlowLabels(outputs.map((item) => item.label), "Выход не определен"),
    autoInputLabel: joinRouteStepFlowLabels(autoInputs.map((item) => item.label), "Вход будет определен после выбора объекта"),
    autoOutputLabel: joinRouteStepFlowLabels(autoOutputs.map((item) => item.label), "Выход будет определен после выбора операции"),
    inputMode: storedInputs.length ? "manual" : "auto",
    outputMode: storedOutputs.length ? "manual" : "auto",
  };
}

function getSlotOperationFlow(slot = {}, route = null, step = null) {
  const slotInputs = normalizeRouteStepFlowItems(slot.operationInputs, "input");
  const slotOutputs = normalizeRouteStepFlowItems(slot.operationOutputs, "output");
  if (slotInputs.length || slotOutputs.length) {
    return {
      inputs: slotInputs,
      outputs: slotOutputs,
      inputLabel: slot.operationInputLabel || joinRouteStepFlowLabels(slotInputs.map((item) => item.label), "Вход не определен"),
      outputLabel: slot.operationOutputLabel || joinRouteStepFlowLabels(slotOutputs.map((item) => item.label), "Выход не определен"),
      inputMode: "snapshot",
      outputMode: "snapshot",
    };
  }
  return getRouteStepFlowModel(route, step || {});
}

function renderOperationFlowMap(flow, options = {}) {
  const className = ["operation-flow-map", options.compact ? "is-compact" : "", options.editable ? "is-editable" : ""].filter(Boolean).join(" ");
  const qaPrefix = String(options.qaPrefix || "").trim();
  const rootQa = qaPrefix ? ` data-visual-qa-target="${escapeAttribute(`${qaPrefix}-flow-map`)}"` : "";
  const inputQa = qaPrefix ? ` data-visual-qa-target="${escapeAttribute(`${qaPrefix}-flow-input`)}"` : "";
  const outputQa = qaPrefix ? ` data-visual-qa-target="${escapeAttribute(`${qaPrefix}-flow-output`)}"` : "";
  return `
    <div class="${className}"${rootQa} aria-label="Входы и выходы операции">
      <span class="operation-flow-point"${inputQa}>
        <b>Вход</b>
        <strong>${escapeHtml(flow.inputLabel)}</strong>
      </span>
      <i aria-hidden="true">&rarr;</i>
      <span class="operation-flow-point"${outputQa}>
        <b>Выход</b>
        <strong>${escapeHtml(flow.outputLabel)}</strong>
      </span>
    </div>
  `;
}

function renderRouteStepFlowEditor(route, step) {
  const flow = getRouteStepFlowModel(route, step);
  const inputValue = getRouteStepManualFlowLabel(step, "input");
  const outputValue = getRouteStepManualFlowLabel(step, "output");
  return `
    <div class="route-step-flow-editor">
      ${renderOperationFlowMap(flow, { editable: true })}
      <details class="route-step-flow-override">
        <summary>Уточнить вход/выход</summary>
        <div>
          <label class="form-field ui-form-field">
            <span>Вход</span>
            <input data-route-step-input="${escapeAttribute(step.id)}" data-route-step-field="operationInputs" value="${escapeAttribute(inputValue)}" placeholder="${escapeAttribute(flow.autoInputLabel)}" />
          </label>
          <label class="form-field ui-form-field">
            <span>Выход</span>
            <input data-route-step-input="${escapeAttribute(step.id)}" data-route-step-field="operationOutputs" value="${escapeAttribute(outputValue)}" placeholder="${escapeAttribute(flow.autoOutputLabel)}" />
          </label>
        </div>
      </details>
    </div>
  `;
}

function renderRouteStepFlowSummary(route, step) {
  const flow = getRouteStepFlowModel(route, step);
  const title = `${flow.inputLabel} -> ${flow.outputLabel}`;
  return `
    <span class="route-step-flow-summary" title="${escapeAttribute(title)}">
      <b>Вход</b>
      <strong>${escapeHtml(flow.inputLabel)}</strong>
      <i aria-hidden="true">&rarr;</i>
      <b>Выход</b>
      <strong>${escapeHtml(flow.outputLabel)}</strong>
    </span>
  `;
}

function renderRouteStepFlowOverride(route, step) {
  const flow = getRouteStepFlowModel(route, step);
  const inputValue = getRouteStepManualFlowLabel(step, "input");
  const outputValue = getRouteStepManualFlowLabel(step, "output");
  return `
    <details class="route-step-flow-override route-step-flow-override-compact">
      <summary title="Уточнить вход и выход операции">${icon("info")}<span>Поток</span></summary>
      <div>
        ${renderOperationFlowMap(flow, { compact: true, editable: true })}
        <label class="form-field ui-form-field">
          <span>Вход</span>
          <input data-route-step-input="${escapeAttribute(step.id)}" data-route-step-field="operationInputs" value="${escapeAttribute(inputValue)}" placeholder="${escapeAttribute(flow.autoInputLabel)}" />
        </label>
        <label class="form-field ui-form-field">
          <span>Выход</span>
          <input data-route-step-input="${escapeAttribute(step.id)}" data-route-step-field="operationOutputs" value="${escapeAttribute(outputValue)}" placeholder="${escapeAttribute(flow.autoOutputLabel)}" />
        </label>
      </div>
    </details>
  `;
}

function renderRouteStepFlowToggle(step) {
  const isOpen = ui.routeFlowStepId === step.id;
  return `
    <button class="icon-button route-step-flow-toggle ui-action-button ${isOpen ? "is-active" : ""}" data-route-step-flow-toggle="${escapeAttribute(step.id)}" type="button" aria-expanded="${isOpen ? "true" : "false"}" title="${isOpen ? "Скрыть вход/выход операции" : "Уточнить вход/выход операции"}">
      ${icon("split")}
    </button>
  `;
}

function renderRouteStepFlowPanelRow(route, step, level) {
  if (ui.routeFlowStepId !== step.id) return "";
  const flow = getRouteStepFlowModel(route, step);
  const inputValue = getRouteStepManualFlowLabel(step, "input");
  const outputValue = getRouteStepManualFlowLabel(step, "output");
  return `
    <tr class="route-step-flow-panel-row" data-route-step-flow-panel="${escapeAttribute(step.id)}" style="--speki-level: ${level};">
      <td colspan="6">
        <div class="route-step-flow-panel">
          ${renderOperationFlowMap(flow, { compact: true, editable: true })}
          <label class="form-field ui-form-field">
            <span>Вход</span>
            <input data-route-step-input="${escapeAttribute(step.id)}" data-route-step-field="operationInputs" value="${escapeAttribute(inputValue)}" placeholder="${escapeAttribute(flow.autoInputLabel)}" />
          </label>
          <label class="form-field ui-form-field">
            <span>Выход</span>
            <input data-route-step-input="${escapeAttribute(step.id)}" data-route-step-field="operationOutputs" value="${escapeAttribute(outputValue)}" placeholder="${escapeAttribute(flow.autoOutputLabel)}" />
          </label>
        </div>
      </td>
    </tr>
  `;
}

function getRouteStepCalculationTypeView(value = "") {
  return ROUTE_STEP_CALCULATION_TYPES.find((item) => item.value === value)
    || ROUTE_STEP_CALCULATION_TYPES.find((item) => item.value === "manual");
}

function getRouteStepCalculationTypeOptions() {
  return ROUTE_STEP_CALCULATION_TYPES.map((item) => ({
    ...item,
    summaryMeta: "",
    tone: "labor-test",
    summaryTitle: `${item.label}: ${item.meta}`,
  }));
}

function getRouteStepLaborPlanningWorkCenterOptions(step = {}) {
  const candidates = getRouteStepPlanningCandidateWorkCenterIds(step, planningState);
  const selectedWorkCenterId = getRouteStepSelectedPlanningWorkCenterId(step, planningState);
  const options = [{
    value: "",
    label: candidates.length > 1 ? "Не выбран" : "Авто",
    meta: candidates.length > 1 ? "выберите ресурс плана" : "по отделу маршрута",
    summaryMeta: "",
    iconName: "settings",
    summaryTitle: "Ресурс планирования операции",
  }];

  candidates.forEach((workCenterId) => {
    const center = getWorkCenter(workCenterId);
    const resourceId = getPlanningResourceForRouteStep(step, workCenterId, step.resourceId || "");
    const resource = resourceId ? getProductionResource(resourceId) : null;
    const rate = Number(getResourceBaseCph(resource) || getWorkCenterUnitsPerHour(workCenterId, planningState) || 0);
    options.push({
      value: workCenterId,
      label: center?.name || resource?.name || workCenterId,
      meta: resource?.name || (rate ? `${formatReportNumber(rate)} ед/ч` : center?.code || "ресурс"),
      summaryMeta: "",
      iconName: "settings",
      summaryTitle: `${center?.name || workCenterId}${resource?.name ? ` · ${resource.name}` : ""}`,
    });
  });

  if (selectedWorkCenterId && !options.some((item) => item.value === selectedWorkCenterId)) {
    const center = getWorkCenter(selectedWorkCenterId);
    options.push({
      value: selectedWorkCenterId,
      label: center?.name || selectedWorkCenterId,
      meta: center?.code || "текущий ресурс",
      summaryMeta: "",
      iconName: "settings",
      summaryTitle: center?.name || selectedWorkCenterId,
    });
  }

  return options;
}

function getRouteStepLaborSnapshot(route, step = {}, options = {}) {
  const routeQuantity = normalizeQuantity(options.routeQuantity || getPlanningRouteQuantity(route), 1);
  const quantity = normalizeQuantity(options.quantity || getRouteStepQuantityForBatch(step, { quantity: routeQuantity }), routeQuantity);
  const planningWorkCenterId = getRouteStepSelectedPlanningWorkCenterId(step, planningState);
  const workCenterId = planningWorkCenterId || step.workCenterId || "";
  const resourceId = getPlanningResourceForRouteStep(step, workCenterId, step.resourceId || "");
  const operationContext = getRouteStepEffectiveOperationContext(route, step, workCenterId, resourceId);
  const calculationType = getDefaultOperationCalculationType(workCenterId, operationContext);
  const durationMs = workCenterId
    ? calculateRequiredDurationMs(workCenterId, quantity, planningState, operationContext.unitsPerHour, operationContext.boardsPerPanel, operationContext)
    : 0;
  const workCenter = getWorkCenter(workCenterId) || getWorkCenter(step.workCenterId);
  const resource = resourceId
    ? getProductionResource(resourceId)
      || getResourcesForWorkCenter(workCenterId).find((item) => item.id === resourceId)
      || null
    : null;
  const bomList = getDurationBomList(operationContext);
  const calculation = getRouteStepCalculationTypeView(calculationType);
  const isSmtLike = calculationType === "components" || isSmtOperationWorkCenter(workCenterId, operationContext, planningState);
  const manualCapacity = getWorkCenterManualCapacity(workCenterId, planningState);
  const resourceCapacity = parseCapacityCount(resource?.capacity);
  const resourceBaseCph = isSmtLike || Number(resource?.baseCph || 0) > 0
    ? getResourceBaseCph(resource)
    : 0;
  const resourceEfficiency = Math.max(0, Number(resource?.efficiency || 0));
  const resourceChangeoverMin = Math.max(0, Number(resource?.changeoverMin || 0));

  return {
    routeQuantity,
    quantity,
    workCenterId,
    workCenterLabel: workCenter?.name || workCenterId || "отдел не выбран",
    resourceId,
    resourceLabel: resource?.name || resource?.code || "авто",
    resourceTypeLabel: PRODUCTION_RESOURCE_TYPE_LABELS[resource?.type] || resource?.type || "ресурс",
    resourceParticipatesInPlanning: resource ? resourceParticipatesInPlanning(resource) : false,
    resourceParticipatesInCalculation: resource ? resourceParticipatesInCalculation(resource) : false,
    resourceCapacity,
    manualCapacity,
    resourceCapacityLabel: resource?.capacity || (manualCapacity ? `${formatReportNumber(manualCapacity)} паралл.` : "-"),
    resourceBaseCph,
    resourceEfficiency,
    resourceChangeoverMin,
    calculationType,
    calculationLabel: calculation?.summaryLabel || calculationType || "расчет",
    calculationMeta: calculation?.meta || "",
    durationMs,
    durationLabel: durationMs ? formatDuration(durationMs) : "не рассчитано",
    secondsPerPanel: Math.max(0, Number(operationContext.secondsPerPanel || 0)),
    unitsPerHour: Math.max(0, Number(operationContext.unitsPerHour || 0)),
    setupMin: Math.max(0, Number(operationContext.setupMin || 0)),
    boardsPerPanel: normalizeBoardsPerPanel(operationContext.boardsPerPanel, 1),
    bomLabel: bomList?.name || bomList?.resultItem || "BOM не привязан",
  };
}

